window.RULES_DB = {
  "subterranean-ambush": {name:`Subterranean Ambush`,desc:`Si l'armée inclut une unité de Miners, après déploiement et avant le 1er tour, placer deux marqueurs de Mine (32mm) +1 par unité de Miners supplémentaire, hors zone adverse, à >12\" d'un autre marqueur ami, >6\" d'un ennemi, >3\" d'un élément spécial/objectif. Une unité de Miners arrivant en réserve peut être placée à <6\" d'un marqueur (pas à <6\" d'un ennemi) ; ne peut charger ce tour, compte comme ayant bougé.`,army:`Dwarfen Mountain Holds`,url:`https://tow.whfb.app/special-rules/subterranean-ambush`},
  "ancient-enemies": {name:`Ancient Enemies`,desc:`Toutes les unités d'une armée Host of Talsyn gagnent Hatred (Beastmen Brayherds).`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/ancient-enemies`},
  "the-awakened-wood": {name:`The Awakened Wood`,desc:`Dans une armée Host of Talsyn, n'importe quel nombre d'unités de Dryads et Tree Kin peut avoir Ambushers pour +1 pt/figurine ; les Treemen et Treeman Ancient pour +10 pts.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/the-awakened-wood`},
  "chieftains-of-the-hunter-king": {name:`Chieftains of the Hunter-King`,desc:`Les Wood Elf Nobles d'une armée Orion's Wild Hunt peuvent avoir Talismanic Tattoos pour 10 pts/figurine.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/chieftains-of-the-hunter-king`},
  "courage-beyond-compare": {name:`Courage Beyond Compare`,desc:`Si ce personnage rejoint une unité de Guardians of Talsyn, l'unité gagne Immune to Psychology. S'il la quitte, l'unité la perd.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/courage-beyond-compare`},
  "daughters-of-eternity": {name:`Daughters of Eternity`,desc:`Les modèles avec cette règle (Sisters of the Thorn) ont une sauvegarde Ward 4+ contre toute blessure.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/daughters-of-eternity`},
  "deepwood-coven": {name:`Deepwood Coven`,desc:`Une unité de Sisters of the Thorn connaît un sort aléatoire (Battle Magic ou Elementalism), ou le sort signature au choix. Lançable en Bound spell : Power Level 1 avec une Handmaiden of the Thorn ; PL 2 avec Handmaiden + porte-étendard ; sinon PL 0.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/deepwood-coven`},
  "guardians-of-the-wildwood": {name:`Guardians of the Wildwood`,desc:`Au contact socle d'un ennemi causant la Peur ou la Terreur, un modèle avec cette règle gagne +1 en Attaques (max 10) et Multiple Wounds (2).`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/guardians-of-the-wildwood`},
  "hawk-eyed-archer": {name:`Hawk-eyed Archer`,desc:`Un modèle avec cette règle peut cibler tout personnage ennemi en ligne de vue (ignorant les règles des personnages isolés). De plus, il peut viser une figurine précise dans l'unité cible (champion ou personnage).`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/hawk-eyed-archer`},
  "in-tune-with-nature": {name:`In Tune With Nature`,desc:`En plus de leurs Lores habituels, les Mages, Treeman Ancients et Branchwraiths d'une armée Host of Talsyn peuvent connaître des sorts du Lore of the Wilds.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/in-tune-with-nature`},
  "parry-wood-elves": {name:`Parry (Wood Elves)`,desc:`En combattant avec arme de main + bouclier, ou Asrai spear + bouclier, cette unité améliore sa valeur d'armure de 1.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/parry-wood-elves`},
  "protectors-of-the-ancient-wood": {name:`Protectors of the Ancient Wood`,desc:`Tant qu'elle contrôle un élément spécial (special feature), une unité d'une armée Host of Talsyn peut relancer les jets pour Toucher et pour Blesser de 1 naturel en phase de Combat.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/protectors-of-the-ancient-wood`},
  "spectral-hounds": {name:`Spectral Hounds`,desc:`Les Hounds of Orion ne peuvent être blessés que par des Magical Attacks. De plus, tant qu'un Hound subsiste, Orion ne peut être ciblé par le tir ennemi.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/spectral-hounds`},
  "the-spirit-of-kurnous": {name:`The Spirit of Kurnous`,desc:`0-1 unité de Glade Riders, Warhawk Riders ou Wood Elf Beast Packs par 1000 pts peut avoir Furious Charge et Impetuous pour +10 pts/unité. Ne s'applique pas à la monture.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/the-spirit-of-kurnous`},
  "talismanic-tattoos": {name:`Talismanic Tattoos`,desc:`Donne au porteur une sauvegarde Ward 6+ contre toute blessure.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/talismanic-tattoos`},
  "tree-whack": {name:`Tree Whack`,desc:`1×/tour en phase de Combat, un modèle avec cette règle peut utiliser une de ses Attaques pour une attaque 'Tree Whack' : désigner une figurine ennemie engagée qui fait un test d'Initiative. Raté = D3 touches de la Force du modèle, sans armure (Ward/Régén OK) ; réussi = esquivé.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/tree-whack`},
  "troubadour-of-loec": {name:`Troubadour of Loec`,desc:`Un Shadowdancer qui rejoint une unité de Wardancers est considéré avoir la règle Dances of Loec tant qu'il reste avec l'unité.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/troubadour-of-loec`},
  "woodland-ambush": {name:`Woodland Ambush`,desc:`Après le placement du décor, le joueur Wood Elf peut placer un bois supplémentaire (3" à 9" de large) n'importe où hors de la zone de déploiement adverse et à plus de 12" du centre du champ de bataille.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/woodland-ambush`},
  "worthy-of-kurnous": {name:`Worthy of Kurnous`,desc:`Après déploiement, avant le 1er tour : désigner un personnage ou un monstre ennemi. Tous les modèles d'une armée Orion's Wild Hunt amie relancent les jets pour Toucher de 1 naturel (Tir/Combat) contre cette unité. +100 PV si le modèle désigné est tué ou fuit en fin de partie.`,army:`Wood Elf Realms`,url:`https://tow.whfb.app/special-rules/worthy-of-kurnous`},
  "spirit-of-galrauch": {name:`Spirit of Galrauch`,desc:`En sous-phase de Start of Turn de chacun de vos tours, faire un test de Cd pour Galrauch. Réussi : contrôlé normalement. Raté (l'esprit se rebelle) : Niveau de Magie réduit à 1 (un seul sort/tour), soumis à Random Movement (2D6), et s'il est au combat il doit diriger D3 de ses attaques contre lui-même (les blessures qu'il s'inflige s'ajoutent au résultat de combat ennemi).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/spirit-of-galrauch`},
  "hellcannon-misfire-table": {name:`Hellcannon Misfire Table`,desc:`Jet D6 : 1 Free at Last! (le Daemon se libère : chaque unité ami/ennemi à 3D6" subit D6 touches de Force 5, AP -1, puis le Hellcannon est retiré) ; 2-4 Chomp! (retirer un Chaos Dwarf Handler) ; 5-6 Blooood! (le Hellcannon bouge de 3D6" comme en Random Movement / Mouvements Obligatoires).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/hellcannon-misfire-table`},
  "steeds-of-darkness": {name:`Steeds of Darkness`,desc:`Quand une unité de cavalerie ou char de cette armée fait un jet de Charge, de Fuite ou de Poursuite, elle peut relancer les dés montrant un 1 naturel, avant d'écarter les dés à écarter.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/steeds-of-darkness`},
  "warped-form": {name:`Warped Form`,desc:`Quand le combat de cette unité (Skin Wolves) est choisi (Étape 1.1 Choose & Fight), choisir une Transfiguration jusqu'au prochain Start of Turn : Enlarged Claws (+1 AP des armes + Armour Bane (2)) ; Barbed Protrusions (Extra Attacks (+1)) ; Toughened Flesh (+1 Endurance et +2 à la valeur d'armure).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/warped-form`},
  "warpfire-aura": {name:`Warpfire Aura`,desc:`Les autres modèles (ami et ennemi) n'ont droit à aucune sauvegarde Ward tant qu'ils sont à moins de 3" de ce modèle.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/warpfire-aura`},
  "mark-of-khorne": {name:`Mark of Khorne`,desc:`Les modèles avec la Marque de Khorne ont la règle Frénésie (Frenzy).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/mark-of-khorne`},
  "mark-of-nurgle": {name:`Mark of Nurgle`,desc:`Toute figurine ennemie qui dirige ses attaques contre un modèle avec la Marque de Nurgle en phase de Combat doit relancer ses jets pour Toucher de 6 naturel.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/mark-of-nurgle`},
  "mark-of-slaanesh": {name:`Mark of Slaanesh`,desc:`Les modèles avec la Marque de Slaanesh ont +1 en Initiative au premier round de combat. De plus, si la majorité de l'unité a la Marque de Slaanesh, l'unité réussit automatiquement ses tests de Panique.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/mark-of-slaanesh`},
  "mark-of-tzeentch": {name:`Mark of Tzeentch`,desc:`Les modèles avec la Marque de Tzeentch ont Flaming Attacks et Magic Resistance (-1). De plus, un Magicien avec la Marque ayant rejoint une unité de même Marque (Force d'Unité 10+) applique +1 à ses jets d'Incantation (perdu s'il quitte l'unité ou si FU < 10).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/mark-of-tzeentch`},
  "favour-of-the-gods": {name:`Favour of the Gods`,desc:`Dans une armée Wolves of the Sea, si un personnage tue son adversaire en défi, il jette immédiatement sur la table Gaze of the Gods. De plus, si une unité capture l'étendard ennemi comme trophée, elle jette sur Gaze of the Gods ('ce modèle' → 'cette unité').`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/favour-of-the-gods`},
  "cursed-by-the-gods": {name:`Cursed by the Gods`,desc:`Les Gigantic Spawn adoptent les traits du dieu qui les a maudits : voir Gigantic Spawn of Khorne / Nurgle / Slaanesh / Tzeentch.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/cursed-by-the-gods`},
  "praising-the-gods": {name:`Praising the Gods`,desc:`1×/partie, en sous-phase de Commandement, une unité d'un Chaotic Cult peut implorer son patron via un test de Cd. Réussi : jusqu'au prochain Start of Turn, les modèles du Culte gagnent le bénéfice de leur Culte (Bloodied Hound / Carrion Crow / Slithering Serpent / Fell Raptor).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/praising-the-gods`},
  "relentless-warriors": {name:`Relentless Warriors`,desc:`Un modèle avec cette règle a une sauvegarde Ward 6+ contre les blessures causées par une attaque ennemie non magique.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/relentless-warriors`},
  "forsaken-by-khorne": {name:`Forsaken by Khorne`,desc:`L'unité a la règle Hatred (tous les ennemis).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/forsaken-by-khorne`},
  "forsaken-by-nurgle": {name:`Forsaken by Nurgle`,desc:`L'unité a la règle Peur (Fear).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/forsaken-by-nurgle`},
  "forsaken-by-slaanesh": {name:`Forsaken by Slaanesh`,desc:`L'unité a la règle Swiftstride.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/forsaken-by-slaanesh`},
  "forsaken-by-tzeentch": {name:`Forsaken by Tzeentch`,desc:`L'unité a la règle Magic Resistance (-3).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/forsaken-by-tzeentch`},
  "gigantic-spawn-of-khorne": {name:`Gigantic Spawn of Khorne`,desc:`Les Gigantic Spawn of Khorne ont Impact Hits (D3) et Killing Blow.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/gigantic-spawn-of-khorne`},
  "gigantic-spawn-of-nurgle": {name:`Gigantic Spawn of Nurgle`,desc:`Les Gigantic Spawn of Nurgle ont Poisoned Attacks et Regeneration (5+).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/gigantic-spawn-of-nurgle`},
  "gigantic-spawn-of-slaanesh": {name:`Gigantic Spawn of Slaanesh`,desc:`Les Gigantic Spawn of Slaanesh ont Counter Charge et Strike First.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/gigantic-spawn-of-slaanesh`},
  "gigantic-spawn-of-tzeentch": {name:`Gigantic Spawn of Tzeentch`,desc:`Les Gigantic Spawn of Tzeentch ont Flaming Attacks, Magical Attacks et Magic Resistance (-2).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/gigantic-spawn-of-tzeentch`},
  "spawn-of-khorne": {name:`Spawn of Khorne`,desc:`Les Spawn of Khorne ont la règle Killing Blow.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/spawn-of-khorne`},
  "spawn-of-nurgle": {name:`Spawn of Nurgle`,desc:`Les Spawn of Nurgle ont la règle Poisoned Attacks.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/spawn-of-nurgle`},
  "spawn-of-slaanesh": {name:`Spawn of Slaanesh`,desc:`Les Spawn of Slaanesh ont la règle Strike First.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/spawn-of-slaanesh`},
  "spawn-of-tzeentch": {name:`Spawn of Tzeentch`,desc:`Les Spawn of Tzeentch ont Flaming Attacks et Magical Attacks.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/spawn-of-tzeentch`},
  "chaotic-cults": {name:`Chaotic Cults`,desc:`Les Marauder Tribes ont la Marque de Chaos Indivis ; certains peuvent la remplacer par la Marque d'un dieu. Les Chaos Marauders et Marauder Horsemen peuvent à la place appartenir à un 'Chaotic Cult'. Un modèle n'appartient qu'à un seul Culte ; un perso marqué peut rejoindre une unité de n'importe quel Culte.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/chaotic-cults`},
  "cult-of-the-bloodied-hound": {name:`Cult of the Bloodied Hound`,desc:`Les modèles de ce Chaotic Cult gagnent +1 en Capacité de Combat (WS).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/cult-of-the-bloodied-hound`},
  "cult-of-the-carrion-crow": {name:`Cult of the Carrion Crow`,desc:`Les modèles de ce Chaotic Cult gagnent +1 en Endurance (T).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/cult-of-the-carrion-crow`},
  "cult-of-the-fell-raptor": {name:`Cult of the Fell Raptor`,desc:`Les modèles de ce Chaotic Cult gagnent une sauvegarde Ward 6+ contre les blessures causées par une attaque ennemie non magique.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/cult-of-the-fell-raptor`},
  "cult-of-the-slithering-serpent": {name:`Cult of the Slithering Serpent`,desc:`Les modèles de ce Chaotic Cult gagnent la règle Poisoned Attacks.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/cult-of-the-slithering-serpent`},
  "mounted-host": {name:`Mounted Host`,desc:`Tous les personnages d'une armée Heralds of Darkness doivent être montés ou avoir Fly (X).`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/mounted-host`},
  "sea-born-raiders": {name:`Sea-Born Raiders`,desc:`Dans une armée Wolves of the Sea, les Chaos Marauders et Marauder Horsemen peuvent avoir Ambushers pour +1 pt/figurine ; les Aspiring Champions d'infanterie/cavalerie pour +10 pts.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/sea-born-raiders`},
  "explosive-demise": {name:`Explosive Demise`,desc:`Quand un Warpfire Dragon perd son dernier PV, avant de le retirer, chaque unité (ami/ennemi) à <6" subit D6 touches de Force 5, AP -2.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/explosive-demise`},
  "fire-and-chaos": {name:`Fire & Chaos`,desc:`Les Warpfire Dragons ont une sauvegarde Ward 5+ contre les blessures causées par une attaque ayant Magical Attacks ou Flaming Attacks.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/fire-and-chaos`},
  "the-shadow-grows": {name:`The Shadow Grows`,desc:`Pour chaque personnage avec une Marque de Chaos (autre qu'Indivis), l'armée doit inclure une unité non-personnage de même Marque, et inversement.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/the-shadow-grows`},
  "warriors-duel": {name:`Warriors' Duel`,desc:`Au lieu du roll-off du premier tour, défier l'adversaire à un Warrior's Duel. Accepté : chaque joueur choisit un champion d'unité (PV 1, infanterie/cavalerie) ; ils combattent comme en défi jusqu'à un vainqueur, dont le joueur prend le 1er tour. Décliné : l'armée Wolves of the Sea gagne le 1er tour. (Bretonnie qui accepte = a prié pour la Bénédiction ; qui décline = la perd.)`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/warriors-duel`},
  "breath-of-change": {name:`Breath of Change`,desc:`1×/partie, au lieu de Dark Fire of Chaos / Fumes of Contagion, Galrauch peut utiliser le Breath of Change : gabarit de souffle ; toute figurine touchée (ami/ennemi) fait un test d'Endurance ; raté = retirée comme perte ; réussi = aucun effet.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/breath-of-change`},
  "caged-fury": {name:`Caged Fury`,desc:`En sous-phase de Start of Turn de chacun de vos tours, faire un test de Commandement pour ce modèle (Hellcannon). Raté = jet immédiat sur la table de Hellcannon Misfire.`,army:`Warriors of Chaos`,url:`https://tow.whfb.app/special-rules/caged-fury`},
  "accursed-weapons": {name:`Accursed Weapons`,desc:`Une arme de main portée par un modèle avec cette règle gagne Magical Attacks et un Armour Piercing de -1.`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/accursed-weapons`},
  "balefire-brazier": {name:`Balefire Brazier`,desc:`Les Magiciens ennemis à <15" d'un ou plusieurs modèles avec cette règle doivent augmenter de 1 la valeur d'incantation de leurs sorts.`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/balefire-brazier`},
  "banner-of-the-count": {name:`Banner of the Count`,desc:`Un Vampire Thrall Porteur de la Bannière de Bataille remplace « Hold Your Ground » : les unités amies à portée de Commandement relancent les tests de Cd ratés ET réduisent de D3 les PV perdus par Unstable. Non cumulatif avec Indomitable (prendre le plus haut).`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/banner-of-the-count`},
  "bestial-fury": {name:`Bestial Fury`,desc:`Les unités ennemies ne peuvent réclamer aucun point de résultat de combat pour être engagées sur le flanc ou l'arrière de ce modèle (Varghulf).`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/bestial-fury`},
  "bound-spirits": {name:`Bound Spirits`,desc:`Contrairement aux autres swarms, cette unité n'est pas soumise à Undisciplined : elle peut bénéficier de l'Inspiring Presence du Général et du « Hold Your Ground » d'une Bannière de Bataille.`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/bound-spirits`},
  "the-death-of-a-general": {name:`The Death of a General`,desc:`Le Général d'une armée Vampire Counts doit être un Magicien. S'il est tué : toutes les unités Necromantic Undead amies perdent Regeneration ; et à la fin de la phase de sa mort puis à chaque Start of Turn, chaque unité Necromantic Undead fait un test de Cd — raté = perte de PV égale à la marge d'échec.`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/the-death-of-a-general`},
  "implacable-defence": {name:`Implacable Defence`,desc:`Une unité avec cette règle en Close Order équipée de boucliers et choisissant de les utiliser peut choisir de ne pas Céder du Terrain si elle perd un round de combat. Exception : si la Force d'Unité du gagnant est plus du double de celle du perdant, elle doit Céder du Terrain normalement.`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/implacable-defence`},
  "martial-pride": {name:`Martial Pride`,desc:`Chaque figurine d'une unité de Blood Knights peut lancer et accepter des défis comme un personnage. Mais l'unité ne peut refuser un défi : si un défi est lancé et qu'une figurine peut l'accepter, elle doit l'accepter.`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/martial-pride`},
  "spectral-coach": {name:`Spectral Coach`,desc:`Un Black Coach peut devenir 'Incorporeal' en sous-phase de Commandement, jusqu'au prochain Start of Turn. Incorporeal : perd Impact Hits (D6+2), gagne Ethereal et Fly (10).`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/spectral-coach`},
  "spectral-reapers": {name:`Spectral Reapers`,desc:`Une unité avec cette règle (Hexwraiths) peut faire une attaque 'Spectral Reapers' contre une unité ennemie non engagée en la survolant en sous-phase de Mouvements Restants : la cible subit, par figurine ayant survolé, une touche de Force 4 sans armure (Ward/Régén OK), avec Flaming Attacks et Magical Attacks.`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/spectral-reapers`},
  "warped-tintinnabulation": {name:`Warped Tintinnabulation`,desc:`Quand une unité amie à <15" récupère des PV via Invocation of Nehek, jet D6 : sur 4+ elle récupère 1 PV de plus. De plus, les unités amies à <15" réduisent de 1 les PV perdus par Unstable. Cumulatif avec Indomitable.`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/warped-tintinnabulation`},
  "wight-banner": {name:`Wight Banner`,desc:`Un Wight Lord Porteur de la Bannière de Bataille remplace « Hold Your Ground » : les unités amies à portée de Commandement relancent les tests de Cd ratés ET réduisent de D3 les PV perdus par Unstable. Non cumulatif avec Indomitable.`,army:`Vampire Counts`,url:`https://tow.whfb.app/special-rules/wight-banner`},
  "authority-of-the-hierophant": {name:`Authority of the Hierophant`,desc:`Une armée Mortuary Cult doit inclure au moins un Liche Priest comme Hierophant ; ce Hierophant doit aussi être le Général, même s'il n'a pas le plus haut Commandement.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/authority-of-the-hierophant`},
  "banner-of-the-king": {name:`Banner of the King`,desc:`Un Royal Herald porté en Porteur de la Bannière de Bataille remplace « Hold Your Ground » par : les unités amies à portée de Commandement relancent les tests de Cd ratés ET réduisent de D3 les PV perdus par Unstable. Non cumulatif avec Indomitable (prendre la plus haute valeur).`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/banner-of-the-king`},
  "commander-of-legions": {name:`Commander of Legions`,desc:`Settra gagne la règle Arise! et, contrairement aux autres, peut l'utiliser même engagé au combat.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/commander-of-legions`},
  "eternal-taskmaster": {name:`Eternal Taskmaster`,desc:`En sous-phase de Commandement, test de Cd ; réussi : jusqu'au prochain Start of Turn, ce personnage et l'unité rejointe gagnent Extra Attacks (+1) et Hatred (tous ennemis).`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/eternal-taskmaster`},
  "grind-them-down": {name:`"Grind Them Down!"`,desc:`À portée de Commandement du Général, les modèles amis de type Char peuvent relancer le dé déterminant le nombre d'Impact Hits qu'ils causent.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/grind-them-down`},
  "harmonious-incantations": {name:`Harmonious Incantations`,desc:`Si un Liche Priest d'une armée Mortuary Cult utilise Arise! à portée de Commandement d'un ou plusieurs autres Liche Priests amis, le nombre de PV récupérés est augmenté de 1.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/harmonious-incantations`},
  "herald-of-despair": {name:`Herald of Despair`,desc:`Toute unité ennemie au contact de Nekaph (ou d'une unité qu'il a rejointe) jette un D6 supplémentaire lors d'un test de Peur ou Terreur, et écarte le résultat le plus bas.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/herald-of-despair`},
  "the-hierophant": {name:`The Hierophant`,desc:`L'armée doit inclure un Liche Priest comme Hierophant (le plus haut Niveau de Magie). S'il est tué : toutes les unités Nehekharan Undead amies perdent Regeneration ; et à la fin de la phase de sa mort puis à chaque Start of Turn, chaque unité Nehekharan Undead fait un test de Cd — raté = perte de PV égale à la marge d'échec.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/the-hierophant`},
  "the-language-of-the-priests": {name:`The Language of the Priests`,desc:`Le Général d'un Nehekharan Royal Host doit être un Tomb King ou Tomb Prince. Pour +35 pts, il peut avoir Arise! et être Magicien Niveau 1 (Lore de Necromancy) et devient l'Hierophant. Un Magicien avec cette règle peut porter une armure sans pénalité.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/the-language-of-the-priests`},
  "lay-in-wait": {name:`Lay In Wait`,desc:`0-1 unité de Skeleton Skirmishers par 1000 pts peut avoir Ambushers gratuitement.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/lay-in-wait`},
  "masterful-outriders": {name:`Masterful Outriders`,desc:`0-1 unité de Skeleton Horse Archers par 1000 pts peut avoir Chariot Runners gratuitement.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/masterful-outriders`},
  "my-will-be-done": {name:`My Will Be Done`,desc:`En sous-phase de Commandement, test de Cd ; réussi : choisir un modificateur jusqu'au prochain Start of Turn pour ce personnage, sa monture et l'unité rejointe (max 10) — Forward to Glory! (+D3 M), My Worthy Champions! (+1 CC), Strike like the Cobra! (+D3 I). Non cumulatif.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/my-will-be-done`},
  "nehekharan-phalanx": {name:`Nehekharan Phalanx`,desc:`Une unité avec cette règle en Close Order équipée de boucliers et choisissant de les utiliser peut choisir de ne pas Céder du Terrain (Give Ground) si elle perd un round de combat. Exception : si la Force d'Unité du gagnant est plus du double de celle du perdant, elle doit Céder du Terrain normalement.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/nehekharan-phalanx`},
  "resurrecting-the-fallen": {name:`Resurrecting the Fallen`,desc:`Soin/résurrection dans un ordre strict : 1) personnages rejoints (un personnage mort ne peut être ressuscité) ; 2) figurines à plusieurs PV (chacune soignée à fond avant la suivante) ; 3) champion, puis porte-étendard, puis musicien ; 4) figurines de base. Au moins une figurine doit subsister ; jamais au-delà de la taille de départ.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/resurrecting-the-fallen`},
  "scarab-prince": {name:`Scarab Prince`,desc:`Si Prince Apophas perd son dernier PV, avant de le retirer, toutes les unités ennemies à 2D6" subissent 2D6 touches de Force 2, AP -1.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/scarab-prince`},
  "screaming-skulls": {name:`Screaming Skulls`,desc:`Toute unité subissant une ou plusieurs blessures non sauvegardées de cette arme doit faire un test de Panique comme si elle avait subi de lourdes pertes.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/screaming-skulls`},
  "sepulchral-animus": {name:`Sepulchral Animus`,desc:`Une fois par tour, avant un jet d'Incantation, un Liche Priest d'une armée Mortuary Cult peut puiser dans un construct mort-vivant ami à portée de Commandement (swarm/monstrueux/monstre/behemoth) : l'unité nominée perd 1 PV, puis le prêtre applique +1 à son jet d'Incantation (ne nie pas un double 1 naturel).`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/sepulchral-animus`},
  "settra-does-not-kneel": {name:`Settra Does Not Kneel!`,desc:`Settra doit toujours accepter un défi, sauf si Nekaph est engagé dans le même combat — auquel cas Nekaph doit accepter le défi à sa place.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/settra-does-not-kneel`},
  "settra-the-great": {name:`Settra the Great`,desc:`Si l'armée inclut Settra, il doit être le Général et l'Hierophant (même sans le plus haut Niveau de Magie). De plus, Settra a une portée de Commandement de 18".`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/settra-the-great`},
  "settras-champion": {name:`Settra's Champion`,desc:`Nekaph doit toujours lancer et accepter les défis si possible ; ses défis ne peuvent être refusés. Engagé dans un défi, il porte un Killing Blow sur un 5 ou 6 naturel pour Blesser (au lieu du 6 habituel).`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/settras-champion`},
  "skulls-of-the-foe": {name:`Skulls of the Foe`,desc:`Jusqu'au prochain Start of Turn, toute unité ennemie à 2D6" du centre du gabarit (après déviation) subit -1 en Commandement (min 2).`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/skulls-of-the-foe`},
  "soul-reaper": {name:`Soul Reaper`,desc:`Après le déploiement mais avant le 1er tour, désigner un personnage ennemi. Ce modèle peut relancer ses jets pour Toucher de 1 naturel contre le personnage désigné.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/soul-reaper`},
  "steadfast-discipline": {name:`Steadfast Discipline`,desc:`Une unité avec cette règle peut faire un Volley Fire lors d'un tour où elle a bougé, ou en réaction de charge Stand & Shoot.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/steadfast-discipline`},
  "stone-shaper": {name:`Stone Shaper`,desc:`En sous-phase de Commandement, hors combat, ce personnage nomme un Necrolith Colossus, Necrosphinx, ou une unité d'Ushabti/Venerable Ushabti ami(e) à portée de Commandement : jusqu'à la fin du tour, l'unité améliore de 1 sa valeur de Régénération.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/stone-shaper`},
  "sworn-protector": {name:`Sworn Protector`,desc:`Si un Monarque de Nehekhara subit une touche à <3" de ce modèle, vous pouvez transférer cette touche et tous ses effets sur ce modèle.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/sworn-protector`},
  "the-terrors-below": {name:`The Terrors Below`,desc:`Un Tomb Scorpion ou une unité de Necroserpents peut avoir cette règle pour +2 pts/figurine. Placé via From Beneath the Sands, il peut nommer une unité ennemie d'infanterie à <8" : celle-ci fait un nombre de tests d'Initiative égal à la Force d'Unité de l'attaquant ; chaque échec = 1 figurine retirée.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/the-terrors-below`},
  "usirians-reaper": {name:`Usirian's Reaper`,desc:`Après le déploiement, nommer un personnage de la liste adverse. Apophas peut relancer ses jets ratés pour Toucher ou Blesser contre lui ; ses touches contre ce personnage gagnent Magical Attacks.`,army:`Tomb Kings of Khemri`,url:`https://tow.whfb.app/special-rules/usirians-reaper`},
  "abominable-attacks": {name:`Abominable Attacks`,desc:`Au lieu d'attaquer normalement, une Hell Pit Abomination peut faire une Abominable Attack : Feed (1 figurine au contact subit D3 blessures auto sans armure ; Ward/Régén OK) ou Avalanche of Flesh (gabarit 3" centré, touches de Force du modèle AP -2).`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/abominable-attacks`},
  "avalanche-of-flesh": {name:`Avalanche of Flesh`,desc:`Placer un petit gabarit (3") centré sur l'unité cible. Toute figurine (ami/ennemi, sauf ce modèle) sous le gabarit risque une touche de Force du modèle, AP -2.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/avalanche-of-flesh`},
  "crushing-bulk": {name:`Crushing Bulk`,desc:`Les Stomp Attacks d'un Doomwheel ont un Armour Piercing de -1. De plus, une unité ennemie subissant des Impact Hits de ce modèle fait immédiatement un test de Commandement ; échoué = Disrupted jusqu'à la fin de la phase de Combat.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/crushing-bulk`},
  "deploying-weapon-teams": {name:`Deploying Weapon Teams`,desc:`Un Weapon Team doit être déployé en même temps que son unité 'parente' (celle pour laquelle il a été acheté), à moins de 3" d'elle.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/deploying-weapon-teams`},
  "eshin-infiltration": {name:`Eshin Infiltration`,desc:`Quand une unité amie de Gutter Runners avec Ambushers arrive de réserve, elle peut être placée n'importe où entièrement à 12" d'un Master Assassin révélé, mais pas à <6" d'ennemis (au lieu d'entrer en renforts). Elle ne peut pas charger ce tour et compte comme ayant bougé. Inutilisable tant que l'assassin est caché.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/eshin-infiltration`},
  "feed": {name:`Feed`,desc:`Désigner une figurine ennemie au contact de la Hell Pit Abomination : si touchée, elle subit D3 blessures automatiques sans sauvegarde d'armure (Ward et Régénération autorisées).`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/feed`},
  "hidden-skaven": {name:`Hidden (Skaven)`,desc:`Les Master Assassins ne sont pas déployés au départ : ils sont 'cachés' dans une unité Skaven d'infanterie amie de Force d'Unité 10+. Révélables en sous-phase de Start of Turn ou au début d'une phase de Combat (placés comme un personnage rejoignant l'unité). Si l'unité est détruite/fuit avant révélation, l'assassin est retiré. Ne peut être Général.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/hidden-skaven`},
  "leader-of-the-pack-skaven": {name:`Leader of the Pack (Skaven)`,desc:`Modèles pris seulement dans une unité de Rat Ogres ou Giant Rats. Ils (y compris le commandement) se placent à l'arrière de l'unité ; les Rat Ogres/Giant Rats occupent toujours les rangs de front. Un Master Moulder peut lancer/accepter des défis même hors du rang de combat.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/leader-of-the-pack-skaven`},
  "lightning-strike": {name:`Lightning Strike`,desc:`En tirant, tracer une ligne droite de 8D6" depuis le bord du socle. Toute figurine (ami/ennemi) sous la ligne subit une touche dont la Force est déterminée par un dé d'artillerie. Misfire → table de Warp Lightning Misfire (Meltdown : détruit ; Energy Overload : Force 6 direction aléatoire ; Fzzzt : pas de tir).`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/lightning-strike`},
  "pavise": {name:`Pavise`,desc:`Une pavise donne une valeur d'armure 4+ contre les attaques ennemies situées dans l'arc avant du porteur. Aucune protection contre les attaques de flanc ou d'arrière.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/pavise`},
  "poisoned-wind": {name:`Poisoned Wind`,desc:`Pour Blesser avec une arme ayant cette règle, un 6+ est toujours une réussite (même si l'Endurance est trop haute). Aucune sauvegarde d'armure permise (Ward/Régén OK). Les porteurs de ces armes sont immunisés à cette règle.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/poisoned-wind`},
  "safe-from-harm": {name:`Safe From Harm`,desc:`Quand l'ennemi tire sur une unité de Rat Ogres contenant un ou plusieurs Packmasters, l'adversaire jette un D6 par touche réussie avant de Blesser : sur 1-4 la touche frappe un Rat Ogre. Au combat, l'ennemi doit allouer ses attaques sur une figurine au contact (ou la plus proche du rang de combat) avant de jeter pour Toucher.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/safe-from-harm`},
  "targeting-weapon-teams": {name:`Targeting Weapon Teams`,desc:`À moins de 3" de son unité parente (contenant 5+ figurines et ne fuyant pas), un Weapon Team ne peut être ciblé par le tir ou les sorts ennemis, sauf s'il est la cible la plus proche.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/targeting-weapon-teams`},
  "too-horrible-to-die": {name:`Too Horrible To Die`,desc:`La 1re fois qu'une Hell Pit Abomination perd son dernier PV, jet D6 avant de la retirer : 1-3 retirée ; 4-5 placer un Rat Swarm (1 figurine) à <3" puis la retirer ; 6 elle récupère immédiatement D3 PV.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/too-horrible-to-die`},
  "weapon-team-leadership": {name:`Weapon Team Leadership`,desc:`À moins de 3" de son unité parente, un Weapon Team gagne un modificateur positif à son Commandement égal au bonus de rang de l'unité parente, jusqu'à un maximum de Commandement 10.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/weapon-team-leadership`},
  "zzzzap": {name:`Zzzzap!`,desc:`À la fin de chaque phase de Tir, placer jusqu'à trois petits gabarits (3") dont le centre est à <6" de ce modèle ; chacun dévie de D6". Toute figurine sous un gabarit subit une touche de Force déterminée par un dé d'artillerie, AP -2. Misfire = le gabarit est retiré, ce modèle perd 1 PV.`,army:`Skaven`,url:`https://tow.whfb.app/special-rules/zzzzap`},
  "big-stabbas": {name:`Big Stabbas`,desc:`Une unité avec Big Stabbas a la règle Impact Hits (D3). Cette règle s'applique à l'unité dans son ensemble, pas aux figurines individuelles.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/big-stabbas`},
  "big-uns": {name:`Big 'Uns`,desc:`Engagé au combat, un modèle avec cette règle a +1 en Force et gagne la règle Armour Bane (1).`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/big-uns`},
  "bully": {name:`Bully`,desc:`Un Orc Bully est un type de personnage pris en amélioration pour accompagner une machine de guerre. Déployé avec sa machine comme un personnage rejoignant une unité ; il ne peut plus la quitter. Sauf s'il fuit, les machines amies à portée de Commandement peuvent utiliser son Commandement au lieu du leur.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/bully`},
  "cunning-hunters": {name:`Cunning Hunters`,desc:`Dans une armée Nomadic Waaagh!, n'importe quel nombre de Goblin Wolf Rider Mobs peut avoir Ambushers pour +1 pt/figurine. De plus, les Goblin Bosses et Shamans montés sur Giant Wolf peuvent avoir Ambushers pour +10 pts.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/cunning-hunters`},
  "da-troll-calla": {name:`Da Troll Calla`,desc:`Sauf s'il fuit, les Troll Mobs amis à portée de Commandement d'Ogdruz peuvent utiliser son Commandement au lieu du leur.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/da-troll-calla`},
  "enhanced-regeneration": {name:`Enhanced Regeneration`,desc:`Les modèles avec Regeneration (X+) dans une armée Troll Horde peuvent relancer les sauvegardes de Régénération ratées contre les blessures causées par des attaques non magiques.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/enhanced-regeneration`},
  "hit-em-fast-and-hit-em-ard": {name:`Hit 'em Fast and Hit 'em 'Ard!`,desc:`Dans une Nomadic Waaagh!, tout modèle Orc monté sur War Boar gagne Impact Hits (1) (Force du War Boar, AP -1). De plus, 0-1 Boar Boyz Mob par 1000 pts peut avoir Vanguard pour +1 pt/figurine.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/hit-em-fast-and-hit-em-ard`},
  "hunting-packs": {name:`Hunting Packs`,desc:`Tout Goblin Wolf Rider Mob dans une Nomadic Waaagh! peut échanger Open Order + Skirmishers contre Close Order + Horde.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/hunting-packs`},
  "indiscriminate-hunger": {name:`Indiscriminate Hunger`,desc:`En sous-phase de Commandement, une Troll Hag engagée au combat peut faire une attaque 'Indiscriminate Hunger' : l'unité ennemie ciblée fait un test d'Initiative. Échoué : elle perd 1 PV (et la Troll Hag récupère 1 PV). Réussi : aucun effet.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/indiscriminate-hunger`},
  "mob-rule": {name:`Mob Rule`,desc:`Si ce personnage a rejoint une unité d'Orcs avec une Force d'Unité de 10+, il applique +1 à ses jets d'Incantation. Perdu s'il quitte l'unité ou si la FU tombe sous 10.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/mob-rule`},
  "bonegrinder-giant-attacks": {name:`Bonegrinder Giant Attacks`,desc:`Au lieu d'attaquer normalement, un Bonegrinder Giant fait une 'Bonegrinder Giant Attack' : désigner une unité ennemie engagée, jet sur la table selon le type (Little/Big/Bigger Things). Résultats : Crush Underfoot, Grind its Bones, Vomit, Wallop, Mighty Swing, 'Eadbutt selon le D6 et la taille de la cible.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/bonegrinder-giant-attacks`},
  "crush-underfoot": {name:`Crush Underfoot`,desc:`Le Bonegrinder Giant piétine l'ennemi. Placer un grand gabarit (5") centré sur l'unité cible. Toute figurine (ami ou ennemi, sauf le Géant) sous le gabarit risque une touche utilisant la Force du Géant, AP -3.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/crush-underfoot`},
  "eadbutt-bonegrinder-giant": {name:`'Eadbutt (Bonegrinder Giant)`,desc:`Le Bonegrinder Giant donne un coup de tête. L'unité cible subit une touche infligeant D3+1 blessures sans sauvegarde d'armure ni Régénération (Ward autorisée).`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/eadbutt-bonegrinder-giant`},
  "grind-its-bones": {name:`Grind its Bones`,desc:`Chaque figurine du rang de combat de l'unité cible fait un test d'Initiative. Échoué : retirée comme perte. Réussi : indemne. Les personnages peuvent faire un Look Out, Sir!.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/grind-its-bones`},
  "ker-splat": {name:`Ker-splat`,desc:`Les Mangler Squigs traitent tout terrain difficile comme terrain dangereux.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/ker-splat`},
  "mighty-swing-bonegrinder-giant": {name:`Mighty Swing (Bonegrinder Giant)`,desc:`Le Bonegrinder Giant balaie son gourdin : l'unité cible subit D6+1 touches de Force S+1, AP -2.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/mighty-swing-bonegrinder-giant`},
  "motherly-love": {name:`Motherly Love`,desc:`Au lieu d'attaquer normalement, une Troll Hag fait une attaque 'Motherly Love' : jet D6. 1-2 Smother (gabarit 5", touche Force du Troll Hag AP -2) ; 3-4 Mother (1 figurine, D3+1 blessures sans armure ni Régén, Ward OK) ; 5-6 Mither (D6+1 touches Force du Troll Hag sans armure, Ward/Régén OK, et -1 Cd à la cible jusqu'à la fin du tour).`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/motherly-love`},
  "netters": {name:`Netters`,desc:`Quand le combat de cette unité est choisi (Étape 1.1 de Choose & Fight), elle peut tenter d''entangler' une unité ennemie engagée : D6, sur 1 elle s'entrave elle-même, sur 2+ l'ennemi est entravé. Jusqu'à la fin de la phase de Combat, l'unité entravée subit -1 en Force (min 1). Non cumulatif.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/netters`},
  "oi-dis-way": {name:`Oi! Dis Way!`,desc:`Sauf si le personnage fuit, les Troll Mobs amis d'une armée Troll Horde à portée de Commandement d'un Orc Shaman, Goblin Shaman ou Troll Hag peuvent utiliser le Commandement de ce personnage.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/oi-dis-way`},
  "on-da-move": {name:`On Da Move`,desc:`Tous les personnages d'une armée Nomadic Waaagh! doivent être montés.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/on-da-move`},
  "protect-da-boss": {name:`Protect Da Boss`,desc:`Ce modèle ne peut pas être ciblé par le tir ou les sorts ennemis tant qu'il est à <3" d'un Troll Mob ami, sauf s'il est la cible la plus proche.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/protect-da-boss`},
  "skulking-menace": {name:`Skulking Menace`,desc:`Les Nasty Skulkers ne sont pas déployés au départ ; noter quels Goblin Mobs en cachent. Au début de leur 1er round de combat (Étape 1.1 Choose & Fight), l'unité dissimulante doit les révéler (placés comme un personnage rejoignant l'unité). Ils ne peuvent plus la quitter.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/skulking-menace`},
  "slimy-shanks": {name:`Slimy Shanks`,desc:`Toute figurine ennemie qui dirige ses attaques contre ce modèle en phase de Combat subit -1 à ses jets pour Toucher.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/slimy-shanks`},
  "solitary-fighters": {name:`Solitary Fighters`,desc:`Les Black Orc Bosses d'une armée Nomadic Waaagh! ne sont pas soumis aux règles Da Boyz ni Quell Impetuosity.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/solitary-fighters`},
  "spiked-ball-and-chains": {name:`Spiked Ball & Chains`,desc:`Les Impact Hits causés par ce modèle ont un Armour Piercing de -3.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/spiked-ball-and-chains`},
  "squigs-go-wild": {name:`Squigs Go Wild`,desc:`Si un Squig Herd se brise et fuit, et contient 5+ Cave Squigs, chaque unité (ami ou ennemi) à 2D6" subit D3 touches de Force 5, AP -1 (+1 au D3 par tranche de 5 Cave Squigs supplémentaires). Puis l'unité est retirée comme détruite.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/squigs-go-wild`},
  "syphoned-strength": {name:`Syphoned Strength`,desc:`Tant qu'Ogdruz Swampdigga est à <3" d'un Troll Mob ami de Force d'Unité 6+ qui ne fuit pas, il applique +1 à ses jets d'Incantation.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/syphoned-strength`},
  "troll-tongue": {name:`Troll Tongue`,desc:`En plus des Lores normaux, les Orc Shamans et Goblin Shamans d'une armée Troll Horde peuvent connaître des sorts du Lore of Troll Magic.`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/troll-tongue`},
  "wallop": {name:`Wallop`,desc:`Le Bonegrinder Giant frappe à deux mains : une seule attaque, gourdin de Force S+3, AP -4, avec Multiple Wounds (2D3).`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/wallop`},
  "warpaint": {name:`Warpaint`,desc:`Donne une sauvegarde Ward 6+ contre toute blessure. Le porteur ne peut jamais porter d'armure (mais peut porter un bouclier).`,army:`Orc & Goblin Tribes`,url:`https://tow.whfb.app/special-rules/warpaint`},
  "bellowers-and-musicians": {name:`Bellowers & Musicians`,desc:`La plupart des musiciens Ogres appartiennent à une caste de Hurleurs (Bellowers) : leur instrument est leur voix et leurs poumons. Fonctionne comme un musicien.`,army:`Ogre Kingdoms`,url:`https://tow.whfb.app/special-rules/bellowers-and-musicians`},
  "blessings-of-the-volcano-god": {name:`Blessings of the Volcano God`,desc:`Un modèle avec cette règle a une sauvegarde Ward 4+ contre toute blessure causée par une attaque ayant la règle Flaming Attacks (attaques enflammées).`,army:`Ogre Kingdoms`,url:`https://tow.whfb.app/special-rules/blessings-of-the-volcano-god`},
  "butchers-cauldron": {name:`Butcher's Cauldron`,desc:`Ce personnage remplace Impact Hits (2) par Impact Hits (D3+1). De plus, pendant la sous-phase de Commandement de son tour, s'il n'est pas engagé au combat, il peut tenter une offrande au Grand Maw via un test de Commandement (avec son propre Cd). Réussi : jusqu'à sa prochaine sous-phase de Début de Tour, lui et l'unité rejointe gagnent Regeneration (5+). Échoué : il perd immédiatement 1 PV.`,army:`Ogre Kingdoms`,url:`https://tow.whfb.app/special-rules/butchers-cauldron`},
  "look-out-gnoblar": {name:`Look-out Gnoblar`,desc:`Un champion ou personnage ayant rejoint une unité avec cette règle peut faire un jet « Look Out, Sir! » s'il y a au moins deux figurines de rang (au lieu des cinq habituelles). De plus, on peut relancer ce jet s'il y a cinq figurines de rang ou plus.`,army:`Ogre Kingdoms`,url:`https://tow.whfb.app/special-rules/look-out-gnoblar`},
  "mournfang-charge": {name:`Mournfang Charge`,desc:`Les Impact Hits causés par un modèle avec cette règle ont la règle Armour Bane (1) et une caractéristique Armour Piercing de -1.`,army:`Ogre Kingdoms`,url:`https://tow.whfb.app/special-rules/mournfang-charge`},
  "ravenous-hunger": {name:`Ravenous Hunger`,desc:`Quand un Gorger déclare une charge, il peut relancer son jet de Charge.`,army:`Ogre Kingdoms`,url:`https://tow.whfb.app/special-rules/ravenous-hunger`},
  "running-with-the-pack": {name:`Running with the Pack`,desc:`Un Hunter qui rejoint une unité de Sabretusks gagne Swiftstride tant qu'il reste avec l'unité. De plus, tant que le Hunter reste avec elle, les Sabretusks perdent la règle Impetuous.`,army:`Ogre Kingdoms`,url:`https://tow.whfb.app/special-rules/running-with-the-pack`},
  "traps-and-snares": {name:`Traps & Snares`,desc:`Toute figurine ennemie qui termine son mouvement de charge au contact socle à socle d'un modèle avec cette règle doit effectuer un test de Terrain Dangereux.`,army:`Ogre Kingdoms`,url:`https://tow.whfb.app/special-rules/traps-and-snares`},
  "primeval-roar": {name:`Primeval Roar`,desc:`Once per game, in the Command sub-phase, a Leadership test; if passed, until end of turn all friendly Lizardmen units within 7" gain Furious Charge.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/primeval-roar`},
  "guardians": {name:`Guardians`,desc:`If a friendly Slann within 3" suffers a hit in the Shooting phase, on a 2+ you may transfer it (and its effects) to this unit. Temple Guard within a Slann's Command range can issue/accept challenges like characters.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/guardians`},
  "beast-handlers": {name:`Beast Handlers`,desc:`When shooting a Salamander/Razordon Pack with Skink Handlers, roll a D6 per hit: 1-4 hits a beast, 5+ hits a Handler. In combat, enemies must allocate attacks to a model in base contact (or the closest in the fighting rank).`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/beast-handlers`},
  "skirmish-screen": {name:`Skirmish Screen`,desc:`A unit with this rule (Kroxigor) can draw line of sight over/through and move through friendly Skink Skirmisher units (nudge models aside). Skirmishing Skinks may count nearby models with this rule as part of the unit for coherency.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/skirmish-screen`},
  "engine-of-the-gods": {name:`Engine of the Gods`,desc:`An Ancient Stegadon with an Engine of the Gods gains Arcane Configuration & Burning Alignment. With 2+ Engines, friendly Wizards within 6" of one add +1 to Casting rolls. It casts a Bound Magic Missile (PL3, 8+, 15"): 2D6 Strength 4 Flaming hits.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/engine-of-the-gods`},
  "arcane-configuration": {name:`Arcane Configuration`,desc:`If your army has two or more Engines of the Gods, friendly Wizards may add +1 to any Casting roll while within 6" of an Engine of the Gods.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/arcane-configuration`},
  "burning-alignment": {name:`Burning Alignment`,desc:`Bound Magic Missile (PL3, casting 8+, 15"): the target suffers 2D6 Strength 4 Flaming hits.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/burning-alignment`},
  "solar-engine": {name:`Solar Engine`,desc:`A Bastiladon with a Solar Engine gains Solar Radiance & Beam of Chotec, and casts a Bound Magic Missile (PL2, 9+, 24"): 3D3 Strength 5 AP-2 Flaming hits.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/solar-engine`},
  "solar-radiance": {name:`Solar Radiance`,desc:`Whilst within 6" of one or more Solar Engines, friendly Cold Blooded units gain +1 Initiative.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/solar-radiance`},
  "beam-of-chotec": {name:`Beam of Chotec`,desc:`Bound Magic Missile (PL2, casting 9+, 24"): the target suffers 3D3 Strength 5 AP-2 Flaming hits.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/beam-of-chotec`},
  "ark-of-sotek": {name:`Ark of Sotek`,desc:`A Bastiladon with an Ark of Sotek gains Slithering Serpents & Spawn of Sotek.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/ark-of-sotek`},
  "slithering-serpents": {name:`Slithering Serpents`,desc:`During the Command sub-phase, every enemy unit within D6" of this model suffers 2D6 Strength 2 hits.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/slithering-serpents`},
  "spawn-of-sotek": {name:`Spawn of Sotek`,desc:`During the Command sub-phase, roll a D6; on 4+ a single Jungle Swarm within 6" regains D3 lost Wounds.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/spawn-of-sotek`},
  "the-questing-vow": {name:`The Questing Vow`,desc:`Chivalrous Vow. Stubborn; re-roll failed Fear/Panic/Terror tests; no Panic from nearby Peasantry; cannot be equipped with a lance. Cannot be joined by a Knight's Vow or Peasantry character.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/the-questing-vow`},
  "the-grail-vow": {name:`The Grail Vow`,desc:`Chivalrous Vow. Immune to Psychology, Magical Attacks and Stubborn; always benefits from Blessings of the Lady (no prayer needed); cannot refuse a challenge. The unit may only be joined by another Grail Vow character or a Handmaiden of the Lady.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/the-grail-vow`},
  "the-crusaders-vow": {name:`The Crusader's Vow`,desc:`Chivalrous Vow (Errantry Crusade). The model gains Veteran; no Panic from nearby Peasantry units destroyed/fled-through.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/the-crusaders-vow`},
  "the-exiles-vow": {name:`The Exile's Vow`,desc:`Chivalrous Vow (Bretonnian Exiles). The model gains Stubborn and Veteran; no Panic from nearby Levies/Peasantry units destroyed/fled-through.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/the-exiles-vow`},
  "forming-the-lance": {name:`Forming the Lance`,desc:`A Lance is two or more models edge-to-edge facing the same way: front rank 1 model, second rank 2, third rank 3, etc. Front/flank/rear arcs are set by the second and last ranks; command models go in the first/second rank (standard at the front).`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/forming-the-lance`},
  "manoeuvring-a-lance": {name:`Manoeuvring a Lance`,desc:`A Lance may not turn or redress the ranks, but may wheel, move backwards/sideways and reform. A wheel is measured from the second rank; all other movement from the front model.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/manoeuvring-a-lance`},
  "the-lance-in-combat": {name:`The Lance in Combat`,desc:`Only the front model needs base contact (else the Lance is blunted). Every model on the outside of the Lance counts as in the fighting rank and in base contact. Rank Bonus +1 per complete rank; +1 combat result if Unit Strength 5+. A flank charge aligns against the widest rank and blunts the Lance.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/the-lance-in-combat`},
  "blunting-the-lance": {name:`Blunting the Lance`,desc:`A Lance becomes 'blunted' if the front model can't reach the enemy, it makes a disordered charge, or it is charged without performing a Counter Charge. A blunted Lance immediately reforms into Close Order (models equal to its complete ranks in base contact).`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/blunting-the-lance`},
  "casualty-removal": {name:`Casualty Removal`,desc:`When removing casualties from a Lance, you may remove models from the middle of the back rank rather than from one end.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/casualty-removal`},
  "characters-joining-a-lance": {name:`Characters Joining a Lance`,desc:`A character joining a Lance is placed on the outside in any rank (may take a command model's spot, displacing it back). A retired character goes to the middle of a rank (not the first/second) and leaves the fighting rank.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/characters-joining-a-lance`},
  "lance-formations-and-skirmishers": {name:`Lance Formations & Skirmishers`,desc:`When a Skirmisher unit charges or is charged by a Lance, the Skirmishers do not form up: each model moves into base contact with the Lance and with one another. Skirmishers cannot blunt a Lance.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/lance-formations-and-skirmishers`},
  "crusaders-zeal": {name:`Crusader's Zeal`,desc:`A unit with this rule increases its maximum charge range by 1", may add +1 to its Charge roll, and gains the Impetuous special rule.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/crusaders-zeal`},
  "earn-your-spurs": {name:`Earn Your Spurs`,desc:`Any enemy standard captured by Knights Errant is worth 100 VP; within 6" of a friendly Grail Vow model or any Bretonnian Lord, a Knights Errant unit may re-roll natural 1s To Hit.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/earn-your-spurs`},
  "peasants-duty": {name:`Peasant's Duty`,desc:`This character and his unit may Give Ground instead of Falling Back in Good Order, and ignore Panic when a friendly Levies unit Breaks within 6". Unless fleeing, friendly Levies units in Command range may re-roll a failed Panic test.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/peasants-duty`},
  "grail-monk": {name:`Grail Monk`,desc:`A Grail Monk is a command-group model that follows the champion rules (a unit may thus have two champions).`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/grail-monk`},
  "grail-reliquae": {name:`Grail Reliquae`,desc:`Placed in the front rank, occupies and counts as six models (two per rank over three ranks). It cannot lose Wounds while any Battle Pilgrims remain. It counts as a standard bearer and a musician; within 12" of a friendly non-fleeing Grail Vow model, its unit gains Immune to Psychology and Unbreakable.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/grail-reliquae`},
  "retinue-of-the-saints": {name:`Retinue of the Saints`,desc:`Your army may include up to one Grail Reliquae for every Grail Vow character or unit it includes.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/retinue-of-the-saints`},
  "living-saints": {name:`Living Saints`,desc:`Every model in a Grail Knights unit can issue and accept challenges like a character.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/living-saints`},
  "the-wyrm-slayer": {name:`The Wyrm Slayer`,desc:`If Sir Cecil Gastonne kills an enemy monstrous infantry/cavalry, monstrous creature or behemoth in combat, he gains the Terror special rule for the rest of the game.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/the-wyrm-slayer`},
  "aura-of-the-fay": {name:`Aura of the Fay`,desc:`When the Green Knight loses his last Wound he is removed but not slain, and may be re-awakened (Guardian of the Sacred Sites) — but each death gives -1 to the awaken roll and -1 Wound (min 1). The enemy only scores VP for him if he is off the battlefield at game end.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/aura-of-the-fay`},
  "guardian-of-the-sacred-sites": {name:`Guardian of the Sacred Sites`,desc:`The Green Knight is not deployed; at any Start of Turn off the table, roll D6 (3+ awakens; auto by round 5). He is placed completely within any natural terrain feature. In Remaining Moves he may teleport between natural terrain features (then no further movement). Respects the 1" rule.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/guardian-of-the-sacred-sites`},
  "reclaimed-glory": {name:`Reclaimed Glory`,desc:`A Bretonnian Exiles army cannot pray for the Blessings at the start. A unit with the Blessings rule gains it if it makes an overrun or contacts a fleeing enemy in a charge/pursuit; a character gains it by killing an enemy character in a challenge. Once lost it cannot be regained this way.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/reclaimed-glory`},
  "crusading-knights": {name:`Crusading Knights`,desc:`In an Errantry Crusade army, listed knight characters/units gain Crusader's Zeal, and any with the Knight's Vow may swap it for the Crusader's Vow for free.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/crusading-knights`},
  "banished-lords": {name:`Banished Lords`,desc:`In a Bretonnian Exiles army, Barons/Paladins cannot have the Grail Vow; listed characters/units may swap the Knight's Vow for the Exile's Vow for free.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/banished-lords`},
  "untutored-arcanist": {name:`Untutored Arcanist`,desc:`When rolling on the Miscast table, this Wizard rolls an extra D6 and discards the highest result.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/untutored-arcanist`},
  "dragon-armour": {name:`Dragon Armour`,desc:`A model with this rule has a 6+ Ward save against any wounds; a Wizard with this rule may wear armour without penalty.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/dragon-armour`},
  "enfeebling-cold": {name:`Enfeebling Cold`,desc:`Whilst in base contact with this model (Merwyrm), enemy models suffer -1 Strength (min 1).`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/enfeebling-cold`},
  "abyssal-cloak": {name:`Abyssal Cloak`,desc:`Any enemy model targeting this model (Merwyrm) in the Shooting phase suffers -2 To Hit at long range (instead of -1).`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/abyssal-cloak`},
  "mighty-constitution": {name:`Mighty Constitution`,desc:`On a turn Korhil charged 3"+, he gains +1 Strength; he is immune to Poisoned Attacks (the attacker rolls To Wound as normal).`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/mighty-constitution`},
  "arrows-of-isha": {name:`Arrows of Isha`,desc:`Any bow carried by a model with this rule has Armour Bane (1) and Armour Piercing -1.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/arrows-of-isha`},
  "precision-strikes": {name:`Precision Strikes`,desc:`A Lothern Sea Guard unit joined by Ishaya Vess improves the Armour Piercing of its weapons by 1.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/precision-strikes`},
  "commanding-voice": {name:`Commanding Voice`,desc:`Ishaya Vess has a Command range of 12" (15" if she is the General).`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/commanding-voice`},
  "horn-of-isha": {name:`Horn of Isha`,desc:`Single use. In the Command sub-phase, a Leadership test; if passed, until your next Start of Turn this character and his unit gain +1 To Hit and +1 To Wound.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/horn-of-isha`},
  "kings-guard": {name:`King's Guard`,desc:`Any model in a White Lions of Chrace unit joined by your General can issue and accept challenges like a character (lost if the General leaves).`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/kings-guard`},
  "sons-of-caledor": {name:`Sons of Caledor`,desc:`A Dragon Princes unit may only be joined by your General or by a character with the Blood of Caledor Elven Honour.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/sons-of-caledor`},
  "chracian-warriors": {name:`Chracian Warriors`,desc:`A White Lions of Chrace unit may only be joined by your General or by a character with the Chracian Hunter Elven Honour.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/chracian-warriors`},
  "warriors-of-nagarythe": {name:`Warriors of Nagarythe`,desc:`A unit with this rule (Shadow Warriors) may only be joined by a character with the Shadow Stalker Elven Honour.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/warriors-of-nagarythe`},
  "warriors-of-the-white-tower": {name:`Warriors of the White Tower`,desc:`A unit with this rule (Swordmasters) may only be joined by a High Elf Mage or by a character with the Warden of Saphery or Loremaster Elven Honour.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/warriors-of-the-white-tower`},
  "warriors-of-chrace": {name:`Warriors of Chrace`,desc:`Chracian Warhost: Elven Spearmen or Elven Archers units may take the Lion Cloak special rule for +10 pts per unit.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/warriors-of-chrace`},
  "chracian-pride": {name:`Chracian Pride`,desc:`Chracian Warhost: characters able to take an Elven Honour may only choose Shadow Stalker, Chracian Hunter or Pure of Heart (Chracian Chieftains count as having Chracian Hunter for joining White Lions).`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/chracian-pride`},
  "hidden-trails": {name:`Hidden Trails`,desc:`Chracian Warhost: 0-1 Elven Spearmen/Archers unit per 1,000 pts may take Move Through Cover (+1 pt/model); once per game you may apply +1/-1 to an Ambusher arrival roll.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/hidden-trails`},
  "warriors-of-the-wilderness": {name:`Warriors of the Wilderness`,desc:`Chracian Warhost: after terrain placement, the player may place one extra wood (3-9"), anywhere outside the opponent's deployment zone and 6" of a special feature (may be within 12" of centre).`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/warriors-of-the-wilderness`},
  "armies-of-the-sea-lord": {name:`Armies of the Sea Lord`,desc:`Sea Guard Garrison: characters able to take an Elven Honour may only choose Shadow Stalker, Pure of Heart or Sea Guard.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/armies-of-the-sea-lord`},
  "from-the-mists": {name:`From the Mists`,desc:`Sea Guard Garrison: after deployment (before Scouts/Vanguard), remove one deployed friendly unit and replace it anywhere in your deployment zone.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/from-the-mists`},
  "from-the-storm-clouds": {name:`From the Storm Clouds`,desc:`Sea Guard Garrison: 0-1 Lothern Skycutter per 1,000 pts (incl. character mounts) may take Ambushers for +10 pts/model.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/from-the-storm-clouds`},
  "old-world-rangers": {name:`Old World Rangers`,desc:`Sea Guard Garrison: 0-1 Shadow Warriors unit (US 10 or less) may take Ambushers for free.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/old-world-rangers`},
  "pride-of-the-fleet": {name:`Pride of the Fleet`,desc:`Sea Guard Garrison: Sea Guard units gain Regimental Unit; 0-1 Sea Guard unit per 1,000 pts may take Drilled for free.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/pride-of-the-fleet`},
  "unity-and-harmony": {name:`Unity & Harmony`,desc:`Any Jade Warriors or Jade Lancers unit within 3" of a friendly Mercenary unit may re-roll To Hit rolls of 1 in the Combat phase.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/unity-and-harmony`},
  "implacable": {name:`Implacable`,desc:`Once per game, on a turn it was charged, this model may choose not to Give Ground if it loses; once per game it may re-roll its Charge roll.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/implacable`},
  "defensive-stance": {name:`Defensive Stance`,desc:`Unless it charged (or counts as charged) this turn, this unit may re-roll natural 1s on Armour Saves in the Combat phase.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/defensive-stance`},
  "the-elemental-winds": {name:`The Elemental Winds`,desc:`Each Start of Turn, roll D6: 1-2 nothing; 3-4 Winds of Yang (Lore of Yang Dispel/Enchantment range +3"; Will of the Dragons models gain +1 M or +1 I); 5-6 Winds of Yin (Lore of Yin Hex/Magic Missile range +3"; +1 WS or +1 Ld). All eligible models gain the same modifier.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/the-elemental-winds`},
  "dragon-form": {name:`Dragon Form`,desc:`Whilst in Dragon form, a Cathayan Dragon is a character with troop type behemoth, but does not have Inspiring Presence even if it is the General.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/dragon-form`},
  "human-form": {name:`Human Form`,desc:`Whilst in Human form, a Cathayan Dragon is a character with troop type heavy infantry.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/human-form`},
  "transformation": {name:`Transformation`,desc:`During the Command sub-phase, a Cathayan Dragon may swap between Human and Dragon form (placed within 6", not within 1" of allies or 3" of enemies), recovering D3 Wounds; it cannot charge that turn, counts as having moved, leaves its unit and may leave combat by transforming.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/transformation`},
  "transformation-of-the-dragon": {name:`Transformation of the Dragon`,desc:`A Cathayan Dragon has both Human and Dragon forms, each with its own profile; choose the starting form during deployment.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/transformation-of-the-dragon`},
  "death-of-a-dragon": {name:`Death of a Dragon`,desc:`Wounds are tracked across both profiles. The first time it reaches 0 Wounds in Dragon form it reverts to Human form and recovers D3 Wounds (and cannot take Dragon form again). Reaching 0 in Human form removes it.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/death-of-a-dragon`},
  "disdain-of-the-dragons": {name:`Disdain of the Dragons`,desc:`Enemy models wishing to issue a challenge within Miao Ying's Command range must pass a Leadership test (with +1/+2 if she is in Human/Dragon form and engaged in the same combat); her own challenges cannot be refused.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/disdain-of-the-dragons`},
  "discipline-of-the-dragon": {name:`Discipline of the Dragon`,desc:`Once per game, in the Command sub-phase, each Sky Lantern may pass a Leadership test to grant a Grand Strategy to friendly Cathayan units within 12" until your next Start of Turn: Defiance (Stubborn, or Unbreakable if already Stubborn), Strength of the Everlasting Empire (infantry/cavalry cannot be wounded on a To Wound roll of 2), or Fury of the Falling Blade (regular infantry +1 M and re-roll Charge/Flee/Pursuit).`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/discipline-of-the-dragon`},
  "grand-strategist": {name:`Grand Strategist`,desc:`Unless fleeing, friendly units in Command range (except the General) may use this character's Leadership; once per turn a unit that wins a combat in Command range may Fall Back in Good Order instead of following up/pursuing.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/grand-strategist`},
  "cathayan-black-powder": {name:`Cathayan Black Powder`,desc:`The first time a Jade Fleet unit armed with a handgun/pistol/brace/repeater shoots, that weapon's range is increased by 3".`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/cathayan-black-powder`},
  "granite-sentinel": {name:`Granite Sentinel`,desc:`+1 armour value, and immune to Multiple Wounds (X): an unsaved wound from such an attack costs only a single Wound.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/granite-sentinel`},
  "jade-sentinel": {name:`Jade Sentinel`,desc:`Knows one Battle Magic or Elementalism spell (chosen before deployment) and casts it as a Bound spell, Power Level 3.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/jade-sentinel`},
  "obsidian-sentinel": {name:`Obsidian Sentinel`,desc:`Has Magic Resistance (-2). An enemy Wizard casting within 12" must pass a Leadership test or suffer -3 to the Casting roll (-1 if passed).`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/obsidian-sentinel`},
  "terracotta-sentinel": {name:`Terracotta Sentinel`,desc:`Has the Regeneration (6+) special rule.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/terracotta-sentinel`},
  "warpstone-sentinel": {name:`Warpstone Sentinel`,desc:`Has Magical Attacks; enemy units in base contact suffer -1 Toughness (min 1).`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/warpstone-sentinel`},
  "wrath-of-the-storm": {name:`Wrath of the Storm`,desc:`All Jade Warriors and Jade Lancers in an army led by Miao Ying gain Hatred (Warriors of Chaos & Daemonic models).`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/wrath-of-the-storm`},
  "enough-for-everyone": {name:`Enough for Everyone`,desc:`If an Ogre Loader has gunpowder bombs, the crew of its war machine also has gunpowder bombs.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/enough-for-everyone`},
  "mastery-of-the-storm-winds": {name:`Mastery of the Storm Winds`,desc:`Miao Ying may discard up to two randomly generated spells (instead of one) and replace them from Lore of Yang/Yin, her signature spell, or The Storm Dragon's Fury (Magic Missile, 10+, 18", 2D3 Strength 5 AP-3 Flaming hits then the target must Give Ground).`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/mastery-of-the-storm-winds`},
  "mercenary-crew": {name:`Mercenary Crew`,desc:`An Ogre Loader joins a Cathayan war machine (cannot leave it). Its crew gains +1 Movement and Stubborn; once per game a Fire Rain Rocket Battery or Grand Cannon with an Ogre Loader may fire twice or re-roll an Artillery dice.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/mercenary-crew`},
  "mercenary-handgun-drill": {name:`Mercenary Handgun Drill`,desc:`Once per game, each State Missile Troops unit/detachment in a Jade Fleet army may fire with one additional rank.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/mercenary-handgun-drill`},
  "supreme-matriarch-of-nan-gau": {name:`Supreme Matriarch of Nan-Gau`,desc:`If the army includes Miao Ying she must be General; 0-1 Jade Warriors or Jade Lancers unit may be upgraded to Celestial Dragon Guard (+2 pts/model: +1 WS, +1 Ld, Celestial Armour (6+)).`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/supreme-matriarch-of-nan-gau`},
  "wailing-spirits": {name:`Wailing Spirits`,desc:`Any unit that suffers one or more unsaved wounds from this weapon must make a Panic test as if it had taken heavy casualties.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/wailing-spirits`},
  "war-balloons": {name:`War Balloons`,desc:`0-1 Sky Lantern per 1,000 pts may take Ambushers (+15 pts); once per game a reserved Sky Lantern may re-roll its arrival roll.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/war-balloons`},
  "warriors-of-the-field": {name:`Warriors of the Field`,desc:`Peasant Levy units do not become Disrupted by difficult or dangerous terrain; 0-1 unit per 1,000 pts may take Move Through Cover (+20 pts).`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/warriors-of-the-field`},
  "warriors-of-the-land": {name:`Warriors of the Land`,desc:`When a Peasant Levy unit Falls Back in Good Order, it may choose which die to discard on its Flee roll (instead of the lowest).`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/warriors-of-the-land`},
  "warriors-of-the-wind": {name:`Warriors of the Wind`,desc:`0-1 Peasant Levy unit per 1,000 pts may take Reserve Move and Scouts (+2 pts/model).`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/warriors-of-the-wind`},
  "thunderous-impact": {name:`Thunderous Impact`,desc:`Until your next Start of Turn, any unit within 2D6" of a Cathayan grand cannon's strike point suffers -1 Movement and cannot use Swiftstride.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/thunderous-impact`},
  "tower-shields": {name:`Tower Shields`,desc:`A tower shield improves armour value by 3 (instead of 1) against attacks from the front arc, but gives no protection against attacks from the flank or rear.`,army:`grand-cathay`,url:`https://tow.whfb.app/special-rules/tower-shields`},
  "ancestral-fury": {name:`Ancestral Fury`,desc:`In a Royal Clan army, a unit that made a charge move of 3"+ or a follow up move gains +1 Strength that turn.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/ancestral-fury`},
  "stoic-defenders": {name:`Stoic Defenders`,desc:`On a turn it was charged, a model with this rule gains +1 Initiative and +1 Attacks.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/stoic-defenders`},
  "striking-a-grudge": {name:`Striking a Grudge`,desc:`After deployment, nominate one enemy character: all friendly models gain Hatred against it, and you gain 75 bonus VP if it is slain/fled/fleeing at game end.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/striking-a-grudge`},
  "grudgelore": {name:`Grudgelore`,desc:`Once Thorgrim sets the Grudgestone, he and his unit replace Hatred (Orcs & Goblins) with Hatred (all enemies).`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/grudgelore`},
  "the-grudgestone": {name:`The Grudgestone`,desc:`During any Start of Turn, Thorgrim may set the Grudgestone: he and his unit gain Unbreakable and auto-pass Panic, but cannot Flee as a charge reaction and cannot move other than Give Ground, follow up or reform.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/the-grudgestone`},
  "venerable": {name:`Venerable`,desc:`Unless fleeing, friendly units within 6" may re-roll a failed Panic test.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/venerable`},
  "wards-of-grimnir": {name:`Wards of Grimnir`,desc:`A Slayer Host unit with a standard bearer may buy Wards of Grimnir (+1 pt/model): 6+ Ward vs non-magical wounds suffered during the Shooting phase.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/wards-of-grimnir`},
  "troll-hunters": {name:`Troll Hunters`,desc:`0-1 character per 1,000 pts in a Slayer Host (not Ungrim) may take Scouts for +10 pts.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/troll-hunters`},
  "king-of-the-slayer-hold": {name:`King of the Slayer Hold`,desc:`Ungrim may join Hammerers or Slayers (despite Loner); a Hammerer unit he joins gains Immune to Psychology and Unbreakable. As Royal Clan General he unlocks Daemon/Dragon Slayers as Characters, Slayers as Core, and Doomseekers as Special.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/king-of-the-slayer-hold`},
  "royal-guard": {name:`Royal Guard`,desc:`One Hammerer unit per King/Thane. A Hammerer unit joined by a King or Thane can issue/accept challenges like a character (lost if they leave).`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/royal-guard`},
  "first-to-the-fray": {name:`First to the Fray`,desc:`This model increases its maximum charge range by 3" and may add +D3 to its Charge roll.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/first-to-the-fray`},
  "fight-me": {name:`\"Fight Me!\"`,desc:`Any model with this rule can issue and accept challenges like a character.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/fight-me`},
  "whirlwind-of-death": {name:`Whirlwind of Death`,desc:`Impact Hits use the profile of its whirling blades; To Wound 4+ always succeeds regardless of Toughness.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/whirlwind-of-death`},
  "whirling-doom": {name:`Whirling Doom`,desc:`Goblin-hewer: roll an Artillery dice + D3 for shots (per rank if front/rear arc, per file if flank). Misfire = no shots, roll on the Misfire table.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/whirling-doom`},
  "from-the-wilds": {name:`From the Wilds`,desc:`0-1 Slayer unit (US 10 or less) in a Slayer Host may take Ambushers and Skirmishers for +1 pt/model.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/from-the-wilds`},
  "prepared-positions": {name:`Prepared Positions`,desc:`During deployment, Entrench one non-character war machine and one Quarreller/Thunderer unit (partial cover + low obstacle). Lost if they move.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/prepared-positions`},
  "range-finding-optics": {name:`Range Finding Optics`,desc:`Burlok: once per turn a friendly Quarreller/Thunderer unit or Dwarf war machine in Command range may re-roll 1s To Hit or one Artillery dice; Burlok and his unit ignore the -1 Long Range To Hit penalty.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/range-finding-optics`},
  "expeditionary-marksmen": {name:`Expeditionary Marksmen`,desc:`0-1 Thunderer unit/1,000 pts upgraded (+1 pt/model) suffer no Move-and-Shoot To Hit penalty; any Engineer may also be upgraded (+10 pts).`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/expeditionary-marksmen`},
  "function-over-form": {name:`Function Over Form`,desc:`You may reduce a Cannon/Organ Gun/Flame Cannon's Toughness by 1 (min 1); a war machine reduced this way also loses Move or Shoot.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/function-over-form`},
  "worst-among-equals": {name:`Worst Among Equals`,desc:`Ungrim must be General if present; otherwise a Daemon/Dragon Slayer is General (despite Loner) but a Slayer Host Slayer-General does not gain Inspiring Presence.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/worst-among-equals`},
  "riches-and-heirlooms": {name:`Riches & Heirlooms`,desc:`Characters may spend +25 points on runes, and units able to buy Standard runes may spend +25 points on them (except Royal Clan Warriors).`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/riches-and-heirlooms`},
  "dive-bomb": {name:`Dive Bomb`,desc:`Once per game, in Remaining Moves a flying unit may fly over a non-engaged enemy: it suffers D6 Strength 3 AP-1 hits per model that moved over it (each natural 1 misfires, costing this unit a Wound).`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/dive-bomb`},
  "bugmans-cart": {name:`Bugman's Cart`,desc:`During the Command sub-phase, any non-fleeing/non-engaged Dwarf unit within 6" of a friendly Bugman's Cart gains +1 Movement until end of turn (not cumulative).`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/bugmans-cart`},
  "miners-cart": {name:`Miner's Cart`,desc:`Any Dwarf unit within 3" of a friendly Miner's Cart may make a Stand & Shoot reaction and/or shooting attack as if armed with Blasting Charges. When the Cart loses its last Wound in combat, on 4+ it explodes (everything within 3" suffers D6 Strength 3 AP-1 Flaming hits).`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/miners-cart`},
  "look-snorri-trolls": {name:`\"Look Snorri, Trolls!\"`,desc:`After deployment (before Scouts/Vanguard), Slayer and Brotherhood of Grimnir units in a Slayer Host may make a D3"+1 move (may manoeuvre, no march).`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/look-snorri-trolls`},
  "abyssal-howl": {name:`Abyssal Howl`,desc:`Whilst within 6" of this model, enemy units suffer -1 Leadership (min 2). Not cumulative.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/abyssal-howl`},
  "cry-of-war": {name:`Cry of War`,desc:`Enemy units suffer -1 Leadership whilst within the Command range of one or more non-fleeing Death Hags with this rule.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/cry-of-war`},
  "dance-of-death": {name:`Dance of Death`,desc:`If this unit makes a successful charge (contacts the target), the charge target suffers -1 to its Maximum Rank Bonus until the end of that Combat phase.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/dance-of-death`},
  "manbane": {name:`Manbane`,desc:`When this character rolls To Wound, a 4+ is always a success regardless of the target's Toughness.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/manbane`},
  "dark-venom": {name:`Dark Venom`,desc:`This character has the Killing Blow special rule.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/dark-venom`},
  "hidden-dark-elves": {name:`Hidden (Dark Elves)`,desc:`A Khainite Assassin starts hidden within a friendly Dark Elf infantry unit (US 10+, not Harpies) and may be revealed during any Start of Turn or at the start of any Combat phase, placed like a joined character. If the host is destroyed/flees first, the Assassin is lost. Cannot be the General.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/hidden-dark-elves`},
  "cursed-coven": {name:`Cursed Coven`,desc:`A unit of Doomfire Warlocks knows one Dark Magic or Daemonology spell (chosen before deployment) and casts it as a Bound spell: Power Level 2 (US 10+ with a Master), 1 (Master but US 9 or less), or 0 otherwise.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/cursed-coven`},
  "forbidden-poisons": {name:`Forbidden Poisons`,desc:`A Khainite Assassin may take one forbidden poison: Black Lotus (enemy characters wounded suffer -1 Ld for the game), Dark Venom (Killing Blow), or Manbane (To Wound 4+ always succeeds).`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/forbidden-poisons`},
  "gifts-of-khaine": {name:`Gifts of Khaine`,desc:`A Death Hag may take one gift: Cry of War (-1 Ld to enemies in Command range), Rune of Khaine (Extra Attacks +D3), or Witchbrew (cannot lose Frenzy).`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/gifts-of-khaine`},
  "witchbrew": {name:`Witchbrew`,desc:`This character, their mount and any unit joined cannot lose the Frenzy special rule.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/witchbrew`},
  "rune-of-khaine": {name:`Rune of Khaine`,desc:`This character has the Extra Attacks (+D3) special rule.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/rune-of-khaine`},
  "black-lotus": {name:`Black Lotus`,desc:`For each unsaved Wound this character inflicts, enemy characters suffer -1 Leadership for the remainder of the game.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/black-lotus`},
  "goad-beast": {name:`Goad Beast`,desc:`During the Command sub-phase, this character may goad a friendly monster (incl. its own mount) within Command range: until end of turn that model gains +D3 Attacks (max 10).`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/goad-beast`},
  "wilful-beast": {name:`Wilful Beast`,desc:`During Start of Turn, this model takes a Leadership test (own unmodified Ld); on a failure its mount becomes Frenzied until the next Start of Turn (the rider gains no +1 Attacks).`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/wilful-beast`},
  "daemonic-alignment": {name:`Daemonic Alignment`,desc:`Indicates a Daemon's god (Khorne/Nurgle/Slaanesh/Tzeentch). A model has at most one Alignment; all models in a unit share the same; a character with an Alignment may only join a unit of the same Alignment or none.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/daemonic-alignment`},
  "daemonic-locus": {name:`Daemonic Locus`,desc:`Friendly units of the same Daemonic Alignment within 12" reduce wounds from Daemonic Instability by 1, and on a natural double 6 Instability test they are not removed but instead lose Wounds equal to the amount failed by.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/daemonic-locus`},
  "chaos-armour-daemons-of-chaos": {name:`Chaos Armour (Daemons of Chaos)`,desc:`This model has a 4+ Ward save against any wounds suffered; a Wizard with this rule may wear armour without penalty.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/chaos-armour-daemons-of-chaos`},
  "brazen-wheels": {name:`Brazen Wheels`,desc:`Stomp Attacks by a Skull Cannon of Khorne have Armour Piercing -3 (not against behemoths).`,army:`daemons`,url:`https://tow.whfb.app/special-rules/brazen-wheels`},
  "plague-proboscis": {name:`Plague Proboscis`,desc:`+1 Initiative (applies only to the Rot Flies, not their riders).`,army:`daemons`,url:`https://tow.whfb.app/special-rules/plague-proboscis`},
  "slime-trail": {name:`Slime Trail`,desc:`Enemy units cannot claim any bonus combat result points for being engaged in this unit's flank or rear arc.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/slime-trail`},
  "cannonade": {name:`Cannonade`,desc:`When shooting a steam cannonade, roll two Artillery dice before rolling To Hit; shots = their total. One Misfire: all shots -1 To Hit. Two Misfires: no shots and the model loses a Wound (no Misfire table).`,army:`chaos-dwarfs`,url:`https://tow.whfb.app/special-rules/cannonade`},
  "carriage-hauler": {name:`Carriage Hauler`,desc:`In the Movement phase, up to two friendly 'Steam Carriage' war machines fully within this model's rear arc and within 8" may move with it (finishing in the same area); unless it uses Lumbering Destruction or charges, those war machines do not count as having moved.`,army:`chaos-dwarfs`,url:`https://tow.whfb.app/special-rules/carriage-hauler`},
  "hellbound": {name:`Hellbound`,desc:`A Hellbound model has a 6+ Ward vs non-magical attacks and gains Fear and Magical Attacks (or Terror if it already had Fear). Once per game it may re-roll a Scatter or Artillery dice, but suffers -1 on any Misfire table roll.`,army:`chaos-dwarfs`,url:`https://tow.whfb.app/special-rules/hellbound`},
  "lumbering-destruction": {name:`Lumbering Destruction`,desc:`An Iron Daemon cannot march; instead roll a D6 and add it to its Movement. On a natural 1 the engine seizes: it halts immediately and cannot move again this turn.`,army:`chaos-dwarfs`,url:`https://tow.whfb.app/special-rules/lumbering-destruction`},
  "quake": {name:`Quake`,desc:`Until your next Start of Turn, any unit (friend or foe) within 2D6" of the central hole of the blast template (after scatter) suffers -1 Movement and cannot use Swiftstride.`,army:`chaos-dwarfs`,url:`https://tow.whfb.app/special-rules/quake`},
  "quell-panic": {name:`Quell Panic`,desc:`Unless fleeing, any friendly unit within 6" that has the Levies special rule may re-roll a failed Panic test.`,army:`chaos-dwarfs`,url:`https://tow.whfb.app/special-rules/quell-panic`},
  "skullcracker": {name:`Skullcracker`,desc:`An Iron Daemon with a Skullcracker replaces Impact Hits (D6+1) with Impact Hits (2D6+2) and gains Armour Bane (1).`,army:`chaos-dwarfs`,url:`https://tow.whfb.app/special-rules/skullcracker`},
  "slow-reload": {name:`Slow Reload`,desc:`If this weapon shot during your previous turn, roll a D6 before shooting: on 1-2 it does not shoot this turn (reload incomplete). A Dreadquake Mortar with an Ogre Loader applies +1 to this roll.`,army:`chaos-dwarfs`,url:`https://tow.whfb.app/special-rules/slow-reload`},
  "stampede": {name:`Stampede`,desc:`Impact Hits caused by a model with this rule have an Armour Piercing of -2.`,army:`chaos-dwarfs`,url:`https://tow.whfb.app/special-rules/stampede`},
  "bestial-charge": {name:`Bestial Charge`,desc:`During a turn in which it made a charge move of 3" or more, a model with this rule gains +1 Strength.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/bestial-charge`},
  "champions-of-slaughter": {name:`Champions of Slaughter`,desc:`If the General of a Minotaur Blood Herd becomes Frenzied via Blood Rage, friendly units within its Command range also become Frenzied.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/champions-of-slaughter`},
  "bloodshed-and-butchery": {name:`Bloodshed & Butchery`,desc:`All Doombulls, Gorebulls, Minotaur Herds and Gor Herds in a Minotaur Blood Herd army gain the Impetuous special rule.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/bloodshed-and-butchery`},
  "spurting-bile-blood": {name:`Spurting Bile Blood`,desc:`For each Wound this model loses during the Combat phase, the attacking enemy unit suffers a Strength 4 hit with AP -1.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/spurting-bile-blood`},
  "maddening-aura": {name:`Maddening Aura`,desc:`During the Command sub-phase, each enemy unit within 8" (even fleeing/engaged) takes a Leadership test or suffers D3 Strength 3 hits with no armour/Regeneration save (Ward allowed).`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/maddening-aura`},
  "swallow-whole": {name:`Swallow Whole`,desc:`During the Command sub-phase, a Ghorgon engaged with regular/heavy infantry may force an Initiative test on a target unit: if failed, one model is removed; the Ghorgon recovers 1 Wound per model eaten.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/swallow-whole`},
  "eadbutt-giant": {name:`'Eadbutt (Giant)`,desc:`Giant Attack: nominate one model in an enemy fighting rank; it suffers D3+1 wounds with no armour/Regeneration save (Ward allowed).`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/eadbutt-giant`},
  "belly-flop": {name:`Belly Flop`,desc:`Giant Attack: place a 3" blast template over the centre of the target unit; each model under it suffers one hit at the Giant's Strength with AP -2.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/belly-flop`},
  "mighty-swing-giant": {name:`Mighty Swing (Giant)`,desc:`Giant Attack: the Giant gains Random Attacks with D6+1 Attacks; its club is Strength S+1 with AP -2.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/mighty-swing-giant`},
  "thump-with-club": {name:`Thump with Club`,desc:`Giant Attack: a powerful single club blow against the target (high-Strength, AP) - see the Giant Attacks entry for the exact profile.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/thump-with-club`},
  "jump-up-and-down": {name:`Jump Up & Down`,desc:`Giant Attack: the Giant stamps repeatedly on the target unit, inflicting multiple high-Strength hits - see the Giant Attacks entry.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/jump-up-and-down`},
  "endless-malice": {name:`Endless Malice`,desc:`If this model wins a round of combat and chooses to restrain & reform (passing its Leadership test), enemy units within 6" must take a Panic test as if a nearby friend had been destroyed.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/endless-malice`},
  "soul-eater": {name:`Soul-eater`,desc:`Any enemy Wizard wishing to cast within 12" of a Cygor must first pass a Leadership test; if failed and the spell then fails to cast, it is miscast (roll on the Miscast table).`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/soul-eater`},
  "ghostsight": {name:`Ghostsight`,desc:`During the Combat phase, a Cygor may re-roll failed To Hit rolls against enemy Wizards, models/units with magic items, or models/units with a Ward or Regeneration save.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/ghostsight`},
  "storm-call": {name:`Storm Call`,desc:`Bound spell (Power Level 1, castable even when engaged): Magic Missile, Self, casting value 7+. If cast, all units within 6" (friend or foe, including in combat) suffer D3 Strength 4 hits with AP -1.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/storm-call`},
  "the-quickening-storm": {name:`The Quickening Storm`,desc:`5+ Ward save against wounds from a Magic Missile or Magical Vortex. If hit by Storm Call, the model becomes Quickened: +1 Initiative and +1 Attacks until your next Start of Turn.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/the-quickening-storm`},
  "dark-coven": {name:`Dark Coven`,desc:`A Bray-Shaman/Great Bray-Shaman in a Wild Herd army may apply +1 to a Casting or Dispel roll if a friendly non-fleeing, non-stupid Wizard is within Command range; on a natural double 1, all those Wizards roll on the Miscast table.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/dark-coven`},
  "ancient-sorcery": {name:`Ancient Sorcery`,desc:`Beastmen Shamans in a Wild Herd army may also know spells from the Lore of Primal Magic, in addition to their normal Lores.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/ancient-sorcery`},
  "magics-of-the-dark-gods": {name:`Magics of the Dark Gods`,desc:`The General of a Minotaur Blood Herd (Doombull/Gorebull) may become a Level 1 (+35) or Level 2 (+65) Wizard knowing Battle Magic or Dark Magic, and may wear armour without penalty.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/magics-of-the-dark-gods`},
  "leering-spirit": {name:`Leering Spirit`,desc:`Place a Leering Spirit marker (not within 8" of an enemy) when Kralmaw deploys; it cannot be charged/targeted and is removed if Kralmaw dies. In each of Kralmaw's Shooting phases it may cast Devolve (Lore of Beasts) as a Bound spell, Power Level 3.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/leering-spirit`},
  "herdstones": {name:`Herdstones`,desc:`A 6" impassable special feature placed by the Beastmen player. Controlled by a friendly US 5+ non-fleeing unit within 6". A controlling Beastmen unit grants nearby effects: Magic Resistance (-1); re-roll To Wound 1s within 12" in combat; +1 cast to friendly / -1 to enemy Wizards within 12"; enemies within 12" suffer -1 Ld on Fear/Panic/Terror tests. Controlling it at battle's end = +200 Victory Points.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/herdstones`},
  "guardians-of-the-herdstones": {name:`Guardians of the Herdstones`,desc:`Doombulls and Gorebulls in a Minotaur Blood Herd may take Chaos Mutations and/or Gifts of Chaos up to a total of 50 points.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/guardians-of-the-herdstones`},
  "blessings-of-chaos": {name:`Blessings of Chaos`,desc:`When this unit's combat is chosen (Step 1.1), roll D6: 1-2 Poisoned Attacks, 3-4 all attacks gain AP -2, 5-6 +1 Toughness - until the end of the Combat phase.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/blessings-of-chaos`},
  "brayhorn": {name:`Brayhorn`,desc:`From round 2, if your General (a Beastlord/Wargor) is on the battlefield during the Command sub-phase, they may pass a Leadership test to re-roll the arrival of each Ambusher unit still in reserve that did not arrive this turn.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/brayhorn`},
  "roaming-warbands": {name:`Roaming Warbands`,desc:`In a Wild Herd army, Gor/Ungor/Primal/Centigor Herds may take Ambushers (+1 pt/model), Chieftains may take it (+10 pts), and 0-1 herd (US 10 or less) per 1,000 pts may take it for free.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/roaming-warbands`},
  "the-sons-of-ghorros": {name:`The Sons of Ghorros`,desc:`0-1 Centigor herd in Ghorros's army may be upgraded to Sons of Ghorros (+2 pts/model): +1 Weapon Skill, +1 Leadership and the Armour Bane (1) special rule.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/the-sons-of-ghorros`},
  "father-of-beasts": {name:`Father of Beasts`,desc:`Whilst within Ghorros Warhoof's Command range, friendly Centigor Herds may re-roll the D6 on the Drunken table.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/father-of-beasts`},
  "future-sight": {name:`Future Sight`,desc:`Kralmaw has a 4+ Ward save against any wounds suffered.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/future-sight`},
  "gifts-from-the-dark-gods": {name:`Gifts from the Dark Gods`,desc:`Characters in this army may spend +25 points on magic items and +25 points on Chaos Mutations.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/gifts-from-the-dark-gods`},
  "leader-of-the-pack-beastmen": {name:`Leader of the Pack (Beastmen)`,desc:`Ungor Ravagers with this rule join a unit of Primal Warhounds, occupying the rear ranks while the Warhounds always make up the front rank(s).`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/leader-of-the-pack-beastmen`},
  "assorted-weapons": {name:`Assorted Weapons`,desc:`War Wagon crew carry varied weapons (blunderbuss, long rifle, repeating rifle, ball & chain, hooked halberd, man-catcher). In the Shooting phase, each crew member with a missile weapon may shoot it; in the Combat phase, each may use either their unique weapon or their hand weapon. Roll separate batches of dice per weapon.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/assorted-weapons`},
  "big-guns-know-no-fear": {name:`Big Guns Know No Fear`,desc:`Empire Engineers in a City-state of Nuln army (and any unit they have joined) gain Immune to Psychology whilst there is a friendly war machine within their Command range.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/big-guns-know-no-fear`},
  "entrenched-position": {name:`Entrenched Position`,desc:`During deployment, Entrench one non-character war machine per Empire Engineer: it counts as behind partial cover and as defending a low linear obstacle. If it moves for any reason it is no longer Entrenched.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/entrenched-position`},
  "fanatical-zeal": {name:`Fanatical Zeal`,desc:`A unit with this rule (Flagellants) can only be joined by a Lector of Sigmar or a Priest of Sigmar; such a character is treated as Unbreakable while it remains with the unit.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/fanatical-zeal`},
  "feel-no-pain": {name:`Feel No Pain`,desc:`A model with this rule has a 6+ Ward save against wounds from non-magical enemy attacks, and a 5+ Ward save against non-magical attacks of Strength 5 or higher.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/feel-no-pain`},
  "grand-master-of-the-knights-panther": {name:`Grand Master of the Knights Panther`,desc:`Harald Gemunsen may re-roll a single die that rolls a natural 1 on a Charge roll (before discarding). He may only join a unit of the Order of the Knights Panther.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/grand-master-of-the-knights-panther`},
  "grinding-wheels": {name:`Grinding Wheels`,desc:`Stomp Attacks by this model have an Armour Piercing of -2 (but not against behemoths). Unlike other chariots, it treats low linear obstacles as open terrain.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/grinding-wheels`},
  "guardians-of-the-temple": {name:`Guardians of the Temple`,desc:`When engaged in combat, a model with this rule may re-roll any To Hit rolls of a natural 1.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/guardians-of-the-temple`},
  "gun-limbers": {name:`Gun Limbers`,desc:`0-1 war machine per 1,000 points (Great Cannon, Mortar, Helblaster Volley Gun or Helstorm Rocket Battery) may be given the Vanguard and Veteran special rules.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/gun-limbers`},
  "handgun-drill": {name:`Handgun Drill`,desc:`Once per game, each detachment of State Missile Troops in a City-state of Nuln army can fire with one additional rank.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/handgun-drill`},
  "helblaster": {name:`Helblaster`,desc:`Roll three Artillery dice before rolling To Hit; shots fired = their total. One Misfire: all shots suffer an extra -1 To Hit. Two Misfires: no shots, roll on the Misfire table. Three Misfires: fires 30 shots then is destroyed (and -1 To Hit).`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/helblaster`},
  "helstorm": {name:`Helstorm`,desc:`No line of sight required: choose an enemy unit in range and place D3 blast templates over it, then scatter each (Artillery + Scatter dice). A Misfire means the rocket fails to launch (roll on the Misfire table). Models under a template risk being hit.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/helstorm`},
  "inner-circle": {name:`Inner Circle`,desc:`When engaged in combat, a model with this rule (but not its mount) may re-roll any To Hit rolls of a natural 1.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/inner-circle`},
  "the-knightly-orders": {name:`The Knightly Orders`,desc:`Knightly Order army composition: the General must be a Grand Master or Chapter Master of a Knightly Order; all Chapter Masters and Empire/Inner Circle/Demigryph Knights must belong to the same Order (Panther, White Wolf, Blazing Sun, Morr or Fiery Heart), each with its own allowances/restrictions.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/the-knightly-orders`},
  "knights-of-morr": {name:`Knights of Morr`,desc:`Order composition: may include Wizard Lords and Master Mages as Characters; cannot include any Lectors/Priests of Sigmar or High Priests/Priests of Ulric.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/knights-of-morr`},
  "knights-of-the-blazing-sun": {name:`Knights of the Blazing Sun`,desc:`Order composition: 0-2 Master Mages per 1,000 pts, and 0-1 Great Cannon or Mortar per 1,000 pts; cannot include Lectors of Sigmar or High Priests of Ulric.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/knights-of-the-blazing-sun`},
  "knights-of-the-fiery-heart": {name:`Knights of the Fiery Heart`,desc:`Order composition: any number of Flagellant units as Rare choices; cannot include High Priests or Priests of Ulric.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/knights-of-the-fiery-heart`},
  "knights-of-the-white-wolf": {name:`Knights of the White Wolf`,desc:`Order composition: any number of Teutogen Guard as Special, and 0-1 Free Company Militia per 1,000 pts as Core; cannot include Lectors/Priests of Sigmar or Witch Hunters.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/knights-of-the-white-wolf`},
  "knights-panther": {name:`Knights Panther`,desc:`Order composition: 0-1 Empire/Inner Circle Knights of the Order of the White Wolf as a Mercenary choice, not subject to Misbehaving Mercenaries.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/knights-panther`},
  "mercenary-commander": {name:`Mercenary Commander`,desc:`If Hans is the army General, friendly Mercenary units benefit from his Inspiring Presence, may be joined by him, and are not subject to Misbehaving Mercenaries.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/mercenary-commander`},
  "prayer-of-the-damned": {name:`Prayer of the Damned`,desc:`During the Command sub-phase, make a Leadership test; if passed, until your next Start of Turn this character and any unit joined gains a 6+ Ward save against all wounds and a 5+ Ward against wounds caused in combat by enemies with Fear or Terror.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/prayer-of-the-damned`},
  "prayers-of-ulric": {name:`Prayers of Ulric`,desc:`During the Command sub-phase, make a Leadership test and chant one Prayer: Battle Howl (+D3 to Charge rolls for infantry/cavalry in Command range), Winter's Chill (enemies must re-roll natural 6s To Hit against this model/unit in Combat), or Wrath of Winter (this model and unit gain Multiple Wounds (2)). Not cumulative.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/prayers-of-ulric`},
  "skilled-duellist": {name:`Skilled Duellist`,desc:`If Harald Gemunsen slays an enemy in a challenge during a turn in which he charged, he may immediately issue a second challenge, fighting two challenges in one round of combat.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/skilled-duellist`},
  "steam-power": {name:`Steam Power`,desc:`A Steam Tank cannot march; instead you may make a Steam Power roll (roll 2D6 and keep the highest) and add the result to the model's Movement characteristic.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/steam-power`},
  "strategic-mastery": {name:`Strategic Mastery`,desc:`In scenarios where players roll off to determine who takes the first turn, you may apply a +1 or -1 modifier to the result of your roll.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/strategic-mastery`},
  "suffer-not": {name:`Suffer Not...`,desc:`Each Witch Hunter chooses a specialism granting Hatred (plus another rule) versus a foe type: The Witch (Hatred enemy Wizards + Magic Resistance -2), The Revenant (Hatred Undead + Flaming Attacks), The Mutant (Hatred Warriors/Beasts of Chaos + Magic Resistance -1), The Daemon (Hatred Daemons + Magical Attacks).`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/suffer-not`},
  "temperamental": {name:`Temperamental`,desc:`If a natural 1 is rolled on either die of a Steam Tank's Steam Power or Charge roll, choose Bang! (lose 1 Wound) or Phweee! (halt immediately, cannot move again this turn). A natural 1 on both dice = lose 1 Wound AND halt for the turn.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/temperamental`},
  "two-heads": {name:`Two Heads`,desc:`An Imperial Griffon with Two Heads gains a +1 modifier to its Attacks characteristic.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/two-heads`},
  "veteran-outriders": {name:`Veteran Outriders`,desc:`Missile weapons wielded by Outriders in a City-state of Nuln army are not subject to the Ponderous special rule.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/veteran-outriders`},
  "zealot": {name:`Zealot`,desc:`A character with this rule can only join a unit that has the Fanatical Zeal special rule.`,army:`empire-of-man`,url:`https://tow.whfb.app/special-rules/zealot`},
  "regimental-leadership": {name:`Regimental Leadership`,desc:`A detachment within 3" of its regimental unit (and unless that unit is fleeing) may use the regiment's Leadership characteristic; if the detachment's own Leadership is higher, it uses its own instead.`,army:`universal`,url:`https://tow.whfb.app/warhammer-armies/regimental-leadership`},
  "regimental-psychology": {name:`Regimental Psychology`,desc:`A detachment within 3" of its regimental unit gains any of the following special rules the regiment has: Frenzy, Hatred (X), Immune to Psychology, Stubborn.`,army:`universal`,url:`https://tow.whfb.app/warhammer-armies/regimental-psychology`},
  "supporting-actions": {name:`Supporting Actions`,desc:`When an enemy declares a charge against a regimental unit that does not Flee, each detachment within 3" that is not engaged and not fleeing may declare one Supporting Action per turn: Supporting Fire (shoot the charger, as a Stand & Shoot; its wounds count toward the combat result) or Supporting Charge (counter-charge the charging unit).`,army:`universal`,url:`https://tow.whfb.app/warhammer-armies/supporting-actions`},
  "ambushers": {name:`Ambushers`,desc:`A unit with this special rule may be held in reserve rather than be deployed at the start of the game. From round two onwards, roll a D6 during each Start of Turn sub-phase for each unit in reserve. On 1-3, delayed until next turn. On 4+, the unit arrives as reinforcements during Compulsory Moves, placed on any battlefield edge but not within 8" of an enemy. If still in reserve`,army:`universal`,url:`https://tow.whfb.app/special-rules/ambushers`},
  "armour-bane": {name:`Armour Bane (X)`,desc:`If a model with this special rule rolls a natural 6 when making a roll To Wound, the Armour Piercing characteristic of its weapon is improved by the amount shown in brackets (X). For example, with Armour Bane (1) and an AP of '-', a natural 6 to wound counts the AP as -1 for that Armour Save roll.`,army:`universal`,url:`https://tow.whfb.app/special-rules/armour-bane`},
  "armoured-hide": {name:`Armoured Hide (X)`,desc:`The hide of some creatures forms natural armour and improves their armour value (and that of their rider) by the amount shown in brackets (X). Note that a model wearing no armour is considered to have an armour value of 7+ for the purposes of rules that improve armour value.`,army:`universal`,url:`https://tow.whfb.app/special-rules/armoured-hide`},
  "breath-weapon": {name:`Breath Weapon`,desc:`A model with a Breath Weapon can use it once per round during the Shooting phase. Place the flame template with its broad end over the target and narrow end touching the model's base edge within its front arc. Any model under the template risks being hit. Cannot be used when making a Stand & Shoot charge reaction or when engaged in combat.`,army:`universal`,url:`https://tow.whfb.app/special-rules/breath-weapon`},
  "chariot-runners": {name:`Chariot Runners`,desc:`Friendly chariots can draw line of sight over or through models with this rule and move through friendly units of Chariot Runners in Skirmish formation (if majority have this rule). If the chariot would end on top of a Chariot Runner, nudge the runner aside. In Skirmish, Chariot Runners treat friendly chariots within 1" as part of the unit for coherency.`,army:`universal`,url:`https://tow.whfb.app/special-rules/chariot-runners`},
  "close-order": {name:`Close Order`,desc:`A unit consisting of models with this special rule may adopt a Close Order formation.`,army:`universal`,url:`https://tow.whfb.app/special-rules/close-order`},
  "counter-charge": {name:`Counter Charge`,desc:`When charged in the front arc by cavalry, chariot, or monster, the unit may declare Counter Charge: measure distance; if less than the charging unit's Movement, must Hold or Flee instead. Otherwise pivot to face the enemy and move D3+1" toward them. Both units count as having charged. Cannot Counter Charge if fleeing or already in combat. Only one Counter Charge per turn.`,army:`universal`,url:`https://tow.whfb.app/special-rules/counter-charge`},
  "cumbersome": {name:`Cumbersome`,desc:`Weapons with this special rule cannot be used when making a Stand & Shoot charge reaction.`,army:`universal`,url:`https://tow.whfb.app/special-rules/cumbersome`},
  "detachment": {name:`Detachment`,desc:`A unit with this special rule can be fielded as a detachment.`,army:`universal`,url:`https://tow.whfb.app/special-rules/detachment`},
  "dragged-along": {name:`Dragged Along`,desc:`A model with this special rule that begins its movement within 1" of a friendly infantry unit that is not fleeing and contains ten or more models may replace its Movement characteristic with that of that unit.`,army:`universal`,url:`https://tow.whfb.app/special-rules/dragged-along`},
  "drilled": {name:`Drilled`,desc:`Unless fleeing, a Drilled unit may perform a free redress the ranks manoeuvre immediately before moving. A Drilled unit can also march whilst within 8" of an enemy unit without making a Leadership test. Any character joining a Drilled unit is considered Drilled as well.`,army:`universal`,url:`https://tow.whfb.app/special-rules/drilled`},
  "ethereal": {name:`Ethereal`,desc:`Ethereal creatures treat all terrain as open ground for movement, but cannot end their movement inside impassable terrain (though they can pass through it). Ethereal creatures can only be wounded by Magical attacks. Characters that are not Ethereal cannot join Ethereal units, and vice versa.`,army:`universal`,url:`https://tow.whfb.app/special-rules/ethereal`},
  "evasive": {name:`Evasive`,desc:`Once per turn, when a unit in which the majority of models have this rule is declared a target during the enemy Shooting phase, it may Fall Back in Good Order, fleeing directly away from the shooting unit. Once the move is complete, the enemy unit may continue shooting as declared.`,army:`universal`,url:`https://tow.whfb.app/special-rules/evasive`},
  "extra-attacks": {name:`Extra Attacks (+X)`,desc:`A model with this special rule has a modifier to its Attacks characteristic as shown in brackets (+X). If this modifier is determined by a dice roll, roll when the model's combat is chosen during the Choose & Fight Combat sub-phase.`,army:`universal`,url:`https://tow.whfb.app/special-rules/extra-attacks`},
  "fast-cavalry": {name:`Fast Cavalry`,desc:`If all of the models (including characters) within a unit arrayed in an Open Order formation have this special rule, the unit may perform its Quick Turn even if it marched.`,army:`universal`,url:`https://tow.whfb.app/special-rules/fast-cavalry`},
  "fear": {name:`Fear`,desc:`Models cause Fear. A unit wishing to charge an enemy that causes Fear and has higher Unit Strength must pass a Leadership test or the charge fails. A unit engaged with such an enemy when combat is chosen must pass a Leadership test or suffer -1 to hit rolls against it. Only one Fear test per turn. Models causing Fear are immune to Fear.`,army:`universal`,url:`https://tow.whfb.app/special-rules/fear`},
  "feigned-flight": {name:`Feigned Flight`,desc:`If this unit chooses to Flee (or Fire & Flee) as a charge reaction, it automatically rallies at the end of its move.`,army:`universal`,url:`https://tow.whfb.app/special-rules/feigned-flight`},
  "fight-in-extra-rank": {name:`Fight in Extra Rank`,desc:`A model with this special rule may make supporting attacks.`,army:`universal`,url:`https://tow.whfb.app/special-rules/fight-in-extra-rank`},
  "fire-and-flee": {name:`Fire & Flee`,desc:`If the majority of models in a missile-armed unit have this rule, the unit may declare Fire & Flee as a charge reaction: Stand & Shoot, then flee. When fleeing, roll two D6 and discard the lowest result. If the distance to the charging unit is less than the charger's Movement, must Hold or Flee instead.`,army:`universal`,url:`https://tow.whfb.app/special-rules/fire-and-flee`},
  "first-charge": {name:`First Charge`,desc:`If this unit's first charge of the game is successful (makes contact with the charge target), the charge target becomes Disrupted until the end of the Combat phase of that turn.`,army:`universal`,url:`https://tow.whfb.app/special-rules/first-charge`},
  "flaming-attacks": {name:`Flaming Attacks`,desc:`Any attack made or hits caused by a model with this rule (or a weapon/spell with it) is a Flaming attack. Also causes Fear in war beasts and swarms. Unless stated otherwise, applies both when shooting and in combat (spells cast by the model and attacks with magic weapons are unaffected).`,army:`universal`,url:`https://tow.whfb.app/special-rules/flaming-attacks`},
  "flammable": {name:`Flammable`,desc:`A model with this special rule cannot make a Regeneration save against a wound caused by a Flaming attack.`,army:`universal`,url:`https://tow.whfb.app/special-rules/flammable`},
  "fly": {name:`Fly (X)`,desc:`Except when following up or pursuing, the model may fly using its Fly Movement (X) instead of moving on the ground. Flying models may pass freely over other models, units, and terrain without penalty, and can march within 8" of enemies without a Leadership test. May end in terrain but suffers its effects; cannot end on impassable terrain, atop another unit, or within 1" of enem`,army:`universal`,url:`https://tow.whfb.app/special-rules/fly`},
  "frenzy": {name:`Frenzy`,desc:`During a turn the model charged or the turn after a follow up, a Frenzied model gains +1 Attack (not its mount/beasts/rider). If majority are Frenzied: auto-pass Fear/Panic/Terror tests; unit must declare a charge if able; cannot choose to Flee as charge reaction or make Restraint tests. Frenzy is lost immediately if the unit loses a round of combat.`,army:`universal`,url:`https://tow.whfb.app/special-rules/frenzy`},
  "furious-charge": {name:`Furious Charge`,desc:`During a turn in which it made a charge move of 3" or more, a model with this special rule gains a +1 modifier to its Attacks characteristic.`,army:`universal`,url:`https://tow.whfb.app/special-rules/furious-charge`},
  "hatred": {name:`Hatred (X)`,desc:`A model with this special rule may re-roll any failed rolls To Hit against a hated enemy during the first round of combat. Which enemies are hated is shown in brackets (X). Some models hate 'all enemies'.`,army:`universal`,url:`https://tow.whfb.app/special-rules/hatred`},
  "horde": {name:`Horde`,desc:`A unit with this special rule may increase the maximum Rank Bonus it can claim (as determined by its troop type) by one.`,army:`universal`,url:`https://tow.whfb.app/special-rules/horde`},
  "howdah": {name:`Howdah`,desc:`A behemoth with this special rule has a split profile and follows both the Split Profile (Chariots) and Firing Platform rules to represent its armoured howdah and crew. In all other respects it is a behemoth.`,army:`universal`,url:`https://tow.whfb.app/special-rules/howdah`},
  "ignores-cover": {name:`Ignores Cover`,desc:`If a model making a shooting attack has this special rule, it ignores any To Hit modifiers caused by partial or full cover.`,army:`universal`,url:`https://tow.whfb.app/special-rules/ignores-cover`},
  "immune-to-psychology": {name:`Immune to Psychology`,desc:`If the majority of models in a unit are Immune to Psychology, the unit automatically passes any Fear, Panic, or Terror tests it must make. However, such a unit cannot choose to Flee as a charge reaction. This rule does not grant immunity to other Leadership tests.`,army:`universal`,url:`https://tow.whfb.app/special-rules/immune-to-psychology`},
  "impact-hits": {name:`Impact Hits (X)`,desc:`Impact Hits (number shown in brackets as X, often a dice roll) can only be made by a charging model that moved 3" or more and is in base contact with the enemy. Resolved against the charged unit when combat is chosen (Step 1.1), before challenges. They hit automatically using the model's unmodified Strength.`,army:`universal`,url:`https://tow.whfb.app/special-rules/impact-hits`},
  "impetuous": {name:`Impetuous`,desc:`If a unit containing one or more Impetuous models is able to declare a charge during the Declare Charges & Charge Reactions sub-phase, it must make a Leadership test. If failed, the unit must declare a charge. If passed, the unit may act as normal.`,army:`universal`,url:`https://tow.whfb.app/special-rules/impetuous`},
  "killing-blow": {name:`Killing Blow`,desc:`If a model with this rule rolls a natural 6 To Wound in combat, it strikes a Killing Blow. Enemy infantry or cavalry cannot make armour or Regeneration saves (Ward saves are allowed). If the wound is unsaved, the model loses all remaining Wounds. Cannot be used if the attack wounds automatically.`,army:`universal`,url:`https://tow.whfb.app/special-rules/killing-blow`},
  "large-target": {name:`Large Target`,desc:`Large Targets do not benefit from partial or full cover. A unit can draw line of sight to a Large Target over or through another non-Large Target unit, and vice versa. A unit shooting at a Large Target may shoot with one additional rank (e.g., crossbows shoot with first two ranks instead of one).`,army:`universal`,url:`https://tow.whfb.app/special-rules/large-target`},
  "levies": {name:`Levies`,desc:`Models with this special rule cannot use the General's Inspiring Presence or the Battle Standard's Hold your Ground. However, units without this rule are not required to make a Panic test when a friendly unit of Levies Breaks and flees from combat.`,army:`universal`,url:`https://tow.whfb.app/special-rules/levies`},
  "loner": {name:`Loner`,desc:`A character with this special rule cannot be your General and cannot join a unit without this special rule. A unit with this special rule cannot be joined by a character without this special rule.`,army:`universal`,url:`https://tow.whfb.app/special-rules/loner`},
  "magical-attacks": {name:`Magical Attacks`,desc:`Any attack made or hit caused by a model with this special rule, or made using a weapon with this special rule, is a Magical attack. All spells are considered to have this special rule, as are any hits caused by magic items.`,army:`universal`,url:`https://tow.whfb.app/special-rules/magical-attacks`},
  "magic-resistance": {name:`Magic Resistance (-X)`,desc:`The Casting roll of any enemy spell (including Bound spells) that targets a unit that includes one or more models with this special rule suffers a modifier, as shown in brackets after the name of this special rule (-X). This special rule is not cumulative — if two or more models in a unit have this special rule, use the highest modifier.`,army:`universal`,url:`https://tow.whfb.app/special-rules/magic-resistance`},
  "mercenaries": {name:`Mercenaries`,desc:`Often, an army can include certain units drawn from another army list as mercenaries. Any such units included in your army gain this special rule. Mercenaries cannot use the Inspiring Presence rule of the army's General nor the "Hold your Ground" rule of a Battle Standard. Mercenaries cannot be joined by characters drawn from another army list.`,army:`universal`,url:`https://tow.whfb.app/special-rules/mercenaries`},
  "monster-handlers": {name:`Monster Handlers`,desc:`A monster with this special rule is accompanied by one or more handler models. During deployment, position handlers adjacent to and in base contact with the monster. In combat, each handler adds its attacks to those of the monster. If the monster suffers an unsaved wound, roll a D6: on 1-4 the monster loses a Wound, on 5+ a handler is removed instead. If the monster is removed `,army:`universal`,url:`https://tow.whfb.app/special-rules/monster-handlers`},
  "monster-slayer": {name:`Monster Slayer`,desc:`If a model with this special rule rolls a natural 6 To Wound in combat, it strikes a 'Monster Slaying Blow'. Enemy monsters are not permitted an armour or Regeneration save against it (Ward saves can be attempted). If an enemy monster suffers an unsaved wound from a Monster Slaying Blow, it loses all remaining Wounds. Note: if an attack wounds automatically, this rule cannot be`,army:`universal`,url:`https://tow.whfb.app/special-rules/monster-slayer`},
  "motley-crew": {name:`Motley Crew`,desc:`Units with this special rule may include models equipped differently or of different types in a single unit. The fighting rank may contain models with different weapons (roll separate dice batches per model). Models may have different armour values (use majority in the fighting rank for combat, majority in the unit for shooting). Casualty removal is divided as equally as possib`,army:`universal`,url:`https://tow.whfb.app/special-rules/motley-crew`},
  "move-and-shoot": {name:`Move & Shoot`,desc:`A weapon with this special rule can be used in the Shooting phase even if the model equipped with it marched this turn.`,army:`universal`,url:`https://tow.whfb.app/special-rules/move-and-shoot`},
  "move-or-shoot": {name:`Move or Shoot`,desc:`A weapon with this special rule cannot be used in the Shooting phase if the model equipped with it moved for any reason during this turn (including rallying and reforming).`,army:`universal`,url:`https://tow.whfb.app/special-rules/move-or-shoot`},
  "move-through-cover": {name:`Move Through Cover`,desc:`Models with this special rule do not suffer any modifiers to their Movement characteristic for moving through difficult or dangerous terrain. In addition, a model with this special rule may re-roll any rolls of 1 when making Dangerous Terrain tests.`,army:`universal`,url:`https://tow.whfb.app/special-rules/move-through-cover`},
  "multiple-shots": {name:`Multiple Shots (X)`,desc:`A weapon with this special rule can fire a single shot as normal, or it can be fired a number of times as shown in brackets (X). If multiple shots are fired, each roll To Hit suffers an additional -1 modifier. All models in a unit must fire either single or Multiple Shots. Where the number is generated by a dice roll, roll separately for each model.`,army:`universal`,url:`https://tow.whfb.app/special-rules/multiple-shots`},
  "multiple-wounds": {name:`Multiple Wounds (X)`,desc:`Each unsaved wound inflicted by an attack with this special rule is multiplied by the number shown in brackets (X). For example, Multiple Wounds (2) means each unsaved wound causes the target to lose two Wounds. Where the number is generated by a dice roll, roll separately for each unsaved wound. Excess wounds do not spill over onto other models.`,army:`universal`,url:`https://tow.whfb.app/special-rules/multiple-wounds`},
  "open-order": {name:`Open Order`,desc:`A unit consisting of models with this special rule may adopt an Open Order formation.`,army:`universal`,url:`https://tow.whfb.app/special-rules/open-order`},
  "poisoned-attacks": {name:`Poisoned Attacks`,desc:`If a model with Poisoned Attacks rolls a natural 6 To Hit, it may apply a +2 modifier to that hit's roll To Wound. Unless otherwise stated, this applies to both shooting and combat attacks. Spells and attacks with magic weapons are unaffected. Note: if an attack needs a To Hit roll of 7+, or hits automatically, this rule cannot be used.`,army:`universal`,url:`https://tow.whfb.app/special-rules/poisoned-attacks`},
  "ponderous": {name:`Ponderous`,desc:`A weapon with this special rule suffers a To Hit modifier of -2 for Moving and Shooting, rather than the usual -1.`,army:`universal`,url:`https://tow.whfb.app/special-rules/ponderous`},
  "quick-shot": {name:`Quick Shot`,desc:`A weapon with this special rule does not suffer the usual -1 To Hit modifier for Moving and Shooting. In addition, a unit equipped with such weapons can make a Stand & Shoot charge reaction regardless of how close the charging unit is.`,army:`universal`,url:`https://tow.whfb.app/special-rules/quick-shot`},
  "rallying-cry": {name:`Rallying Cry`,desc:`During the Command sub-phase of their turn, if not engaged in combat, this character may nominate a single fleeing friendly unit within their Command range. The nominated unit immediately makes a Rally test. If this test is failed, the unit may attempt to rally again as normal during the Rally sub-phase.`,army:`universal`,url:`https://tow.whfb.app/special-rules/rallying-cry`},
  "random-attacks": {name:`Random Attacks`,desc:`Models with this special rule do not have a normal Attacks characteristic. Instead, a dice roll is given (e.g. D3+1). Each time a model with this rule attacks in combat, roll the dice to determine the number of attacks, then roll To Hit as normal. If a fighting rank contains more than one such model, roll separately for each unless specified otherwise.`,army:`universal`,url:`https://tow.whfb.app/special-rules/random-attacks`},
  "random-movement": {name:`Random Movement`,desc:`Models with this special rule do not have a normal Movement characteristic; a dice roll is given instead (e.g. 2D6). They move during the Compulsory Moves sub-phase, cannot march or declare a charge, and can only wheel. If they contact an enemy during Compulsory Moves or pursuit they count as having charged (the enemy must Hold). If every model in a unit has this rule, roll onc`,army:`universal`,url:`https://tow.whfb.app/special-rules/random-movement`},
  "regeneration": {name:`Regeneration (X+)`,desc:`Immediately after a Wound is lost, but before models with zero Wounds remaining are removed from play, a model with this special rule may make a 'Regeneration save' by rolling a D6 and comparing to its Regeneration value (X+). If the roll equals or exceeds the value, the lost Wound is recovered, but still counts for combat result. Rules that affect armour values do not affect R`,army:`universal`,url:`https://tow.whfb.app/special-rules/regeneration`},
  "regimental-unit": {name:`Regimental Unit`,desc:`A unit with this special rule can be accompanied by a detachment.`,army:`universal`,url:`https://tow.whfb.app/special-rules/regimental-unit`},
  "requires-two-hands": {name:`Requires Two Hands`,desc:`A model cannot use a shield alongside a weapon with this special rule during the Combat phase. A shield can still be used against wounds caused by shooting or magic during other phases of the game.`,army:`universal`,url:`https://tow.whfb.app/special-rules/requires-two-hands`},
  "reserve-move": {name:`Reserve Move`,desc:`Unless it charged, marched or fled during the Movement phase, a unit where the majority of models have this rule may make a Reserve move at the end of the Shooting phase, after all shooting is resolved. A unit making a Reserve move moves as per Basic Movement rules, may manoeuvre normally, but cannot march.`,army:`universal`,url:`https://tow.whfb.app/special-rules/reserve-move`},
  "scouts": {name:`Scouts`,desc:`Units with this special rule may be deployed after all other units from both armies, anywhere on the battlefield more than 12" away from an enemy model. If deployed this way, Scouts cannot declare a charge during their first turn. If both armies contain Scouts, a roll-off determines who deploys first; players alternate deploying scouting units one at a time.`,army:`universal`,url:`https://tow.whfb.app/special-rules/scouts`},
  "shieldwall": {name:`Shieldwall`,desc:`Once per game, during a turn in which it was charged, a unit with this rule that is in Close Order formation and equipped with and using shields may Give Ground rather than Fall Back in Good Order.`,army:`universal`,url:`https://tow.whfb.app/special-rules/shieldwall`},
  "skirmishers": {name:`Skirmishers`,desc:`A unit consisting of models with this special rule may adopt a Skirmish formation.`,army:`universal`,url:`https://tow.whfb.app/special-rules/skirmishers`},
  "stomp-attacks": {name:`Stomp Attacks (X)`,desc:`The number of Stomp Attacks varies per model and is shown in brackets (X), often determined by a dice roll. Stomp Attacks can only be made when in base contact with the enemy. They are made last in combat, after all other attacks including those at Initiative 1. They hit automatically and use the unmodified Strength of the model making them.`,army:`universal`,url:`https://tow.whfb.app/special-rules/stomp-attacks`},
  "strike-first": {name:`Strike First`,desc:`During the Combat phase, a model with this rule that is engaged in combat improves its Initiative characteristic to 10 (before any other modifiers are applied). If a model has both Strike First and Strike Last, the two rules cancel one another out.`,army:`universal`,url:`https://tow.whfb.app/special-rules/strike-first`},
  "strike-last": {name:`Strike Last`,desc:`During the Combat phase, a model with this rule that is engaged in combat reduces its Initiative characteristic to 1 (before any other modifiers are applied). If a model has both Strike Last and Strike First, the two rules cancel one another out.`,army:`universal`,url:`https://tow.whfb.app/special-rules/strike-last`},
  "stubborn": {name:`Stubborn`,desc:`The first time this unit is required to make a Break test, it may choose not to and will automatically Fall Back in Good Order instead, even if the winning side's Unit Strength is more than twice that of the losing side. A non-Stubborn unit does not become Stubborn when joined by a Stubborn character. A Stubborn character cannot use this rule whilst part of a non-Stubborn unit.`,army:`universal`,url:`https://tow.whfb.app/special-rules/stubborn`},
  "stupidity": {name:`Stupidity`,desc:`Unless fleeing or in combat, a unit with this rule must test for Stupidity (Leadership test) during the Start of Turn sub-phase each turn. If failed, until its next Start of Turn the unit cannot move (except to flee), cannot shoot or cast spells, cannot attempt a Wizardly dispel, and must Hold if charged. A unit/mount without this rule gains it when joined/ridden by a character`,army:`universal`,url:`https://tow.whfb.app/special-rules/stupidity`},
  "swiftstride": {name:`Swiftstride`,desc:`A unit consisting entirely of models with this special rule increases its maximum possible charge range by 3" and, before making a Charge, Flee or Pursuit roll, may choose to apply a +D6 modifier to the result.`,army:`universal`,url:`https://tow.whfb.app/special-rules/swiftstride`},
  "terror": {name:`Terror`,desc:`Models with this rule cause Terror and also Fear. When a Terror-causing unit declares a charge, the target must make a Leadership test: failure means it must Flee; success allows a normal charge reaction. If the winning combat side includes a Terror-causing unit, losing side units apply -1 to Leadership when making Break tests. Models with Fear also Fear Terror-causers. Terror-`,army:`universal`,url:`https://tow.whfb.app/special-rules/terror`},
  "timmm-berrr": {name:`Timmm-berrr!`,desc:`When this model is reduced to zero Wounds, the winner of a roll-off chooses one of its arcs (front, flank or rear) for it to fall into. Any units within the chosen arc and in base contact suffer D6 hits, each using the Strength of this model with AP -1. Once these hits are resolved, the model is removed from play.`,army:`universal`,url:`https://tow.whfb.app/special-rules/timmm-berrr`},
  "unbreakable": {name:`Unbreakable`,desc:`If a unit with this rule loses a round of combat, it is not required to make a Break test. Instead, it automatically Gives Ground as it is pushed back by the enemy. Characters that are not Unbreakable cannot join units that are, and vice versa.`,army:`universal`,url:`https://tow.whfb.app/special-rules/unbreakable`},
  "unstable": {name:`Unstable`,desc:`If a unit with this rule loses a round of combat, it loses one additional Wound for every combat result point by which it lost. These Wounds are lost after combat results are calculated but before Break tests, and cannot be recovered by a Regeneration save. If the unit contains Unstable characters, allocate wounds to all models first (one each), then divide any remaining wounds`,army:`universal`,url:`https://tow.whfb.app/special-rules/unstable`},
  "vanguard": {name:`Vanguard`,desc:`After deployment, units with this special rule may make a Vanguard move as per Basic Movement rules (may manoeuvre normally but cannot march). If both armies contain Vanguard units, a roll-off determines who moves first; players alternate moving Vanguard units one at a time. Units that make a Vanguard move cannot declare a charge during their first turn.`,army:`universal`,url:`https://tow.whfb.app/special-rules/vanguard`},
  "veteran": {name:`Veteran`,desc:`If the majority of the models in a unit have this special rule, the unit may re-roll any failed Leadership test. Note that a Break test is not a Leadership test.`,army:`universal`,url:`https://tow.whfb.app/special-rules/veteran`},
  "volley-fire": {name:`Volley Fire`,desc:`When a unit with this rule makes a shooting attack, half the models in each rank other than the front rank (or front two ranks if on a hill), rounding up, can also shoot. A unit cannot Volley Fire if it moved for any reason during the turn (including reforming) or when making a Stand & Shoot charge reaction.`,army:`universal`,url:`https://tow.whfb.app/special-rules/volley-fire`},
  "warband": {name:`Warband`,desc:`Unless fleeing, a Warband gains a positive modifier to its Leadership equal to its current Rank Bonus (max Leadership 10). This modifier cannot be used for Restraint tests or, if Impetuous, when testing to charge. If the majority of models in a unit have this rule, the unit may re-roll its Charge roll. Non-Warband characters' Leadership cannot be modified by this rule.`,army:`universal`,url:`https://tow.whfb.app/special-rules/warband`},
  "warp-spawned": {name:`Warp-spawned`,desc:`A model with this special rule cannot make a Regeneration save against a wound caused by a Magical attack. In addition, characters that are not Warp-spawned cannot join units that are, and vice versa.`,army:`universal`,url:`https://tow.whfb.app/special-rules/warp-spawned`},
  "gromril-armour": {name:`Gromril Armour`,desc:`The metal the Dwarfs call gromril is the toughest and sturdiest in the known world. A model with this special rule may re-roll any roll of a natural 1 made when making an Armour Save roll.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/gromril-armour`},
  "gromril-weapons": {name:`Gromril Weapons`,desc:`A hand weapon carried by a model with this special rule has an Armour Piercing characteristic of -1. Note that this special rule only applies to a single, ordinary hand weapon. If the model is using two hand weapons or any other sort of weapon, or if their hand weapon is inscribed with any Weapon runes, this special rule ceases to apply.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/gromril-weapons`},
  "ancestral-shield": {name:`Ancestral Shield`,desc:`An Anvil of Doom and the Forgefather & Anvil Guard have a 5+ Ward save against any wounds suffered.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/ancestral-shield`},
  "resolute": {name:`Resolute`,desc:`Models with this special rule suffer a -1 modifier to the result of any Flee roll or Pursuit roll they make (to a minimum of 1). Note that this modifier does not apply to Chaos Dwarf mounted characters.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/resolute`},
  "deathblow": {name:`Deathblow`,desc:`When a model with this special rule is reduced to zero Wounds by an enemy attack during the Combat phase, the unit that made the attack suffers a Strength 3 hit, with an AP of -1. Note that if this model is reduced to zero Wounds whilst engaged in a challenge, it is the model that made the attack that suffers this hit, rather than its unit.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/deathblow`},
  "slayer": {name:`Slayer`,desc:`When this model makes a roll To Wound, a roll of 4+ is always a success, regardless of the target's Toughness.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/slayer`},
  "slayer-of-daemons": {name:`Slayer of Daemons`,desc:`When this character makes a roll To Wound, a roll of 4+ is always a success, regardless of the target's Toughness. In addition, each unsaved wound inflicted by this character against an enemy model with the Warp-spawned special rule, or whose troop type is behemoth, has the Multiple Wounds (D3) special rule.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/slayer-of-daemons`},
  "slayer-of-dragons": {name:`Slayer of Dragons`,desc:`When this character makes a roll To Wound, a roll of 4+ is always a success, regardless of the target's Toughness. In addition, each unsaved wound inflicted by this character against an enemy model whose troop type is behemoth has the Multiple Wounds (D3) special rule.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/slayer-of-dragons`},
  "rune-lore": {name:`Rune Lore`,desc:`A model with this special rule may be nominated to attempt a Wizardly Dispel as if it were a Wizard. An Anvil of Doom has a Dispel range of 24" and may apply a +3 modifier to its Dispel rolls. A Runelord has a Dispel range of 21" and may apply a +2 modifier. A Runesmith has a Dispel range of 18" and may apply a +1 modifier.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/rune-lore`},
  "runes-of-protection": {name:`Runes of Protection`,desc:`Models with this special rule have a 6+ Ward save against any wounds suffered that were caused by a non-magical enemy attack.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/runes-of-protection`},
  "runes-of-warding": {name:`Runes of Warding`,desc:`A model with this special rule has a 5+ Ward save against any wounds suffered that were caused by an attack that has the Flaming Attacks special rule.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/runes-of-warding`},
  "immovable-object": {name:`Immovable Object`,desc:`Once this model has been placed on the battlefield during deployment it cannot be moved by its crew during the Remaining Moves sub-phase. Note that the model can still pivot freely at any time during its turn and may make a follow up move as normal.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/immovable-object`},
  "strike-the-runes": {name:`Strike the Runes`,desc:`An Anvil of Doom can cast the following Bound spells (Power Level 2): Rune of Oath & Steel (re-roll failed Armour Saves, or also improve armour value by 1 on 11+), Rune of Hearth & Home (friendly Dwarfs within 21" gain Immune to Psychology), Rune of Haste & Urgency (target unit may move again), Rune of Wrath & Ruin (target suffers 2D6 Strength 4 hits, AP -2).`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/strike-the-runes`},
  "bombing-run": {name:`Bombing Run`,desc:`This model may perform a Bombing Run attack against a single enemy unit not engaged in combat, by flying over it during Remaining Moves. Roll D6: 1=lose a Wound; 2=enemy loses a Wound; 3-4=place large (5") blast template, scatter D6", Str 4 AP -1 hits; 5-6=place two small (3") blast templates, scatter D6" each, Str 4 AP -1 hits.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/bombing-run`},
  "forgefire": {name:`Forgefire`,desc:`If this character joins a unit, that unit will gain the Armour Bane (2) and Flaming Attacks special rules. Should this character leave a unit it has joined for any reason, that unit loses these special rules.`,army:`dwarfs`,url:`https://tow.whfb.app/special-rules/forgefire`},
  "elven-reflexes": {name:`Elven Reflexes`,desc:`A model with this special rule (but not its mount) has a +1 modifier to its Initiative characteristic (to a maximum of 10) during the first round of any combat.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/elven-reflexes`},
  "sea-dragon-cloak": {name:`Sea Dragon Cloak`,desc:`A model with this special rule improves its armour value by 1 (to a maximum of 2+) against non-magical shooting attacks.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/sea-dragon-cloak`},
  "martial-prowess": {name:`Martial Prowess`,desc:`A unit with this special rule can make supporting attacks to its flank or rear, as well as to its front.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/martial-prowess`},
  "eternal-hatred": {name:`Eternal Hatred`,desc:`Against High Elves, this model's Hatred applies in every round of close combat, not just the first. Note that this special rule does not apply to this model's mount (should it have one).`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/eternal-hatred`},
  "dark-runes": {name:`Dark Runes`,desc:`This unit has a 5+ Ward save against any wounds suffered that were caused by a non-magical enemy attack.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/dark-runes`},
  "murderous": {name:`Murderous`,desc:`When engaged in combat, a model with this special rule that is fighting with a hand weapon may re-roll any rolls To Wound of a natural 1. Note that this special rule only applies to a single, non-magical hand weapon and does not apply to a model's mount. If the model is using two hand weapons or any other sort of weapon, this special rule ceases to apply.`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/murderous`},
  "cleaving-blow": {name:`Cleaving Blow`,desc:`If a model with this special rule rolls a natural 6 when making a roll To Wound for an attack made in combat, it has struck a Cleaving Blow. Enemy models whose troop type is regular infantry, heavy infantry, light cavalry, heavy cavalry or war beasts are not permitted an armour or Regeneration save against a Cleaving Blow (Ward saves can be attempted as normal). Note that if an`,army:`dark-elves`,url:`https://tow.whfb.app/special-rules/cleaving-blow`},
  "daemonic": {name:`Daemonic`,desc:`Models with this special rule are Daemonic and have a 5+ Ward save against wounds caused by non-magical enemy attacks. All Daemonic models also have: Daemonic Instability, Fear, Immune to Psychology, Magical Attacks, Unbreakable, and Warp-spawned. A character with this special rule cannot join a unit without this special rule, and vice versa.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/daemonic`},
  "daemonic-instability": {name:`Daemonic Instability`,desc:`If a unit with this special rule loses a round of combat, it must make a Leadership test with a +1 modifier per combat result point lost. If passed, all is well. If failed, the unit loses Wounds equal to the amount failed by. If failed on a natural double 6, the unit is immediately removed from play.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/daemonic-instability`},
  "daemonic-charge": {name:`Daemonic Charge`,desc:`Impact Hits caused by this model have an Armour Piercing characteristic of -2.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/daemonic-charge`},
  "daemon-of-khorne": {name:`Daemon of Khorne`,desc:`Daemons of Khorne have the Hatred (Daemons of Slaanesh) special rule. In addition, during a turn in which it made a charge move, a Daemon of Khorne (but not its mount) gains a +1 modifier to its Strength characteristic.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/daemon-of-khorne`},
  "daemon-of-nurgle": {name:`Daemon of Nurgle`,desc:`Daemons of Nurgle have the Hatred (Daemons of Tzeentch) special rule. In addition, any enemy model that directs its attacks against a Daemon of Nurgle during the Combat phase must re-roll any rolls To Hit of a natural 6.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/daemon-of-nurgle`},
  "daemon-of-slaanesh": {name:`Daemon of Slaanesh`,desc:`Daemons of Slaanesh have the Hatred (Daemons of Khorne) special rule. In addition, Daemons of Slaanesh increase their maximum possible charge range by 1" and have a +1 modifier to the result of any Charge or Pursuit roll they make.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/daemon-of-slaanesh`},
  "daemon-of-tzeentch": {name:`Daemon of Tzeentch`,desc:`Daemons of Tzeentch have the Hatred (Daemons of Nurgle) special rule. In addition, a Daemon of Tzeentch that is also a Wizard may apply a +1 modifier to any Casting roll they make. Note that this modifier does not negate a roll of a natural double 1.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/daemon-of-tzeentch`},
  "infernal-favour": {name:`Infernal Favour (X)`,desc:`A unit with this special rule reduces the number of wounds suffered due to the Daemonic Instability special rule by the number shown in brackets (X). Note that this special rule is not cumulative — if two or more models in a unit have this special rule, use the highest value for the entire unit.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/infernal-favour`},
  "scintillating-sorcery": {name:`Scintillating Sorcery`,desc:`A unit of Pink Horrors knows one of the spells that corresponds to their Daemonic Alignment (chosen by their controlling player before armies are deployed). The unit may cast this spell as a Bound spell, with a Power Level equal to the unit's current Rank Bonus.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/scintillating-sorcery`},
  "soporific-musk": {name:`Soporific Musk`,desc:`Enemy models engaged in combat with a model with this special rule cannot use the Strike First special rule. Enemy models that do not have the Strike First special rule become subject to the Strike Last special rule instead.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/soporific-musk`},
  "gorefeast": {name:`Gorefeast`,desc:`For each Wound an enemy unit loses as a result of an Impact Hit caused by this model, roll a D6. For each roll of 6, this model immediately recovers a single lost Wound.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/gorefeast`},
  "attention-seeker": {name:`Attention Seeker`,desc:`Every model in a unit of Beasts of Nurgle can issue and accept challenges in the same manner as a character.`,army:`daemons`,url:`https://tow.whfb.app/special-rules/attention-seeker`},
  "necromantic-undead": {name:`Necromantic Undead`,desc:`Models with this special rule are 'Undead'. Undead models cannot march (unless they have the Fly (X) special rule and choose to move by flying). All Undead models have: Fear, Immune To Psychology, Unbreakable, Unstable. A character with this special rule cannot join a unit without this special rule, and vice versa.`,army:`vampire-counts`,url:`https://tow.whfb.app/special-rules/necromantic-undead`},
  "nehekharan-undead": {name:`Nehekharan Undead`,desc:`Models with this special rule are 'Undead'. Undead models cannot march (unless they have the Fly (X) special rule and choose to move by flying). All Undead models have: Fear, Immune To Psychology, Unbreakable, Unstable. A character with this special rule cannot join a unit without this special rule, and vice versa.`,army:`tomb-kings`,url:`https://tow.whfb.app/special-rules/nehekharan-undead`},
  "the-hunger": {name:`The Hunger`,desc:`At the end of any Combat phase in which this character inflicted one or more unsaved wounds, roll a D6. On a 6, this character recovers a single lost Wound. However, whenever they (and any unit they have joined) make a Pursuit roll, they roll only a single D6 (rather than the usual 2D6).`,army:`vampire-counts`,url:`https://tow.whfb.app/special-rules/the-hunger`},
  "invocation-of-nehek": {name:`Invocation of Nehek`,desc:`During the Command sub-phase of their turn, if not engaged in combat, this character may attempt to resurrect the fallen by making a Leadership test. If passed, a single friendly Necromantic Undead unit within 12" recovers lost Wounds: regular/heavy infantry recover Level +D3; swarms/light cavalry/war beasts recover Level +1; monstrous infantry/heavy cavalry/monstrous cavalry/l`,army:`vampire-counts`,url:`https://tow.whfb.app/special-rules/invocation-of-nehek`},
  "dry-as-dust": {name:`Dry as Dust`,desc:`Each time this model suffers an unsaved wound from a Flaming Attack, your opponent may roll a D6. On 1-3, the flames die down and this model escapes further harm. On 4+, the flames take hold and this model loses one additional Wound. Excess wounds have no additional effect except for Overkill in a challenge; they do not spill over onto other models.`,army:`tomb-kings`,url:`https://tow.whfb.app/special-rules/dry-as-dust`},
  "khopesh": {name:`Khopesh`,desc:`A hand weapon carried by a model with this special rule has an Armour Piercing characteristic of -1. This only applies to a single, ordinary hand weapon and does not apply to the model's mount. If the model is using two hand weapons or any other sort of weapon, this special rule ceases to apply.`,army:`tomb-kings`,url:`https://tow.whfb.app/special-rules/khopesh`},
  "choppas": {name:`Choppas`,desc:`During a turn in which it charged, a model with this special rule may re-roll any rolls To Wound of a natural 1, and improves the Armour Piercing characteristic of its weapon(s) by 1. This only applies to non-magical weapons and does not apply to the model's mount. If the model is using a magic weapon, this special rule ceases to apply.`,army:`orc-goblins`,url:`https://tow.whfb.app/special-rules/choppas`},
  "da-boyz": {name:`Da Boyz`,desc:`Your army must include one Black Orc Boss for every Black Orc Mob it includes, and vice versa. For each Black Orc Mob your army includes, it must also include one Black Orc War Boss or Big Boss. For each Black Orc War Boss or Big Boss your army includes, it must also include one Black Orc Mob.`,army:`orc-goblins`,url:`https://tow.whfb.app/special-rules/da-boyz`},
  "waaagh": {name:`Waaagh!`,desc:`Once per game, during the Command sub-phase of their turn, this character may attempt to invoke the Waaagh! by making a Leadership test. If passed, until the next Start of Turn sub-phase this character, their mount and any Orc unit joined may re-roll To Hit rolls of 1 and claim an additional +1 combat result point. Not cumulative. An Orc unit must be made up entirely of Orcs or`,army:`orc-goblins`,url:`https://tow.whfb.app/special-rules/waaagh`},
  "ignore-panic": {name:`Ignore Panic`,desc:`This unit does not have to make a Panic test when a friendly unit that does not also have this special rule is destroyed or Breaks and flees from combat whilst within 6" of it. Nor does this unit have to make a Panic test when it is fled through by a friendly unit that does not have this special rule.`,army:`orc-goblins`,url:`https://tow.whfb.app/special-rules/ignore-panic`},
  "quell-impetuosity": {name:`Quell Impetuosity`,desc:`Whilst within 6" of a unit with this special rule, a friendly Impetuous unit may re-roll a failed Leadership test when testing to determine if it must declare a charge or act as normal.`,army:`orc-goblins`,url:`https://tow.whfb.app/special-rules/quell-impetuosity`},
  "primal-fury": {name:`Primal Fury`,desc:`When this unit's combat is chosen during Step 1.1 of any Choose & Fight Combat sub-phase, it must make a Leadership test. If this test is passed, the unit becomes subject to 'Primal Fury' until the end of this Combat phase. A unit subject to Primal Fury may re-roll any rolls To Hit of a natural 1.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/primal-fury`},
  "blood-rage": {name:`Blood Rage`,desc:`If, when testing to see if it becomes subject to Primal Fury, this unit passes its Leadership test with any roll of a natural double, it will also become Frenzied. A unit with this special rule may become Frenzied in this way even if it has lost Frenzy earlier in the game.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/blood-rage`},
  "ensorcelled-weapons": {name:`Ensorcelled Weapons`,desc:`A hand weapon carried by a model with this special rule has the Magical Attacks special rule and an Armour Piercing characteristic of -1. This only applies to a single, non-magical hand weapon and does not apply to the model's mount. If the model is using two hand weapons or any other sort of weapon, this special rule ceases to apply.`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/ensorcelled-weapons`},
  "gaze-of-the-gods": {name:`Gaze of the Gods`,desc:`During the Command sub-phase of their turn, a character with this special rule may roll on the Gaze of the Gods table (D6): 1 - Stupidity for the game (or -1 Ld); 2 - +1 Initiative until next Start of Turn; 3 - +1 Toughness until next Start of Turn; 4 - +1 Weapon Skill for the game; 5 - +1 Attacks for the game; 6 - +1 Strength and +1 Leadership for the game. Benefits apply only`,army:`beastmen`,url:`https://tow.whfb.app/special-rules/gaze-of-the-gods`},
  "mark-of-chaos-undivided": {name:`Mark of Chaos Undivided`,desc:`Models with the Mark of Chaos Undivided can re-roll any failed Fear, Panic or Terror test.`,army:`warriors-chaos`,url:`https://tow.whfb.app/special-rules/mark-of-chaos-undivided`},
  "chaos-armour-warriors-of-chaos": {name:`Chaos Armour (Warriors of Chaos)`,desc:`A model with this special rule has a Ward save against any wounds suffered. The armour value of this Ward save is shown in brackets after the name of this special rule (X+). In addition, a Wizard with this special rule may wear armour without penalty.`,army:`warriors-chaos`,url:`https://tow.whfb.app/special-rules/chaos-armour-warriors-of-chaos`},
  "cold-blooded": {name:`Cold Blooded`,desc:`When required to make a Fear, Panic or Terror test, models with this special rule may roll an extra D6 and discard the highest result.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/cold-blooded`},
  "impervious-defence": {name:`Impervious Defence`,desc:`Enemy units cannot claim any bonus combat result points for being engaged with this model's flank or rear arc.`,army:`lizardmen`,url:`https://tow.whfb.app/special-rules/impervious-defence`},
  "valour-of-ages": {name:`Valour of Ages`,desc:`A unit with this special rule may re-roll any failed Panic test caused by taking heavy casualties or by being fled through by a friendly unit.`,army:`high-elves`,url:`https://tow.whfb.app/special-rules/valour-of-ages`},
  "blessings-of-the-lady": {name:`Blessings of the Lady`,desc:`Once deployment is complete, the Bretonnia army may kneel and pray, giving the opponent first turn. If granted, all models with this rule gain: a 6+ Ward save against any wounds, and a 5+ Ward save against wounds caused by Strength 5+. This rule is lost if the model/unit flees or a character refuses a challenge. Cannot be used in mirror matches.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/blessings-of-the-lady`},
  "the-knights-vow": {name:`The Knight's Vow`,desc:`A model with this Chivalrous Vow does not have to make a Panic test when a friendly unit with the Peasantry special rule is destroyed within 6" or flees through it. A unit with this vow cannot be joined by a character with the Peasantry special rule, and vice versa.`,army:`bretonnia`,url:`https://tow.whfb.app/special-rules/the-knights-vow`},
  "battle-magic": {name:`Battle Magic`,desc:`A lore of magic widely practised across the Old World, tailored for the battlefield. Practitioners draw from multiple Winds of Magic. Spells include: Hammerhand (Signature, Assailment, 7+, Combat, 2D3 S4 AP-2 hits), Fireball (Magic Missile, 8+, 24", 2D6 S4 Flaming hits), Curse of Arrow Attraction (Hex, 7+, 21", re-roll To Hit 1s vs target), Pillar of Fire (Vortex, 9+), Arcane U`,army:`universal`,url:`https://tow.whfb.app/the-lores-of-magic/battle-magic`},
  "high-magic": {name:`High Magic`,desc:`The most refined lore, drawing all eight Winds together. Spells include: Drain Magic (Signature Hex, 9+, Remains in Play, enemy Wizards within 24" must increase casting values by 2), Walk Between Worlds (Conveyance, 10+, Ethereal+Reserve Move), Fiery Convocation (Magic Missile, 10+, 18", large blast Flaming hits), Tempest (Vortex, 9+), Corporeal Unmaking (Assailment, 8+), Fury `,army:`high-elves`,url:`https://tow.whfb.app/the-lores-of-magic/high-magic`},
  "strength-in-numbers": {name:`Scurrying Masses`,desc:`Although not brave by nature, Skaven find courage and discipline in large numbers. Whilst within 3" of a friendly unit, this model gains a positive (+) modifier to its Leadership characteristic equal to that unit's current Rank Bonus, up to a maximum of Leadership 10.`,army:`skaven`,url:`https://tow.whfb.app/special-rules/scurrying-masses`},
  "warpstone-weapons": {name:`Warpstone Weapons`,desc:`A hand weapon carried by a model with this special rule has the Magical Attacks special rule and an Armour Piercing characteristic of -1. This only applies to a single, ordinary hand weapon. If the model is using two hand weapons or any other sort of weapon, this special rule ceases to apply.`,army:`skaven`,url:`https://tow.whfb.app/special-rules/warpstone-weapons`},
  "swarm": {name:`Swarms`,desc:`Swarms are seething masses of small creatures (rats, snakes, insects) summoned or herded to the battlefield. Each base counts as a single model. Troop type: Swarms. Unit Strength per Model: 3. Special rules: Insignificant, No One Cares, Undisciplined. No models per rank or maximum rank bonus.`,army:`universal`,url:`https://tow.whfb.app/troop-types-in-detail/swarms`},
  "mixed-unit": {name:`Mixed Unit`,desc:`Models within a Primal Warherd have different Weapon Skill and Toughness characteristics. Before rolling To Wound, hits from enemy shooting are divided as evenly as possible between Gors and Ungors. In combat, enemy models must direct their attacks against models in the fighting rank of this unit.`,army:`universal`,url:`https://tow.whfb.app/special-rules/mixed-unit`},
  "largely-insignificant": {name:`Largely Insignificant`,desc:`Units with this special rule never cause friendly units to make Panic tests. However, a unit with this special rule cannot be joined by a character without this special rule.`,army:`universal`,url:`https://tow.whfb.app/special-rules/largely-insignificant`},
  "skirmish-formation": {name:`Skirmish Formation`,desc:`A unit in Skirmish formation never consists of rigid ranks and files. Instead, it moves as a single loose group or rough line. Models are deployed on the battlefield in a single loose but contiguous group, where every model is within 1" of another model belonging to the same unit. This enables Skirmishers to move quickly and take advantage of terrain to shelter from the enemy.`,army:`universal`,url:`https://tow.whfb.app/unusual-formations/skirmish-formation`},
  "open-order-formation": {name:`Open Order Formation`,desc:`A unit in Open Order formation closely resembles one in Close Order. Models are arranged in base contact edge-to-edge and front corner to front corner, in ranks and files, all facing the same direction. The key differences lie in how the unit moves and interacts with terrain. Allows highly manoeuvrable movement and, in Combat Order, can claim a Rank Bonus.`,army:`universal`,url:`https://tow.whfb.app/unusual-formations/open-order-formation`},
  // ── Équipements ─────────────────────────────────────────────────────────
  "arme-de-base":{name:`Arme de base`,desc:`Arme à une main portée par défaut. Utilisable avec un bouclier.`,army:`universal`},
  "arme-lourde":{name:`Arme lourde`,desc:`+2 Force au CàC. Frappe toujours en dernier. Incompatible avec bouclier.`,army:`universal`},
  "arme-a-deux-mains":{name:`Arme à deux mains`,desc:`+2 Force au CàC. Frappe toujours en dernier.`,army:`universal`},
  "hallebarde":{name:`Hallebarde`,desc:`+1 Force au CàC et Armour Bane (1). Frappe avant les armes à 2 mains.`,army:`universal`},
  "lance":{name:`Lance`,desc:`+2 Force lors d'une charge uniquement.`,army:`universal`},
  "lance-de-cavalerie":{name:`Lance de cavalerie`,desc:`+2 Force lors d'une charge (cavalerie seulement).`,army:`universal`},
  "arbalete":{name:`Arbalète`,desc:`Portée 30'', Force 4, Perforant (1). Mouvement OU Tir.`,army:`universal`},
  "arc":{name:`Arc`,desc:`Portée 24'', Force 3. Peut tirer en se déplaçant (demi-portée).`,army:`universal`},
  "arc-court":{name:`Arc court`,desc:`Portée 18'', Force 3. Peut tirer en se déplaçant.`,army:`universal`},
  "arc-long":{name:`Arc long`,desc:`Portée 30'', Force 3. Peut tirer en se déplaçant (demi-portée).`,army:`universal`},
  "pistolet":{name:`Pistolet`,desc:`Portée 8'', Force 4, Ignorer Armure. CàC : +1 Attaque F4 Ignorer Armure (1er tour).`,army:`universal`},
  "pistolets":{name:`Pistolets (paire)`,desc:`2 tirs portée 8'', F4, Ignorer Armure. CàC : +1 Attaque F4 Ignorer Armure.`,army:`universal`},
  "armes-additionnelles":{name:`Armes additionnelles`,desc:`+1 Attaque en CàC (deux armes simultanées).`,army:`universal`},
  "arme-de-tir":{name:`Arme de tir`,desc:`Arme à distance (portée et Force selon la fiche).`,army:`universal`},
  "armure-legere":{name:`Armure légère`,desc:`Sauvegarde 6+. Avec bouclier : 5+ en CàC.`,army:`universal`},
  "armure-lourde":{name:`Armure lourde`,desc:`Sauvegarde 5+. Avec bouclier : 4+ en CàC.`,army:`universal`},
  "armure-de-plate-complete":{name:`Armure de plate complète`,desc:`Sauvegarde 4+. Avec bouclier : 3+ en CàC.`,army:`universal`},
  "armure-runique":{name:`Armure runique`,desc:`Sauvegarde 4+. Peut recevoir des Runes naines.`,army:`dwarfen-mountain-holds`},
  "carapace":{name:`Carapace`,desc:`Protection naturelle. Sauvegarde 5+.`,army:`universal`},
  "bouclier":{name:`Bouclier`,desc:`+1 Sv en CàC. Parade : Sv+ 6+ en CàC.`,army:`universal`},
  "bouclier-runique":{name:`Bouclier runique`,desc:`+1 Sv en CàC. Parade 6+. Peut recevoir des Runes.`,army:`dwarfen-mountain-holds`},
  "arme-magique":{name:`Arme magique`,desc:`Arme enchantée (effets selon l'objet choisi). Compte comme magique.`,army:`universal`},
  "armure-magique":{name:`Armure magique`,desc:`Protection enchantée (effets selon l'objet choisi).`,army:`universal`},
  "objet-enchante":{name:`Objet enchanté`,desc:`Objet magique divers : talisman, parchemin, pierre runique, etc.`,army:`universal`},
  "marque-de-khorne":{name:`Marque de Khorne`,desc:`+1 Attaque. L'unité gagne Frénésie (doit charger si possible).`,army:`warriors-of-chaos`},
  "marque-de-nurgle":{name:`Marque de Nurgle`,desc:`+1 Endurance. L'unité gagne la règle Pestiféré.`,army:`warriors-of-chaos`},
  "marque-de-slaanesh":{name:`Marque de Slaanesh`,desc:`+1 Initiative. Immunisé à la Peur et à la Terreur.`,army:`warriors-of-chaos`},
  "marque-de-tzeentch":{name:`Marque de Tzeentch`,desc:`Sauvegarde Invulnérable 6+. Accès aux sorts de Tzeentch.`,army:`warriors-of-chaos`},
  "don-de-khorne":{name:`Don de Khorne`,desc:`+1 Attaque ou capacité spéciale de Khorne.`,army:`warriors-of-chaos`},
  "don-de-nurgle":{name:`Don de Nurgle`,desc:`+1 Endurance ou capacité spéciale de Nurgle.`,army:`warriors-of-chaos`},
  "don-de-slaanesh":{name:`Don de Slaanesh`,desc:`+1 Initiative ou capacité spéciale de Slaanesh.`,army:`warriors-of-chaos`},
  "don-de-tzeentch":{name:`Don de Tzeentch`,desc:`Sort supplémentaire ou capacité de Tzeentch.`,army:`warriors-of-chaos`},
  "rune-de-combat":{name:`Rune de combat`,desc:`Rune gravée sur l'arme. Effets : Puissance (+1F), Feu, Tranchant, etc.`,army:`dwarfen-mountain-holds`},
  "rune-de-protection":{name:`Rune de protection`,desc:`Rune défensive : Préservation (+1Sv), Résistance (Sv+ 5+), etc.`,army:`dwarfen-mountain-holds`},
  "benediction-de-sigmar":{name:`Bénédiction de Sigmar`,desc:`Prière divine. Effets selon la prière choisie dans le livre d'armée.`,army:`empire-of-man`},
  "priere-de-la-dame":{name:`Prière de la Dame`,desc:`Sauvegarde Invulnérable 6+ pour l'unité. Peut relancer un test de Panique.`,army:`kingdom-of-bretonnia`},
  "benediction-de-la-dame":{name:`Bénédiction de la Dame`,desc:`Sauvegarde Invulnérable 6+ (foi en la Dame du Lac).`,army:`kingdom-of-bretonnia`},
  "sorcier-niveau-1":{name:`Sorcier Niveau 1`,desc:`1 Dé de Pouvoir. Connaît 1 sort. Lance 1 sort/phase de Magie.`,army:`universal`},
  "sorcier-niveau-2":{name:`Sorcier Niveau 2`,desc:`1 Dé de Pouvoir. Connaît 2 sorts. Lance 2 sorts/phase de Magie.`,army:`universal`},
  "sorcier-niveau-3":{name:`Sorcier Niveau 3`,desc:`2 Dés de Pouvoir. Connaît 3 sorts. Lance 3 sorts/phase de Magie.`,army:`universal`},
  "sorcier-niveau-4":{name:`Sorcier Niveau 4`,desc:`2 Dés de Pouvoir. Connaît 4 sorts. Accès à tout le domaine.`,army:`universal`},

  "hand-weapon": {name:`Arme de base`,desc:`Arme de corps à corps standard. Si le combattant n'est pas équipé d'une autre arme de corps à corps, il utilise son Arme de base. Une figurine possédant une Arme de base additionnelle gagne +1 Attaque mais subit une pénalité de -1 à sa Sauvegarde d'Armure.`},
  "additional-hand-weapon": {name:`Arme de base additionnelle`,desc:`+1 Attaque supplémentaire en phase de combat. La figurine subit une pénalité de -1 à sa Sauvegarde d'Armure.`},
  "great-weapon": {name:`Arme lourde`,desc:`+2 Force et règle Armure Brisée (6+). La figurine frappe toujours en dernier (Initiative 1) lors de la phase de combat, sauf si l'ennemi est lui-même équipé d'une Arme lourde.`},
  "halberd": {name:`Hallebarde`,desc:`+1 Force et règle Armure Brisée (6+). La figurine frappe toujours en dernier (Initiative 1) lors de la phase de combat.`},
  "lance": {name:`Lance de joute`,desc:`+2 Force lors du premier tour de corps à corps si la figurine a chargé ce tour-là. Peut être utilisée depuis le dos d'une monture appropriée.`},
  "spear": {name:`Lance / Pique`,desc:`La première rangée de figurines peut attaquer même si l'unité n'a pas chargé. Une unité équipée de lances peut compter une rangée supplémentaire lors du calcul du bonus de rang.`},
  "shield": {name:`Bouclier`,desc:`+1 à la Sauvegarde d'Armure en corps à corps. Si la figurine combat un ennemi qui la charge de front, elle gagne un +1 supplémentaire à sa Sauvegarde d'Armure (total +2).`},
  "light-armour": {name:`Armure légère`,desc:`Sauvegarde d'Armure de 6+.`},
  "heavy-armour": {name:`Armure lourde`,desc:`Sauvegarde d'Armure de 5+.`},
  "full-plate-armour": {name:`Armure de plate complète`,desc:`Sauvegarde d'Armure de 4+.`},
  "barding": {name:`Caparaçon`,desc:`La monture gagne +1 à sa Sauvegarde d'Armure. En contrepartie, la valeur de Mouvement de la monture est réduite de 1.`},
  "crossbow": {name:`Arbalète`,desc:`Portée 30 ps, Force 4, Perforant (4+). Si la figurine a bougé ce tour-là, elle subit une pénalité de -1 pour toucher.`},
  "longbow": {name:`Arc long`,desc:`Portée 30 ps, Force 3. Peut tirer même si l'unité a bougé ce tour-là (avec pénalité de -1 pour toucher).`},
  "handgun": {name:`Arquebuse`,desc:`Portée 24 ps, Force 4, Perforant (4+). Ne peut pas tirer si la figurine a bougé ce tour-là. Ignore les couverts légers.`},
  "pistol": {name:`Pistolet`,desc:`Portée 8 ps, Force 4, Perforant (4+). En corps à corps, un pistolet confère +1 Attaque supplémentaire à Initiative.`},
  "brace-of-pistols": {name:`Paire de pistolets`,desc:`Portée 8 ps, Force 4, Perforant (4+). En corps à corps, la paire de pistolets confère +2 Attaques supplémentaires à Initiative.`},
  "flail": {name:`Fléau`,desc:`+2 Force lors du premier tour de corps à corps (y compris le tour où la charge est réalisée). Frappe toujours en dernier (Initiative 1) lors des tours suivants.`},
  "morning-star": {name:`Masse d'armes à pointes`,desc:`+1 Force. Frappe en dernier (Initiative 1). Ignore les bonus de sauvegarde liés aux boucliers.`},
  "great-axe": {name:`Grande hache`,desc:`+2 Force, Armure Brisée (6+). Frappe en dernier (Initiative 1).`},
  "pike": {name:`Pique`,desc:`La première et la deuxième rangée peuvent attaquer. Une unité équipée de piques peut compter jusqu'à 2 rangées supplémentaires pour le bonus de rang. Frappe toujours en dernier (Initiative 1) sauf si l'ennemi charge.`},
  "bow": {name:`Arc`,desc:`Portée 24 ps, Force 3.`},
  "repeater-crossbow": {name:`Arbalète répétitrice`,desc:`Portée 24 ps, Force 3. Peut effectuer 2 tirs par tour (avec -1 pour toucher sur le second tir).`},
  "throwing-weapons": {name:`Armes de jet`,desc:`Portée 8 ps, Force utilisateur. Peuvent être utilisées en mouvement.`},
  "javelin": {name:`Javelot`,desc:`Portée 8 ps, Force utilisateur. Lance comme une arme de trait avant le combat.`},
  "stomp": {name:`Piétinement`,desc:`À la fin de chaque phase de corps à corps, la figurine inflige D3 touches automatiques de Force 3 à une unité ennemie en contact socle à socle (sauf Monstres ou Machines de Guerre).`},
  "thunder-stomp": {name:`Piétinement Dévastateur`,desc:`À la fin de chaque phase de corps à corps, la figurine inflige D6 touches automatiques de Force 3 à une unité ennemie en contact socle à socle (sauf Monstres ou Machines de Guerre).`},
  "battle-line": {name:`Formation de Bataille`,desc:`L'unité peut compter ses rangs complets de la même façon qu'une infanterie en rangs serrés. Elle ne souffre pas des pénalités habituelles pour formation ouverte.`},
  "magical-attacks": {name:`Attaques Magiques`,desc:`Les attaques de la figurine comptent comme magiques. Elles peuvent blesser des adversaires Éthérés et ignorent certaines règles de protection comme Régénération contre les attaques non-magiques.`},
  "swiftstride": {name:`Allure Rapide`,desc:`Lors d'une charge, d'une poursuite ou d'une retraite, la figurine lance 3D6 et conserve les 2 meilleurs résultats pour calculer la distance.`},
  "impact-hits": {name:`Impacts de Charge`,desc:`Lors d'un tour où la figurine charge, elle inflige D6 touches automatiques de sa Force avant le début normal de la phase de corps à corps.`},
  "armour-bane": {name:`Armure Brisée`,desc:`Les attaques avec cette règle ignorent une partie de la Sauvegarde d'Armure de la cible. La valeur entre parenthèses indique le minimum requis sur le dé de sauvegarde pour que l'armure soit ignorée.`},
  "breath-weapon": {name:`Arme Soufflante`,desc:`Une fois par partie, au lieu d'attaquer normalement, la figurine projette son arme soufflante via un gabarit de souffle. Chaque figurine partiellement couverte subit une touche automatique avec les caractéristiques indiquées dans le profil.`},
  "ward-save": {name:`Sauvegarde Invulnérable`,desc:`La figurine dispose d'une Sauvegarde Invulnérable (valeur indiquée). Cette sauvegarde peut être tentée même si la Sauvegarde d'Armure a échoué. Elle ne peut pas être améliorée au-delà de 4+.`},

  /* ── Domaines de magie ── */
  "elementalism":{"name":"Élémentalisme","desc":"Domaine de magie universelle axé sur les forces naturelles. Sorts qui manipulent feu, eau, terre, air et foudre.","army":"universal"},
  "illusion":{"name":"Illusion","desc":"Domaine de magie des Hauts Elfes. Sorts qui trompent l'esprit, créent des mirages et aveuglent les ennemis.","army":"high-elf-realms"},
  "dark-magic":{"name":"Magie Noire","desc":"Magie des Elfes Noirs alimentée par l'énergie corrompue du vortex. Sorts offensifs puissants mais dangereux pour le lanceur.","army":"dark-elves"},
  "daemonology":{"name":"Démonologie","desc":"Domaine de magie qui invoque et manipule les forces daemoniques. Sorts offensifs et d'invocation, risques élevés.","army":"universal"},
  "necromancy":{"name":"Nécromancie","desc":"Magie des morts-vivants. Invoque des squelettes, ranime des cadavres et draine la vie des ennemis.","army":"universal"},
  "lore-of-daemons":{"name":"Lore des Daémons","desc":"Magie des Démons du Chaos. Sorts chaotiques qui reflètent la corruption et la puissance des dieux du Chaos.","army":"daemons-of-chaos"},
  "lore-of-undeath":{"name":"Lore des Morts-Vivants","desc":"Magie nécromantique avancée permettant d'invoquer de puissants morts-vivants et de drainer la vie.","army":"vampire-counts"},
  "waaagh-magic":{"name":"Magie Waaagh!","desc":"Magie des Orques et Gobelins, alimentée par l'énergie brute des combattants verts. Imprévisible mais puissante.","army":"orc-and-goblin-tribes"},
  "lore-of-saphery":{"name":"Lore de Saphery","desc":"Domaine de magie des Hauts Elfes, héritage de la cité de Saphery. Sorts défensifs et de soutien.","army":"high-elf-realms"},
  "lore-of-beasts":{"name":"Lore des Bêtes","desc":"Magie qui invoque et transforme des créatures sauvages. Sorts de métamorphose et d'invocation animale.","army":"universal"},
  "lore-of-chaos":{"name":"Lore du Chaos","desc":"Magie de mutation et de corruption. Sorts qui transforment les ennemis et invoquent les puissances du Chaos.","army":"universal"},
  "lore-of-the-lady":{"name":"Lore de la Dame","desc":"Magie de Bretonnie, accordée par la Dame du Lac. Sorts de protection, purification et guérison.","army":"kingdom-of-bretonnia"},
  "lore-of-athel-loren":{"name":"Lore d'Athel Loren","desc":"Magie des Elfes des Bois issue de la forêt sacrée. Sorts de croissance, de nature et de soin.","army":"wood-elf-realms"},
  "lore-of-chaos-undivided":{"name":"Lore du Chaos Individu","desc":"Magie des Guerriers du Chaos non alignés. Sorts de destruction pure et de corruption.","army":"warriors-of-chaos"},
  "lore-of-mork":{"name":"Lore de Mork","desc":"Magie des Gobelins et orques cunning. Sorts de tromperie, pièges et attaques sournoises.","army":"orc-and-goblin-tribes"},
  "lore-of-gork":{"name":"Lore de Gork","desc":"Magie des Orques forts. Sorts de combat brutal, d'augmentation de Force et de destruction directe.","army":"orc-and-goblin-tribes"},
  "lore-of-nehekhara":{"name":"Incantations de Nehekhara","desc":"Magie des Rois des Tombes. Invoque des squelettes, anime des construits et maudit les ennemis.","army":"tomb-kings-of-khemri"},
  "lore-of-the-horned-rat":{"name":"Lore du Rat Cornu","desc":"Magie Skaven canalisée depuis leur dieu. Sorts de pestilence, corruption et manipulation warp.","army":"skaven"},
  "lore-of-hashut":{"name":"Lore de Hashut","desc":"Magie des Nains du Chaos dédiée au Père des Ténèbres. Sorts de feu, forge et pétrification.","army":"chaos-dwarfs"},
  "lore-of-lustria":{"name":"Lore de Lustria","desc":"Magie ancienne des Hommes-Lézards héritée des Slann. Sorts de contrôle du destin et puissance cosmique.","army":"lizardmen"},
  "lore-of-the-great-maw":{"name":"Lore du Grand Mâchoire","desc":"Magie des Ogres centrée sur la faim dévorante. Sorts d'engloutissement, d'augmentation et de destruction.","army":"ogre-kingdoms"},
  "lore-of-the-great-winds":{"name":"Lore des Grands Vents","desc":"Magie de Grand Cathay manipulant les vents magiques. Sorts de tempête, foudre et contrôle des éléments.","army":"grand-cathay"},
  "lore-of-the-shadowlands":{"name":"Lore des Terres des Ombres","desc":"Magie des Elfes Noirs issue des Terres des Ombres. Sorts d'obscurité et d'ombre.","army":"dark-elves"},
  "lore-of-naggaroth":{"name":"Lore de Naggaroth","desc":"Magie des Elfes Noirs spécifique à leur continent. Sorts de froid extrême et de malédictions.","army":"dark-elves"},

  /* ── Règles universelles manquantes ── */
  "indomitable":{"name":"Indomptable","desc":"L'unité est immunisée à la Peur et à la Terreur.","army":"universal",desc:`Within the ranks of undead march creatures with an indomitable will to hang on to the last vestiges of life no matter what.

A unit with this special rule reduces the number of wounds suffered due to the Unstable special rule by the number shown in brackets (shown here as 'X'). Note that this special rule is not cumulative — if two or more models in a unit have this special rule, use the highest value for the entire unit.`},
  "aquatic":{"name":"Aquatique","desc":"L'unité peut se déplacer normalement à travers les terrains aquatiques sans malus. Traite l'eau comme un terrain découvert.","army":"universal"},
  "lance-formation":{"name":"Formation en Lance","desc":"Quand cette unité charge, tous les combattants de la première rangée peuvent attaquer, pas uniquement le premier rang.","army":"universal"},
  "run-with-the-pack":{"name":"Courir avec la Meute","desc":"L'unité peut se déplacer et agir en coordination avec les créatures loups adjacentes ou leur unité de rattachement.","army":"universal",desc:`Having long hunted with their packs, Elven Beast Keepers keep pace with their charges whilst instilling them with discipline.

Whilst one or more Beast Keeper remains within this unit, the unit is not subject to the Undisciplined rule and war beasts within this unit do not fear models with the Flaming Attacks special rule. In addition, a unit with this special rule may use the Movement characteristic of the majority of the models in the unit.`},
  "tree-spirit":{"name":"Esprit des Bois","desc":"Créature magique liée à la forêt. Traite comme Éthéré pour certains effets et bénéficie de protections liées à Athel Loren.","army":"wood-elf-realms"},
  "wailing-dirge":{"name":"Lamentation Funèbre","desc":"La présence de l'unité inflige la Terreur et peut pousser les ennemis à tester leur Commandement en début de tour.","army":"universal",desc:`The chilling howl of a restless spirit is an omen of death and despair, capable of crippling even the most resilient prey.

During the Shooting phase of its turn (unless it marched), this model may make a Wailing Dirge attack targeting any enemy unit within 8" it can draw line of sight to. The target must make a Leadership test with a -2 modifier. If failed, the target suffers wounds equal to the amount by which it failed the test, with no armour or Regeneration saves (Ward saves allowed).`},
  "blood-greed":{"name":"Soif de Sang","desc":"Après avoir tué un ennemi en combat, l'unité peut récupérer des Points de Vie. Lance un D6 pour chaque ennemi tué — sur 4+, récupère 1 PV.","army":"vampire-counts",desc:`At times, the blood-fuelled frenzy of the Beastmen is so great that they fall upon their foes in a butcherous rage, feeding upon the flesh of the fallen in the heat of battle.

Whilst Frenzied, this model has a +2 modifier to its Attacks characteristic (rather than the usual +1). However, such is this model's desperate need to feed upon flesh that it rolls only a single D6 when making a Pursuit roll (rather than the usual 2D6).`},

  /* ── Règles Hauts Elfes ── */
  "ithilmar-weapons":{"name":"Armes en Ithilmar","desc":"Armes forgées en ithilmar, métal léger et tranchant propre aux Hauts Elfes. Confèrent le Frappe en Premier.","army":"high-elf-realms",desc:`Weapons crafted of Ithilmar are incredibly lightweight and balanced to perfection. Such blades slice swiftly through the clumsy parries and counter-thrusts of enemies.

When engaged in combat, a model with this special rule that is fighting with a hand weapon may re-roll any rolls To Hit of a natural 1. Note that this special rule only applies to a single, non-magical hand weapon and does not apply to a model's mount. If the model is using two hand weapons or any other sort of weapon, this special rule ceases to apply.`},
  "lion-cloak":{"name":"Cape de Lion","desc":"Cape en peau de lion de Chrace. Confère une sauvegarde invulnérable de 6+ ou améliore la sauvegarde existante.","army":"high-elf-realms",desc:`The thick pelt of a Chracian White Lion offers exemplary protection against arrows and shot, though to wear such a trophy a warrior must have earned the right.

A model with this special rule improves its armour value by 1 (to a maximum of 2+) against non-magical shooting attacks.`},
  "blessings-of-asuryan":{"name":"Bénédictions d'Asuryan","desc":"Protection divine du dieu suprême des Hauts Elfes. Unité immunisée aux règles de Peur et aux effets de sort de contrôle de l'esprit.","army":"high-elf-realms",desc:`The most devoted servants of Asuryan seem to blaze with a fiery intensity borne of unshakeable faith. In battle, such faith is rewarded by the Creator God of the Elves.

A model with this special rule has a 5+ Ward save against any wounds suffered that were caused by an attack that has the Flaming Attacks special rule.`},
  "lileaths-blessing":{"name":"Bénédiction de Lileath","desc":"Faveur de la déesse Lileath, accordant un bonus sur les jets de sauvegarde contre la magie ou une immunité partielle.","army":"high-elf-realms",desc:`Lileath is the patron of seers and prophets, and many are her gifts to the Elves of Ulthuan. Those students of High Magic that earn her blessing become possessed of a profound understanding and ability to control the Winds of Magic.

Once per turn, a model with this special rule may re-roll a single failed Casting roll.`},

  /* ── Règles Elfes Noirs ── */
  "blackshard-armour":{"name":"Armure d'Éclat Noir","desc":"Armure des Elfes Noirs forgée en métal sombre. Compte comme Armure Lourde et confère une résistance supplémentaire.","army":"dark-elves",desc:`Glowing eternally with the flame of its forging, Blackshard armour protects its wearer from fire and heat.

A model with this special rule has a 5+ Ward save against any wounds suffered that were caused by an attack that has the Flaming Attacks special rule. In addition, a Wizard with this special rule may wear armour without penalty.`},
  "dark-vitality":{"name":"Vitalité des Ténèbres","desc":"Régénération partielle liée à la magie noire des Elfes Noirs. L'unité peut ignorer certaines blessures sur un jet de dé.","army":"dark-elves",desc:`Vampires and Necromancers are powerful beings able to exist without the animating will of another.

Models with this special rule are not subject to the Death of a General rule. In addition, unless they have joined a unit that does not have this special rule, they (and their mounts) can march as normal.`},
  "obsidian-blades":{"name":"Lames d'Obsidienne","desc":"Armes des Elfes Noirs taillées en obsidienne volcanique. Confèrent Perforant (2) ou un effet similaire de pénétration d'armure.","army":"dark-elves"},
  "fear-of-elves":{"name":"Peur des Elfes","desc":"Cette unité provoque la Peur chez les Orques et Gobelins. Les unités orques et gobelines doivent tester leur Commandement.","army":"dark-elves",desc:`Goblins don't like Elves. They smell of soap, they walk funny and they're too tall.

Elves of any type cause Fear in models with this special rule.`},

  /* ── Règles Skaven ── */
  "scurry-away":{"name":"Décampade Rapide","desc":"Si l'unité rate un test de Moral, elle peut tenter une fuite en désordre supplémentaire (D6 pouces) pour tenter d'échapper à la poursuite.","army":"skaven",desc:`Wherever possible, Skaven prefer to run from danger rather than face it head-on.

Models with this special rule have a +1 modifier to the result of any Flee roll they make.`},
  "verminous-valour":{"name":"Valeur des Nuisibles","desc":"Quand un chef Skaven se bat à proximité, les unités Skaven relancent les jets de Panique ratés sur un résultat de 1.","army":"skaven",desc:`Notorious cowards, Skaven leaders often prefer to lead from the back.

Unless they are engaged in a challenge, a character with this special rule that has joined a unit with a Unit Strength of 10 or more may voluntarily 'retire' to the rear of the unit at any time. Should they do so, they are no longer within the fighting rank and cannot make any attacks or have attacks directed against them. However, the unit may still use this character's Leadership.`},
  "backstab":{"name":"Coup dans le Dos","desc":"Combat dans les flancs ou l'arrière : +1 en CC et +1 en Initiative pendant la première phase de combat.","army":"skaven",desc:`Hobgoblins are treacherous and underhanded creatures that excel at stabbing their enemies (and often their friends) in the back.

If a unit with this special rule is engaged with an enemy unit's flank or rear arc, it may re-roll any failed rolls To Hit made against that enemy unit.`},

  /* ── Règles Ogres ── */
  "ogre-charge":{"name":"Charge Ogre","desc":"Lors d'une charge, l'unité inflige des Touches d'Impact égales au nombre de figurines en contact socle à socle.","army":"ogre-kingdoms",desc:`Ogres barge into combat using their great lumbering mass as a weapon, harnessing their tremendous momentum to crush anything they collide with.

The Armour Piercing characteristic of any Impact Hits caused by a model with this special rule (but not its mount) is improved by the current Rank Bonus of its unit (or, in the case of characters, the current Rank Bonus of any unit they have joined).`},
  "tusker-charge":{"name":"Charge des Défenses","desc":"L'unité et ses montures à défenses infligent des Touches d'Impact Force 5 lors de toute charge.","army":"ogre-kingdoms",desc:`A charging War Boar is an ill-tempered mound of bloody-minded muscle with savage tusks and a terrible attitude.

During a turn in which it charged, a War Boar's Tusks (hand weapon) have a Strength characteristic of S+1 and an Armour Piercing characteristic of -1.

Note: this special rule only applies to attacks made by a War Boar, not to their rider, a chariot or its crew.`},
  "foe-render":{"name":"Déchiqueteur","desc":"Attaques qui blessent automatiquement sur un 2+ ou qui ignorent les sauvegardes d'armure normales.","army":"ogre-kingdoms",desc:`The crude weapons of Beastmen are empowered by their bearer's primal hatred for the trappings of civilisation.

Whilst subject to Primal Fury, a hand weapon carried by a model with this special rule has an Armour Piercing characteristic of -2. Note that this special rule only applies to a single, non-magical hand weapon and does not apply to a model's mount. If the model is using two hand weapons or any other sort of weapon, this special rule ceases to apply.`},

  /* ── Règles Empire ── */
  "detachment-special-rules":{"name":"Règles de Détachement","desc":"Les détachements de l'Empire bénéficient de contre-charges gratuites et peuvent effectuer des manœuvres de flanc offensives.","army":"empire-of-man"},
  "nuln-state-troops":{"name":"Troupes de Nuln","desc":"Troupes d'élite de la cité de Nuln, maîtres des armes à feu. Bénéficient d'une Formation En Rang et de règles spéciales de fusiliers.","army":"empire-of-man"},
  "naval-discipline":{"name":"Discipline Navale","desc":"Discipline de Marine. L'unité est immunisée à la Panique tant qu'un officier est présent.","army":"empire-of-man",desc:`The citizens of Lothern are justifiably proud of the discipline of the Sea Guard regiments. These skilled warriors drill for many hours, perfecting the art of firing a volley of shots even as they redress their ranks to receive the enemy's charge.

A unit of Lothern Sea Guard may use this special rule when it makes a Stand & Shoot charge reaction — it can make a Stand & Shoot charge reaction regardless of how close the charging unit is. Once resolved, the charged unit may make a free redress the ranks manoeuvre, after which it will Hold. Units that are fleeing, already engaged in combat, or have been joined by a character without this special rule cannot use it.`},

  /* ── Règles Bretonnie ── */
  "peasantry":{"name":"Paysannerie","desc":"Soldats paysans de Bretonnie. Ne peuvent pas utiliser le Commandement d'un Personnage sauf si c'est un Yeoman. Moral limité à 8.","army":"kingdom-of-bretonnia",desc:`The low-born peasants of Bretonnia habitually look to their knightly betters for leadership.

If a unit with this special rule is within 6" of a friendly model with the Knight's Vow, the Questing Vow or the Grail Vow (and if that model is not fleeing), this unit can use that model's Leadership instead of its own. In addition, a standard carried by a unit with this special rule cannot be counted as a trophy of war. A character with this special rule can only join a unit that also has this special rule.`},
  "aura-of-the-lady":{"name":"Aura de la Dame","desc":"La Bénédiction de la Dame protège l'unité. Confère une sauvegarde Ward de 5+ contre les attaques à distance magiques.","army":"kingdom-of-bretonnia",desc:`The Handmaidens of the Lady and their loyal companions are ever in the presence of their goddess, and a magical aura hangs like silvery light in the air about them.

Any unit this character has joined gains the Magical Attacks special rule.`},
  "shield-of-the-lady":{"name":"Bouclier de la Dame","desc":"Protection divine de la Dame du Lac. L'unité bénéficie d'une sauvegarde invulnérable de 4+ contre les touches magiques.","army":"kingdom-of-bretonnia",desc:`To march to war in the company of a Handmaiden of the Lady is a great privilege, and the Knights of Bretonnia consider it their sacred duty to protect these emissaries of their goddess from harm.

If this character has joined a unit that has a Unit Strength of 10 or more with a Chivalrous Vow, they may voluntarily 'retire' to the rear of the unit at any time. Should they do so, they are no longer within the fighting rank and cannot make any attacks or have attacks directed against them. However, they continue to confer benefits to the unit in the form of Leadership and special rules, and may cast spells as if they were within the fighting rank.`},
  "blessed-knight":{"name":"Chevalier Béni","desc":"Chevalier ayant accompli le Pèlerinage du Graal ou reçu la bénédiction de la Dame. Immunisé à la Peur et à la Terreur.","army":"kingdom-of-bretonnia"},

  /* ── Règles Rois des Tombes ── */
  "arrows-of-asaph":{"name":"Flèches d'Asaph","desc":"Flèches magiques bénies par la déesse Asaph. Ignorent les sauvegardes d'armure et blessent sur 3+.","army":"tomb-kings-of-khemri",desc:`These arrows carry the blessing of the goddess Asaph, and they seek out their enemies with unerring accuracy.

Units with this special rule never apply any modifiers to their rolls To Hit when shooting, regardless of the source of the modifier.`},
  "curse-of-the-necropolis":{"name":"Malédiction de la Nécropole","desc":"Malédiction ancienne frappant les ennemis qui détruisent des Rois des Tombes. Inflige D3 touches Force 5 à l'unité attaquante.","army":"tomb-kings-of-khemri",desc:`A powerful curse hangs over the rulers of Nehekhara. Those that would dare strike down these ancient lords find their blood turned to sand and their bodies engulfed in swarms of desert locusts.

If a model with this special rule loses its last Wound to an enemy attack, the unit that made the attack must immediately make a Leadership test. If this test is failed, the enemy unit suffers D3 Strength 2 hits, each with an AP of -.`},

  /* ── Règles Nains ── */
  "dwarf-crafted":{"name":"Artisanat Nain","desc":"Équipement fabriqué par des maîtres artisans nains. Relancez les jets de 1 pour toucher ou les jets de sauvegarde ratés de 1.","army":"dwarfen-mountain-holds",desc:`Dwarfs craft missile weapons with a skill and precision of both form and function that is not seen in the weapons of other races.

Models with this special rule do not suffer the usual -1 To Hit modifier when making a Stand & Shoot charge reaction.`},
  "ancestral-grudge":{"name":"Rancune Ancestrale","desc":"Les Nains ont une haine ancestrale de leurs ennemis traditionnels. Relancent les jets de toucher ratés lors du premier tour de combat.","army":"dwarfen-mountain-holds"},
  "hold-the-line":{"name":"Tenir la Ligne","desc":"Formation défensive naine. L'unité ne peut pas faire de manœuvre mais obtient +1 en Commandement et ne peut jamais être repoussée.","army":"dwarfen-mountain-holds"},
  "master-of-battle":{"name":"Maître du Combat","desc":"Général ou personnage d'exception. Étend le rayon d'influence du Commandement de +6 pouces supplémentaires.","army":"universal"},

  /* ── Règles Grand Cathay ── */
  "will-of-the-dragons":{"name":"Volonté des Dragons","desc":"L'unité peut relancer un jet de dé par phase lorsqu'elle est à portée du Dragon Père ou de la Dragon Mère.","army":"grand-cathay",desc:`For the people of Grand Cathay loyalty to their Dragon masters is paramount. They know, as long as they are true to their will, the Empire of Grand Cathay will never falter before her enemies.

A unit with this special rule may re-roll a failed Panic test when a friendly unit is destroyed whilst within 6" of it, or when it is fled through by a friendly unit.`},
  "harmony-of-stone-and-steel":{"name":"Harmonie de Pierre et d'Acier","desc":"Quand deux unités complémentaires de Cathay sont adjacentes, elles gagnent +1 en Sauvegarde d'Armure ou +1 en Commandement.","army":"grand-cathay"},

  /* ── Règles Elfes des Bois ── */
  "accomplished-archers":{"name":"Archers Accomplis","desc":"L'unité peut tirer à longue portée sans malus de -1 pour toucher et peut également tirer en mouvement.","army":"wood-elf-realms",desc:`Under the watchful eye of a veteran commander, regiments of Sea Guard train with their bows, perfecting the art of firing at the foe even as they evade attacks.

Unless mounted on a Lothern Skycutter, a Sea Guard Garrison Commander has the Evasive and Fire & Flee special rules. In addition, any unit of Lothern Sea Guard joined by this character gains the Evasive and Fire & Flee special rules for as long as the character remains with the unit.`},

  /* ── Règles Beastmen ── */
  "bull-gors":{"name":"Bull-Gors","desc":"Bêtes-Hommes à tête de taureau. Obtiennent +1 en Force lors d'une charge et +1 Attaque si en contact socle à socle avec 2+ ennemis.","army":"beastmen-brayherds",desc:`The very ground itself trembles and shakes beneath the unstoppable thunder of a Minotaur's charge.

Impact Hits caused by a model with this special rule have an Armour Piercing characteristic of -1.`},
  "drunken":{"name":"Ivre","desc":"L'unité est permanemment ivre. Lance un D6 au début de chaque phase de Mouvement. Sur 1-2, ne peut pas se déplacer ce tour.","army":"universal",desc:`Centigors are inclined to drink vast quantities of noxious liquor before battle. While this sometimes turns them into berserk fighters, it can also severely incapacitate them.

During the Start of Turn sub-phase of each of your turns, roll on the Drunken table for each unit with this special rule that is not currently Frenzied, that is not engaged in combat and that is not fleeing: 1=Unsteady (Random Movement D6+2 until next Start of Turn); 2-5=Sobering Up (no effect); 6=Belligerent Drunks (subject to Frenzy until next Start of Turn, may become Frenzied even if it previously lost Frenzy).`},
  "slashing-attack":{"name":"Attaque Tranchante","desc":"Attaques dotées d'une lame particulièrement acérée. Confèrent Perforant (1) ou une relance des jets de blessure ratés de 1.","army":"universal",desc:`Screamers' slashing blades tear through the foe as they dive close and pass quickly by.

A unit with this special rule may perform a 'Slashing Attack' against a single enemy unit that is not engaged in combat. To do so, this unit must move (by flying) over the unit it wishes to attack during the Remaining Moves sub-phase. Once this unit's movement is complete, the enemy unit suffers D3 Strength 4 hits, each with an AP of -, for each model in this unit that moved over it.`},

  /* ── Règles Nains du Chaos ── */
  "blazing-body":{"name":"Corps Enflammé","desc":"L'unité est enveloppée de flammes. Toutes ses attaques sont des Attaques Enflammées et infligent +1 point de blessure si non-sauvegardé.","army":"chaos-dwarfs",desc:`This creature's flesh burns with the intensity of a furnace, wreathing its form in clouds of black smoke and burning embers.

At the start of every Combat phase, any model (friend or foe) that is in base contact with this model and that does not also have this special rule suffers a single Strength 3 hit (AP -, Flaming Attacks).

Note: any Wounds lost due to these hits do not count towards the combat result.`},
  "stony-stare":{"name":"Regard de Pierre","desc":"Le regard de l'unité peut pétrifier les ennemis. Cibler une unité à 12 pouces : elle doit tester son Commandement ou subir des touches Force 3.","army":"chaos-dwarfs"},

  /* ── Règles Orques et Gobelins ── */
  "ignore-goblin-panic":{"name":"Ignorer la Panique Gobeline","desc":"Les unités d'Orques ignorent les tests de Panique causés par les Gobelins alliés qui fuient à travers ou près d'elles.","army":"orc-and-goblin-tribes"},

  /* ── Règles diverses ── */
  "arcane-vassal":{"name":"Vassal Arcanique","desc":"L'unité peut utiliser un personnage-magicien allié dans son unité pour lancer ou soutenir des sorts. Partage les niveaux de magie.","army":"universal"},
  "arcane-shield":{"name":"Bouclier Arcanique","desc":"Barrière magique protégeant l'unité. Confère une sauvegarde Ward de 5+ contre les sorts et les attaques magiques.","army":"universal",desc:`Pure magic shimmers about the Slann, shielding it from the blows of the enemy.

This character has a 5+ Ward save against any wounds suffered.`},
  "arcane-backlash":{"name":"Contre-Choc Arcanique","desc":"Lorsque l'unité dissipe un sort, elle peut infliquer D3 touches Force 3 à l'unité du lanceur du sort dissipé.","army":"universal"},
  "ithilmar-armour-ithilmar-barding":{"name":"Armure et Caparaçon en Ithilmar","desc":"Armure complète et caparaçon de la monture fabriqués en ithilmar. Compte comme Armure de Plate Complète et Caparaçon sans malus de Mouvement.","army":"high-elf-realms",desc:`Ithilmar is a wondrous and lightweight metal found only in Vaul's Anvil, the largest volcano in Ulthuan. A warrior wearing a gleaming suit of Ithilmar armour enjoys great protection and freedom of movement.

A model with this special rule may re-roll any rolls of 1 when making Dangerous Terrain tests. In addition, a Wizard with this special rule may wear armour without penalty.`},
  "celestial-forged-armour-x":{"name":"Armure Forgée Céleste","desc":"Armure de Grand Cathay forgée selon les secrets célestes. Confère une sauvegarde d'armure améliorée et peut réduire la Force des attaques ennemies.","army":"grand-cathay",desc:`Created in the armouries of Wei-jin, Celestial Forged Armour is made from the meteoric ore of Kunlan.

A model with this special rule has a Ward save against any wounds suffered. The armour value of this Ward save is shown in brackets after the name of this special rule. In addition, a Wizard with this special rule may wear armour without penalty.`},
  "razor-tusks":{"name":"Défenses Tranchantes","desc":"Défenses redoutablement acérées de la bête. Les attaques de morsure de la monture ont Perforant (2).","army":"universal",desc:`Tuskgors and Razorgors bristle with viciously sharp tusks and spines which, when charged into the enemy, can wreak utter devastation.

During a turn in which it charged, the Armour Piercing characteristic of this model's tusks (hand weapon) is improved by 1.

Note: this special rule only applies to attacks made by the model, not to a chariot or its crew (should it have one).`},
  "finest-warhorses":{"name":"Meilleurs Destriers de Guerre","desc":"Les meilleurs destriers de Bretonnie. Relancent les jets de 1 pour toucher lors d'une charge de Cavalerie.","army":"kingdom-of-bretonnia",desc:`The Warhorses of Bretonnia are bred to bear the weight of a fully armoured knight.

When a unit with this special rule makes a Charge, Flee or Pursuit roll, it may re-roll any dice that roll a natural 1, before discarding any dice that are required to be discarded.`},
  "oathstone":{name:`Oathstone`,desc:`Un personnage avec l'Oathstone ne peut pas se déplacer normalement, effectuer de marche forcée ou charger. En revanche, l'unité accompagnée du personnage ne peut jamais fuir comme réaction à une charge. Le personnage bénéficie de la règle Immovable Object.`,army:`dwarfen-mountain-holds`},
  "mastery-of-the-elemental-winds":{name:`Mastery of the Elemental Winds`,desc:`Le Longma est une créature forgée dans les vents élémentaires ancestraux de Grand Cathay. Le Shugengan qui le chevauche gagne un bonus de +1 à ses jets de lancement pour chaque domaine de magie de Grand Cathay qu'il maîtrise.`,army:`grand-cathay`},
  "celestial-forged-armour":{name:`Celestial Forged Armour (5+)`,desc:`Cette armure forgée dans la magie céleste accorde une sauvegarde d'armure de 5+. Cette sauvegarde ne peut être ignorée que par des armes magiques ou des attaques de Force 7 ou supérieure.`,army:`grand-cathay`},


  "chill-scales":{name:"Chill Scales (5+)",desc:`Les Sang-froids sont couverts d'écailles rigides et glissantes qui leur confèrent une sauvegarde d'armure naturelle de 5+. Cette protection ne se cumule pas avec d'autres formes d'armure portée mais s'applique en toutes circonstances.`,army:"dark-elves"},
"accursed-reliquary":{name:`Accursed Reliquary`,desc:`Powerful necromantic magic clings to the unhallowed remains enshrined within the heart of a Mortis Engine, energising nearby Undead.

Whilst within this model's Command range, friendly units with the Necromantic Undead special rule gain a +1 modifier to their Movement and Initiative characteristics.`},
"all-sneaky-like":{name:`All Sneaky Like`,desc:`Kiknik's packmates are excellent hunters that encircle the enemy before launching their attacks.

0-1 Goblin Wolf Rider Mobs in the same muster list as Kiknik may have the Ambushers special rule for free. In addition, you may apply a +1 or -1 modifier to the result when rolling to determine if a Goblin Wolf Rider Mob with the Ambushers special rule that is currently held in reserve arrives this turn as reinforcements or is delayed.`},
"arise":{name:`Arise!`,desc:`As the Liche Priest intones words of power learned long ago from dusty papyrus, the broken forms of fallen skeletal legionaries begin to rise jerkily from the dust.

During the Command sub-phase of their turn, if they are not engaged in combat, this character may attempt to resurrect the fallen by making a Leadership test (using their own Leadership). If this test is passed, a single friendly unit that has the Nehekharan Undead special rule and is within 12" of this character recovers a number of lost Wounds. How many Wounds are recovered depends upon the unit's troop type and this character's Level of Wizardry: regular infantry/heavy infantry/swarms recover Level of Wizardry +D3 Wounds; light/heavy cavalry/war beasts recover Level +1 Wounds; monstrous infantry/cavalry/light chariot recover Level Wounds; heavy chariot/monstrous creature/behemoth/war machine recover 1 Wound.`},
"artillery-master":{name:`Artillery Master`,desc:`Engineers are quick to advise artillery crews how best to aim and fire a war machine.

Unless this character is fleeing or engaged in combat, once per turn, during the Shooting phase, a friendly unit of Quarrellers, unit of Thunderers or Dwarf war machine that is within its Command range can either re-roll any rolls To Hit of a natural 1, or re-roll a single Artillery dice.`},
"beguiling-aura":{name:`Beguiling Aura`,desc:`Unicorns shimmer with magical power, a gleaming aura that also bears an enfolding glamour that bewitches and beguiles any who come near.

Enemy models must make a Leadership test before making any rolls To Hit against this model during the Combat phase. If this test is failed, only rolls of a natural 6 will hit.`},
"blasphemous-tome":{name:`Blasphemous Tome`,desc:`Rumoured to have been penned by Nagash himself, the Winds of Magic become nigh uncontrollable in the presence of a Blasphemous Tome.

All Wizards (friend or foe) may apply a +1 modifier to any Casting roll whilst within this model's Command range. However, if any Wizard miscasts whilst within this model's Command range, they must roll twice on the Miscast table and apply both results.`},
"blessings-of-grimnir":{name:`Blessings of Grimnir`,desc:`Those that tend the inner sanctum of the Shrine of Grimnir are well-versed in the secrets of his cult and able to unbind the foul magic of cowardly foes.

A model with this special rule may be nominated to attempt a Wizardly Dispel, as if it were a Wizard. However, unlike regular Wizards, a Shrine Keeper does not have a Level of Wizardry. Instead, a Shrine Keeper has a Dispel range of 21" and may apply a +1 modifier to their Dispel rolls.`},
"blessings-of-khaine":{name:`Blessings of Khaine`,desc:`As the Cauldron of Blood fills, the baleful spirit of Khaine surrounds his devoted daughters.

Even if engaged in combat, this model can cast the following Bound spell (Power Level 2, Enchantment, Casting Value 9+, Range Self): Until your next Start of Turn sub-phase, this model and every friendly Death Hag, unit of Witch Elves or unit of Sisters of Slaughter within its Command range gains one of: Fury of Khaine (Furious Charge), Strength of Khaine (Cleaving Blow), or Bloodshield of Khaine (5+ Ward save).`},
"blessings-of-the-horned-rat":{name:`Blessings of the Horned Rat`,desc:`The Horned Rat protects its favoured followers, warding them against the weapons of their enemies.

This model has a 5+ Ward save against any wounds suffered that were caused by a non-magical enemy attack.`},
"blessings-of-ulric":{name:`Blessings of Ulric`,desc:`Members of the Teutogen Guard are fierce devotees of Ulric and carry wards blessed by his priests.

A model with this special rule has a 6+ Ward save against any wounds suffered that were caused by an attack that has the Flaming Attacks special rule.`},
"blizzard-aura":{name:`Blizzard Aura`,desc:`The ice that sheathes a Frostheart Phoenix is as hard as glass, and enemies find their own strength and resolve eaten away by its chill presence.

Whilst in base contact with this model, enemy models become subject to the Strike Last special rule.`},
"blood-frenzy":{name:`Blood Frenzy`,desc:`Carnosaurs are huge, aggressive creatures that become almost impossible to control when they taste the blood of the enemy.

When this model (but not its rider) inflicts an unsaved wound upon an enemy model, it becomes subject to the Frenzy special rule. A model with this special rule may become Frenzied in this way even if it has lost Frenzy earlier in the game. Note that this model's rider does not gain a +1 modifier to their Attacks characteristic.`},
"boldest-of-the-bold":{name:`Boldest of the Bold`,desc:`Having found his courage, Araloth will never again be the meek, cowardly figure he once was.

Araloth ignores all negative modifiers to his Leadership characteristic.`},
"born-of-fire":{name:`Born of Fire`,desc:`The Great Tauruses are the living embodiments of Hashut's fiery rage, creatures born of the intense heat and pressure found only within a volcano's heart.

A Bale Taurus or Great Taurus has a 3+ Ward save against any wounds suffered that were caused by an attack that has the Flaming Attacks special rule.`},
"borne-aloft":{name:`Borne Aloft`,desc:`Carried upon the broad shoulders of their most trusted retainers, a Dwarf lord towers above the serried ranks of their army.

A model with Shieldbearers consists of not one, but four models – the character and three loyal retainers – occupying a single base and acting together as a single entity. To represent this, a model with Shieldbearers has a split profile and follows the Split Profile (Cavalry) rule. In all other respects, this model is heavy infantry.`},
"bull-charge":{name:`Bull Charge`,desc:`The sheer bulk of an Ogre Tyrant or Bruiser is such that the enemy is often crushed by the force of their charge alone.

Impact Hits caused by this model (but not its mount) have an Armour Piercing characteristic of -1.`},
"carrion-feeders":{name:`Carrion Feeders`,desc:`The decaying carcass of a Zombie Dragon is wreathed by swarms of buzzing carrion feeders that crawl greedily across the exposed flesh of its enemies, choking and blinding them.

Enemy units engaged in combat with this model suffer a -1 modifier to their Initiative characteristic.`},
"cathayan-cataphracts":{name:`Cathayan Cataphracts`,desc:`Jade Lancers are trained to fight with long cavalry spears, bringing the heavily armoured bulk of their warhorses and the weight of their numbers to bear in crushing charges that grind the enemy underfoot.

When a unit in which the majority of the models have this special rule makes a follow up move, the unit counts as having charged during the next turn.`},
"chainmaker":{name:`Chainmaker`,desc:`Those who find themselves as Frydaal's captives know that their banners will decorate the prow of her ship and the luckiest amongst them will spend the rest of their days rowing its oars.

Any enemy standard captured by Frydaal or any unit she has joined is worth 100 Victory Points as a trophy of war.`},
"champions-of-chrace":{name:`Champions of Chrace`,desc:`Even amongst the warriors of Chrace, the Lion Guard are renowned fighters, eager to best their foes in single combat.

Any model in a unit of Lion Guard can accept challenges in the same manner as a character. In addition, once per turn a character that has joined a unit of Lion Guard may re-roll their "Look Out, Sir!" roll.`},
"cloud-of-dust":{name:`Cloud of Dust`,desc:`Great clouds of desert sand and dust seethe and billow about a Necrolith Bone Dragon, hiding its form from the eyes of its enemies.

Any enemy model that targets this model during the Shooting phase suffers an additional -1 To Hit modifier.`},
"cloud-of-flies":{name:`Cloud of Flies`,desc:`Swarms of fat flies surround the Plague Priests of Clan Pestilens, blinding and choking their enemies.

Any enemy model that directs its attacks against this character during the Combat phase suffers a -1 modifier to its rolls To Hit.`},
"clouds-of-soot-and-smoke":{name:`Clouds of Soot & Smoke`,desc:`Imperial guns produce prodigious clouds of smoke, concealing Engineers from enemy fire.

Unless it is mounted, this model is considered to be behind full cover whilst it is within 3" of a friendly unit whose troop type is war machine.`},
"commander-and-captain":{name:`Commander & Captain`,desc:`Even before falling to the darkness of the Chaos gods, Frydaal was a renowned sea captain, both feared and respected in equal measure.

Unless she is fleeing, friendly units of Chaos Marauders, Marauder Horsemen, Marauder Tribe Huscarls and Marauder Tribe Berserkers gain a +1 modifier to their Leadership characteristic whilst within Frydaal's Command range (to a maximum of 10).`},
"covenant-of-power":{name:`Covenant of Power`,desc:`A nimbus of sorcerous energy swirls around a Casket of Souls' infernal form. So great is this power that the incantations of nearby Liche Priests become infused with a portion of the casket's energy.

Whilst within 12" of a Casket of Souls, friendly Liche Priests may apply a +1 modifier to any Casting roll they make. Additionally, any model (friend or foe) that casts a Bound spell whilst within 12" of a Casket of Souls may apply a +1 modifier to the Casting roll. Note that this bonus does not apply to any Bound spells cast by a Casket of Souls.`},
"crown-of-antlers":{name:`Crown of Antlers`,desc:`Some creatures have powerful antlers that tear through armour and cuts deeply into the flesh beneath.

Impact Hits caused by a model with this special rule have the Armour Bane (1) special rule and an Armour Piercing characteristic of -1.`},
"crushing-weight":{name:`Crushing Weight`,desc:`Enemies unfortunate enough to fall beneath the tremendous weight of a War Wagon's metal-bound wheels are crushed into the dirt.

Stomp Attacks made by a War Wagon have an Armour Piercing characteristic of -1. In addition, and unlike other chariots, this model treats low linear obstacles as dangerous terrain rather than as impassable terrain.`},
"dances-of-loec":{name:`Dances of Loec`,desc:`In battle, Wardancers perform the favoured rituals of the Trickster God, Loec, each instinctively enacting a pattern of lethal movements in perfect harmony with the rest of their troupe.

When this unit's combat is chosen during Step 1.1 of any Choose & Fight Combat subphase, choose one of the following Dances of Loec: Whirling Death (AP improved by 2 until end of Combat phase); Storm of Blades (Extra Attacks +1 until end of Combat phase); The Shadows Coil (4+ Ward save until end of Combat phase); Woven Mist (enemies suffer -1 To Hit until end of Combat phase). Note that a Shadowdancer that joins this unit is considered to have this special rule as well.`},
"deflect-shots":{name:`Deflect Shots`,desc:`It is said that, as the Swordmasters advance into battle, their blades blur and weave faster than the eyes of the enemy can see, knocking aside arrows in mid-flight.

A model with this special rule has a 6+ Ward save against any wounds suffered that were caused by a non-magical shooting attack.`},
"dig-in":{name:`"Dig In!"`,desc:`A Sapper will direct the rapid construction of fieldworks and trenches that protect their comrades from the enemy.

During any Command sub-phase, if they are not engaged in combat, this character may attempt to lead their unit in the digging of some fieldworks by making a Leadership test (using their own Leadership). If this test is passed, this character and any unit they have joined becomes 'Entrenched'. An Entrenched unit is considered to be behind partial cover and to be defending a low linear obstacle. Should the unit move for any reason, it is no longer Entrenched.`},
"disengage":{name:`Disengage`,desc:`In the face of overwhelming aggression a Sky Lantern can easily disengage, climbing to the heavens before attacking once more.

Should this model lose a round of combat and Give Ground, it may choose to Fall Back in Good Order instead. Enemy units can follow up as if this model had given ground, moving 2" directly towards it, but cannot pursue it. In addition, should it win a round of combat and choose to restrain and reform, this model may choose to Fall Back in Good Order rather than remaining where it is.`},
"dispersed-formation":{name:`Dispersed Formation`,desc:`With their great wings extended, Pegasus Knights descend upon the foe from on high.

Whilst in Skirmish formation, every model in a unit of Pegasus Knights must be within 2" of another model belonging to the same unit, rather than the usual 1".`},
"drop-rocks":{name:`Drop Rocks`,desc:`Skinks train Terradons to glide over the battlefield clutching great rocks in their talons.

Once per game, a unit with this special rule may perform a 'Drop Rocks' attack against a single enemy unit that is not engaged in combat. To do so, this unit must move (by flying) over the unit it wishes to attack during the Remaining Moves sub-phase. Once this unit's movement is complete, the enemy unit suffers D3 Strength 4 hits (AP -) for each model in this unit that moved over it.`},
"entrenchment":{name:`Entrenchment`,desc:`An Engineer will direct the rapid construction of effective entrenchments that protect both war machine and crew.

During deployment, you may 'Entrench' a single non-character model whose troop type is 'war machine' for each character in your army with this special rule. An Entrenched war machine is considered to be behind partial cover and to be defending a low linear obstacle. Should the war machine move for any reason, it is no longer Entrenched.`},
"extended-formation":{name:`Extended Formation`,desc:`Ranging far and wide above the mountain peaks, units of Scout Gyrocopters adopt an extended formation, the better to scour the landscape for the movements of the enemy.

Whilst in Skirmish formation, every model in a unit of Scout Gyrocopters must be within 3" of another model belonging to the same unit, rather than the usual 1".`},
"eye-of-the-dragon":{name:`Eye of the Dragon`,desc:`From the vantage point of a Sky Lantern's armoured gondola, gunners signal the crews of earthbound war machines, guiding their aim.

Friendly models whose weapons shoot using the Bombardment special rule can shoot using this model's line of sight rather than their own.`},
"favour-of-the-goddess":{name:`Favour of the Goddess`,desc:`Ever since their encounter in the woods, Araloth has been shielded from harm by an ancient goddess.

Araloth has a 5+ Ward save against any wounds suffered.`},
"from-beneath-the-sands":{name:`From Beneath the Sands`,desc:`At the Liche Priest's command, the sands begin to shift and churn, revealing their hidden treasures: the dry bones of long dead warriors and the glistening wing cases of biting insects.

During the Command sub-phase of their turn, if they are not engaged in combat, this character may choose a single friendly unit that has both the Nehekharan Undead and the Ambushers special rules, and that is currently held in reserve, and attempt to summon it by making a Leadership test. If passed, the unit is placed anywhere completely within 12" of this model, but not within 6" of any enemy models. If failed, it is delayed until their controlling player's next turn at least. Ambushers arrive automatically at the start of round five as usual.`},
"from-the-ashes":{name:`From the Ashes`,desc:`Should a Phoenix be slain, it explodes in a shower of flaming cinders. If the Winds of Magic are strong, these fiery fragments swiftly coalesce and the Phoenix is reborn.

When a Flamespyre Phoenix loses its last Wound, roll a D6 before removing the model from play:
- On a roll of 1-2, the Phoenix crumbles into cold ashes and is removed from play.
- On a roll of 3-5, the Phoenix explodes into flame. Every enemy unit in base contact suffers D6 Strength 3 hits (AP -1, Flaming Attacks). Once resolved, this model is removed from play.
- On a roll of 6, the Phoenix (and its rider, should it have one) are briefly consumed in a ball of flames, and are immediately reborn, recovering D3 Wounds.`},
"ghoulish-glamour":{name:`Ghoulish Glamour`,desc:`Mortals quail in awestruck disbelief at the sight of a Vampire coven lounging upon the decayed luxury of a Coven Throne.

Enemy units must make a Leadership test before making any rolls To Hit against this model during the Combat phase. If this test is failed, only rolls of a natural 6 will hit.`},
"giant-attacks":{name:`Giant Attacks`,desc:`Giants do not attack in the same way as other creatures. They are far too large and fractious to take orders and much too scatter-brained to have any sort of coherent plan.

Instead of attacking normally during the Combat phase, a Giant may choose to make a 'Giant Attack'. Roll on the Giant Attacks table (D6): 1='Eadbutt, 2=Belly Flop, 3-4=Mighty Swing, 5=Thump with Club, 6=Jump Up & Down.`},
"great-censer":{name:`Great Censer`,desc:`As the Plague Furnace crashes into the enemy ranks, the rusty chains holding the great censer are loosed with devastating effect.

Stomp Attacks made by a Plague Furnace represent the Great Censer being let loose to swing into the enemy. Any Stomp Attacks made by a Plague Furnace have an Armour Piercing characteristic of -2. In addition, whilst within 3" of one or more models with this special rule, the noxious fumes cause enemy units to suffer a -1 modifier to their Toughness characteristic (to a minimum of 1).`},
"handler":{name:`Handler`,desc:`Chaos Warhounds are little more than wild animals and it requires the lash of an experienced handler to discipline a pack of such beasts.

A Chaos Warhound Handler is a special type of character that can be taken as an upgrade to accompany a unit of Chaos Warhounds. During deployment, position a Chaos Warhound Handler with its unit, as you would a character that has joined a unit. Once placed, a Chaos Warhound Handler cannot leave its unit. Unless this model is fleeing, friendly units of Chaos Warhounds within its Command range can use this model's Leadership instead of their own.`},
"heavenly-beacon":{name:`Heavenly Beacon`,desc:`Brightly coloured and illuminated from within, Sky Lanterns act as both a beacon and a rallying point to the forces of the Celestial Dragon.

Unless this model is fleeing, friendly units within 12" of it may re-roll any failed Panic or Rally test. In addition, whilst this model is on the battlefield and not fleeing, you may apply a +1 or -1 modifier when rolling to determine if a friendly Ambusher unit arrives or is delayed. Finally, a Lord Magistrate or Strategist mounted on a Sky Lantern has a Command range of 12".`},
"hekartis-blessing":{name:`Hekarti's Blessing`,desc:`Dark Elf Sorceresses make devotions to Hekarti, the Hydra Queen and Elven goddess of conjurations.

Once per game, a model with this special rule may re-roll a single failed Casting roll.`},
"hit-and-run":{name:`Hit & Run`,desc:`Scout Gyrocopters appear from nowhere, descending quickly from the skies or emerging unexpectedly from behind dense terrain, to strike at the enemy before vanishing again.

Should it win a round of combat, a unit with this special rule may choose to Fall Back in Good Order rather than making a follow up or pursuit move.`},
"holy-fervour":{name:`Holy Fervour`,desc:`The presence of the War Altar of Sigmar fills those that march beside it with courage and a grim resolve to overcome their fears in defence of the Empire.

Unless this unit is fleeing, friendly units within 6" of it automatically pass any Fear tests they are required to make and can re-roll any failed Panic tests.`},
"hostile-terrain":{name:`Hostile Terrain`,desc:`Under the watchful eye of a Sapper, those under their command will constantly be working to ensure the battlefield is an especially dangerous place for the enemy.

Any enemy model that ends its movement within the Command range of one or more characters with this special rule (that are not fleeing or engaged in combat) must make a Dangerous Terrain test.`},
"immortal-overseer":{name:`Immortal Overseer`,desc:`Under the cruel gaze of an Arch Necrotect, even the emotionless skeletal servants and magical constructs of the Mortuary Cult are driven to ever greater efforts.

During the Command sub-phase of their turn, this character may attempt to drive a single friendly unit within their Command range to greater efforts by making a Leadership test. If this test is passed, until your next Start of Turn sub-phase that unit gains a +D3 modifier to its Initiative characteristic (to a maximum of 10).`},
"infernal-engineer":{name:`Infernal Engineer`,desc:`Under the scornful gaze of their masters, the gun crews of Zharr-Naggrund are amongst the finest artillerists in all the known world.

Unless this model is fleeing or engaged in combat, once per turn a friendly war machine that is within its Command range may re-roll one Scatter dice or one Artillery dice.`},
"infested":{name:`Infested`,desc:`Legend has it that, when slain, Terrorgheists explode into great clouds of multitudinous, swarming bats.

When this model loses its last Wound, every unit in base contact with it (friend or foe) suffers D6 Strength 2 hits, each with an AP of -1.`},
"it-and-run":{name:`'It & Run`,desc:`With a barked command from their leader, Kiknik's riders fall back, ready to charge off in pursuit of new prey.

Should they win a round of combat, Kiknik and any Goblin Wolf Rider Mob he has joined may choose to Fall Back in Good Order rather than making a follow up or pursuit move.`},
"marks-of-chaos":{name:`Marks of Chaos`,desc:`Those who bear the favour of the Dark Gods are marked by them. Their appearance becomes shaped by the signs and stigmata of their patron, proclaiming their loyalty for all to see.

Many models have the Mark of Chaos Undivided listed among their special rules. Some have the option to replace it with the Mark of a specific Chaos god. A model cannot have more than one Mark of Chaos. All models within a unit must have the same Mark of Chaos. A character with the Mark of a specific god can only join a unit with the same Mark, with Mark of Chaos Undivided, or with no Mark. Note that the benefits granted by a Mark of Chaos apply only to its bearer, not to their mount.`},
"master-of-ballistics":{name:`Master of Ballistics`,desc:`Learned veterans of the Empire's colleges, Engineers quickly assess the preparation of their war machines and guide their crews towards greater accuracy.

Unless this model is fleeing or engaged in combat, once per turn a friendly Empire war machine that is within its Command range can either use this model's Ballistic Skill characteristic, or re-roll a single Artillery dice.`},
"numbing-chill":{name:`Numbing Chill`,desc:`The Mountains of Mourn are deathly cold, and the terrible chill of the high peaks clings eternally to the hide of the creatures that dwell there.

Whilst in base contact with this model, enemy models suffer a -1 modifier to their Weapon Skill and Initiative characteristics, to a minimum of 1.`},
"peerless-raider":{name:`Peerless Raider`,desc:`Frydaal has raided the coastlines of the Empire and Kislev for many seasons and is second to none when it comes to orchestrating lightning-fast strikes.

0-1 unit of Chaos Marauders or Marauder Horsemen in the same muster list as Frydaal may have the Ambushers special rule for free. In addition, if Frydaal is your General, you may apply a +1 or -1 modifier when rolling to determine if she or any unit of Chaos Marauders, Marauder Horsemen, Marauder Tribe Huscarls or Marauder Tribe Berserkers with Ambushers arrives or is delayed.`},
"pick-up-and":{name:`Pick Up And...`,desc:`Sometimes, Giants forget there is a battle raging around them and, when faced with rank upon rank of bite-sized snacks, will become distracted, reaching down and grabbing enemies by the handful.

Instead of attacking normally or making a Giant Attack, a Giant engaged with regular or heavy infantry units may make a 'Pick Up And...' attack. Nominate an enemy regular or heavy infantry unit in base contact. That unit must make an Initiative test: if failed, a single model is removed from play as a casualty; if passed, no one is picked up. Then roll D6: on 1-3, the Giant stops; on 4+, it tries to pick up another. This continues until the Giant stops or the target unit is destroyed.`},
"prayers-of-sigmar":{name:`Prayers of Sigmar`,desc:`The solemn hymns and chanted prayers of Sigmar's Warrior Priests do more than simply strengthen the faith of believers; through them, Sigmar's power is made manifest.

During the Command sub-phase, this character may attempt to invoke Sigmar's blessings by chanting a single Prayer and making a Leadership test. If passed: Hammer of Sigmar (this model, its mount and one friendly unit within Command range may re-roll rolls To Hit or To Wound of natural 1 in Combat phase); Shield of Faith (this model and one friendly unit within Command range gains 5+ Ward save during Shooting phase); or Soulfire (one engaged enemy unit suffers D6 S3 AP-2 Flaming Magical Attacks hits).`},
"rampant-mutation":{name:`Rampant Mutation`,desc:`Damned by their dark masters, the bodies of the Forsaken constantly writhe and mutate, their limbs forever reshaping into strange new forms.

When this unit's combat is chosen during Step 1.1 of any Choose & Fight Combat sub-phase, roll D6: 1-2=Venomous Fangs (Poisoned Attacks); 3-4=Razor Talons (all attacks AP -2); 5-6=Decapitating Claws (Killing Blow).`},
"release-the-fanatics":{name:`Release the Fanatics!`,desc:`As the enemy draws near, mobs of Night Goblins unleash Fanatics in a whirlwind of destruction.

Fanatics are not placed on the battlefield at the start of the game. Make a note of which Night Goblin units include Fanatics. Unless fleeing or in Marching Column, a concealing unit may release one or more of its Fanatics during any Start of Turn sub-phase. When released, place the Fanatic within 3" of its concealing unit, not touching other models. During the Compulsory Moves sub-phase it was released, it moves 2D6" in a direction chosen by the controlling player; subsequently, it moves 2D6" in a random direction. If its movement brings it into contact with a unit, it moves through it. A Fanatic is removed if a natural double is rolled for its movement, or if it moves into difficult, dangerous or impassable terrain or a linear obstacle. If a concealing unit is destroyed or flees before releasing its Fanatics, they are removed as casualties.`},
"scrying-pool":{name:`Scrying Pool`,desc:`The Coven Thrones bear great enchanted bowls full of fresh blood, within which the Vampire's handmaidens can scry the future.

Even if engaged in combat, this model can cast the following Bound spell (Power Level 2, Enchantment, Casting Value 9+, Range Self): Until your next Start of Turn sub-phase, this model may re-roll any rolls To Hit of a natural 1.`},
"scurrying-masses":{name:`Scurrying Masses`,desc:`Although not brave by nature, Skaven find courage and discipline in large numbers.

Whilst within 3" of a friendly unit, this model gains a positive (+) modifier to its Leadership characteristic equal to that unit's current Rank Bonus, up to a maximum of Leadership 10.`},
"skaryn-the-eye-thief":{name:`Skaryn the Eye Thief`,desc:`Upon hearing the call from his master, Skaryn descends from the skies to scratch and peck at the eyes of Araloth's enemies.

During the Command sub-phase of his turn, Araloth may attempt to dispatch Skaryn by rolling a D6. On 1-2, nothing happens. On 3+, nominate a single enemy model within 18" of Araloth. That model suffers a single Strength 4 hit with an AP of -1. If the target suffers an unsaved wound, its Weapon Skill and Initiative characteristics are reduced by D3 (to a minimum of 1) for the remainder of the game.`},
"slaughterers-call":{name:`Slaughterer's Call`,desc:`The bloodlust of a Minotaur Champion is infectious. When blood is scented, all rational thought is driven from the minds of those around them, replaced with an unquenchable thirst for slaughter.

Whilst this model is Frenzied, any unit it has joined will also become Frenzied.`},
"slavering-charge":{name:`Slavering Charge`,desc:`Fighting as a ferocious pack, charging Dire Wolves quickly overpower their enemies.

During a turn in which it charged, this model has a +1 modifier to its Strength characteristic.`},
"sorcerers-curse":{name:`Sorcerer's Curse`,desc:`The flesh of a Sorcerer of Hashut hardens and blackens over time, eventually turning to stone.

If this model miscasts a spell, it must immediately make a Toughness test. If this test is failed, it loses a single Wound and gains a +1 modifier to its Toughness characteristic instead of rolling on the Miscast table. If this test is passed, it rolls on the Miscast table as normal.`},
"sorcerous-miasma":{name:`Sorcerous Miasma`,desc:`Sorcerous black clouds curl about the Lammasu, protecting it from spells and befouling the magical weapons of its enemies, preventing them from striking the beast to full effect.

During the Combat phase, any enemy model that uses a magic weapon to attack a character mounted on a Lammasu counts as being armed with a simple hand weapon instead.`},
"stable-firing-platform":{name:`Stable Firing Platform`,desc:`Atop the slow moving bulk of a War Wagon, the crew can shoot in all directions, taking careful aim behind its heavily armoured flanks before each shot.

To reflect the stability of a War Wagon, any missile weapons carried by the crew can be used in the Shooting phase even if the War Wagon marched this turn.`},
"stand-back-chief":{name:`"Stand Back Chief"`,desc:`Hunkering down behind their war machines, an Engineer is well-protected from enemy fire.

A character with this special rule cannot be targeted by enemy shooting or by enemy spells whilst it is within 3" of a friendly unit whose troop type is war machine.`},
"stone-skeleton":{name:`Stone Skeleton`,desc:`A Stonehorn is akin to a living fossil, its massive skeleton having hardened to rock.

This model is less vulnerable to the Multiple Wounds (X) special rule. If it suffers an unsaved wound from an attack with this special rule, reduce the number of Wounds lost by 1, to a minimum of 1.`},
"symbol-of-might":{name:`Symbol of Might`,desc:`The War Altar of Sigmar is an imposing structure. From atop its mighty pulpit, the prayers of a Warrior Priest resonate across the battlefield.

The Command range of a Lector of Sigmar mounted on the War Altar is increased from 8" to 12". Note that, if this model is your General, it has a Command range of 18" as normal.`},
"the-arrow-of-kurnous":{name:`The Arrow of Kurnous`,desc:`It is traditional for the Wood Elves not to launch into battle until one of their champions has loosed a shot at the heart of the enemy leader.

Once deployment is complete, but before the roll-off to determine who takes the first turn, if the General of your opponent's army is within 36" of one or more models in your army with this special rule, one of those models may fire the Arrow of Kurnous. The General suffers a single Strength 3 hit with no armour or Regeneration saves permitted (Ward saves allowed). However, if the Arrow of Kurnous is fired, your opponent adds +1 to their roll when determining who takes the first turn.`},
"the-newly-dead":{name:`The Newly Dead`,desc:`Those that fall in battle may be compelled by necromantic magic to rise again and fight against their former comrades.

When resurrecting the fallen, a unit with this special rule can be taken beyond its starting size (but not beyond its maximum size).`},
"thunderous-charge":{name:`Thunderous Charge`,desc:`The ground trembles and shakes beneath the thunderous charge of a Stonehorn.

Impact Hits caused by this model have an Armour Piercing characteristic of -2.`},
"toad-rage":{name:`Toad Rage`,desc:`Ripperdactyls are driven into a feeding frenzy by the scent of their favourite food – the Lustrian blot toad.

Before the game starts (after Scouts are deployed), place one Lustrian blot toad marker per unit of Ripperdactyl Riders on any enemy unit. When engaged in combat with a unit bearing a blot toad marker, Ripperdactyls (not their riders) gain Extra Attacks (+1) and may re-roll any roll To Hit of a natural 1.`},
"tolling-the-bell":{name:`Tolling the Bell`,desc:`The tolling of a Screaming Bell declares the Horned Rat's supremacy and fills the foe with dread.

A Screaming Bell may be rung during the Command sub-phase. Roll 2D6: 2=Magical Backlash (D3 S4 AP-2 hits to all within Command range); 3-4=Dissonant Peal (-1 Ld to enemies within 18"); 5-6=Wall of Unholy Sound (friendly Skaven within 18" gain Fear); 7=Resonant Power (+1 to Casting rolls for friendly Wizards in Command range); 8-9=Emboldening Clamour (Immune to Psychology for Skaven within 18"); 10-11=Rapturous Ringing (Extra Attacks +1 for Skaven within 18"); 12=Sonorous Knell (enemies within 18" make Ld test or suffer D6 S4 hits, no armour/Regen saves).`},
"totem-of-endless-bloodletting":{name:`Totem of Endless Bloodletting`,desc:`A Blood Throne is a physical manifestation of the Blood God's favour. In its presence, Daemons of Khorne are driven into a raging bloodlust.

Friendly Daemons of Khorne that are within this model's Command range and that made a Charge move this turn may re-roll any rolls To Hit of a natural 1 made during the Combat phase.`},
"two-headed-dragon":{name:`Two-headed Dragon`,desc:`The twin maws of Chaos Dragons breathe death upon their foes; one exhaling dark flame whilst the other emits corrosive gas.

A Chaos Dragon/Galruch may use either Dark Fire of Chaos or Fumes of Contagion during the Shooting phase of its turn. It cannot use both during the same turn.`},
"unbound-spirits":{name:`Unbound Spirits`,desc:`If the guardians of a Casket of Souls are slain, the tortured souls contained within the vessel will escape their confines in a raging maelstrom of destruction and vengeance.

If the crew of a Casket of Souls is reduced to zero Wounds, immediately roll a D6 for every unit (friend or foe) within 12" of the model. On a roll of 4+, the unit suffers D6 Strength 3 hits, with no armour or Regeneration saves (Ward saves allowed). Once hits are resolved, the Casket of Souls is removed from play.`},
"unstoppable-assault":{name:`Unstoppable Assault`,desc:`A charging Necrolith Colossus is nigh impossible to stop, its huge arms raining blow upon blow down on the foe, each sending dead and broken bodies flying in all directions.

During the Combat phase of any turn in which this model charged, every attack it makes that causes an unsaved wound allows it to immediately make one additional attack. These additional attacks also benefit from this special rule. Note that any unsaved wounds caused by the Stomp Attacks (D3) special rule do not benefit from this special rule.`},
"vortex-of-souls":{name:`Vortex of Souls`,desc:`When a Casket of Souls is opened, blinding light is unleashed upon the battlefield as the countless bound souls entombed within it scream into the air.

A Casket of Souls can cast the following Bound spells (Power Level 2): Light of Death & Light of Protection.

Light of Death: The target enemy unit makes a Leadership test. If passed, suffers D3 Strength 3 hits (AP -1). If failed, suffers D6+3 Strength 6 hits with Multiple Wounds (2), no armour or Regeneration saves.

Light of Protection (Remains in Play): This model and any friendly unit within 18" gains a 6+ Ward save. Enemy units suffer -1 To Hit against this model and friendly units within 18".`},
"wake-of-fire":{name:`Wake of Fire`,desc:`When a Flamespyre Phoenix is enraged, its plumage explodes into a magical flame, causing the creature to leave a trail of angry fire in its wake.

This model may perform a 'Wake of Fire' attack against a single enemy unit that is not engaged in combat. To do so, this model must move (by flying) over the unit it wishes to attack during the Remaining Moves sub-phase. Once this model's movement is complete, the enemy unit suffers D6 Strength 4 hits, each with AP -1 and the Flaming Attacks special rule.`},
"witch-bane":{name:`Witch Bane`,desc:`The Golden Griffon is a sacred relic of the Cult of Sigmar and a powerful reminder to all witches and warlocks of how the Heldenhammer once cast their wickedness from his lands.

All Wizards within this model's Command range (friend or foe) suffer a -2 modifier to their Casting rolls.`},
"witness-to-destiny":{name:`Witness to Destiny`,desc:`Cursed with the knowledge of their own demise, the Phoenix Guard are able to effortlessly avoid the mundane weapons of the enemy with a disturbing ease.

This unit has a 6+ Ward save against any wounds suffered that were caused by a non-magical enemy attack.`}
}
